    private BroImportedProfileRecord ImportBroProfilePdf(string sourcePath, string fallbackModelType)
    {
        if (_selectedProject is null) throw new InvalidOperationException("Geen project actief.");
        if (!File.Exists(sourcePath)) throw new FileNotFoundException("BRO PDF niet gevonden.", sourcePath);

        var parsed = ParseBroProfilePdf(sourcePath, fallbackModelType);
        var modelType = NormalizeBroModelType(parsed.ModelType);
        var id = Guid.NewGuid();
        var safeName = $"{DateTime.Now:yyyyMMdd_HHmmss}_{id:N}_{ToSafeFileName(System.IO.Path.GetFileNameWithoutExtension(sourcePath))}.pdf";
        var localPath = System.IO.Path.Combine(GetBroProfileImportDirectory(modelType), safeName);
        File.Copy(sourcePath, localPath, overwrite: true);
        var profileImagePath = RenderBroImportedProfileImage(localPath, modelType, parsed.Identification);

        return parsed with
        {
            Id = id,
            SourcePath = sourcePath,
            LocalPath = localPath,
            ProfileImagePath = profileImagePath,
            FileName = System.IO.Path.GetFileName(sourcePath),
            ImportedAt = DateTimeOffset.Now
        };
    }

    private BroImportedProfileRecord ParseBroProfilePdf(string path, string fallbackModelType)
    {
        var text = ExtractPdfText(path);
        var modelName = ReadBroPdfValue(text, @"Boormonsterprofiel\s+en\s+interpretatie\s+(?<value>BRO[^\r\n]+)");
        var modelType = DetectBroProfileModelType(modelName, fallbackModelType);
        var identification = ReadBroPdfValue(text, @"Identificatie:\s*(?<value>[A-Z0-9_-]+)");

        double? x = null;
        double? y = null;
        var coordinateMatch = Regex.Match(text, @"Co.?rdinaten:\s*(?<x>[-0-9.,]+)\s*,\s*(?<y>[-0-9.,]+)\s*\(RD\)", RegexOptions.IgnoreCase | RegexOptions.CultureInvariant);
        if (coordinateMatch.Success)
        {
            x = ParseBroPdfDouble(coordinateMatch.Groups["x"].Value);
            y = ParseBroPdfDouble(coordinateMatch.Groups["y"].Value);
        }

        var surfaceNap = ParseBroPdfDouble(ReadBroPdfValue(text, @"Maaiveld:\s*(?<value>[-0-9.,]+)\s*m"));
        double? depthTop = null;
        double? depthBottom = null;
        var depthMatch = Regex.Match(text, @"Diepte\s+t\.?o\.?v\.?\s*maaiveld:\s*(?<from>[-0-9.,]+)\s*m\s*-\s*(?<to>[-0-9.,]+)\s*m", RegexOptions.IgnoreCase | RegexOptions.CultureInvariant);
        if (depthMatch.Success)
        {
            depthTop = ParseBroPdfDouble(depthMatch.Groups["from"].Value);
            depthBottom = ParseBroPdfDouble(depthMatch.Groups["to"].Value);
        }

        return new BroImportedProfileRecord
        {
            Id = Guid.Empty,
            ModelType = modelType,
            ModelName = string.IsNullOrWhiteSpace(modelName) ? DinoModelLabel(modelType) : modelName.Trim(),
            Identification = string.IsNullOrWhiteSpace(identification) ? ToSafeFileName(System.IO.Path.GetFileNameWithoutExtension(path)) : identification.Trim(),
            X = x,
            Y = y,
            SurfaceNap = surfaceNap,
            DepthTop = depthTop,
            DepthBottom = depthBottom,
            ExtractedSummary = BuildBroPdfExtractSummary(text),
            SourcePath = path,
            LocalPath = path,
            ProfileImagePath = "",
            FileName = System.IO.Path.GetFileName(path),
            ImportedAt = DateTimeOffset.Now
        };
    }

    private static string RenderBroImportedProfileImage(string pdfPath, string modelType, string identification)
    {
        if (string.IsNullOrWhiteSpace(pdfPath) || !File.Exists(pdfPath)) return "";

        var stopwatch = Stopwatch.StartNew();
        Exception? failure = null;
        try
        {
            var directory = System.IO.Path.GetDirectoryName(pdfPath);
            if (string.IsNullOrWhiteSpace(directory)) return "";

            var outputName = $"{System.IO.Path.GetFileNameWithoutExtension(pdfPath)}-profiel.png";
            var outputPath = System.IO.Path.Combine(directory, outputName);
            using var document = DocLib.Instance.GetDocReader(pdfPath, new PageDimensions(2.25));
            var pageCount = document.GetPageCount();
            if (pageCount == 0) return "";

            var renderedPages = new List<DrawingBitmap>();
            try
            {
                // DINOloket BRO profile PDFs use page 1 for the profile and page 2 for the legend.
                var pageLimit = Math.Min(2, pageCount);
                for (var pageIndex = 0; pageIndex < pageLimit; pageIndex++)
                {
                    using var page = document.GetPageReader(pageIndex);
                    var width = page.GetPageWidth();
                    var height = page.GetPageHeight();
                    var bytes = page.GetImage(new NaiveTransparencyRemover(255, 255, 255));
                    using var bitmap = CreateBitmapFromBgra(bytes, width, height);
                    renderedPages.Add(CropBroProfileBitmap(bitmap, modelType, identification));
                }

                using var combined = CombineBroProfilePages(renderedPages);
                combined.Save(outputPath, DrawingImageFormat.Png);
            }
            finally
            {
                foreach (var page in renderedPages)
                {
                    page.Dispose();
                }
            }

            return outputPath;
        }
        catch (Exception exception)
        {
            failure = exception;
            return "";
        }
        finally
        {
            stopwatch.Stop();
            LogPerformanceTimingIfSlow($"BRO profielbeeld renderen {modelType} {identification}", stopwatch.Elapsed, 150);
            if (failure is not null)
            {
                LogPerformanceTiming($"BRO profielbeeld renderen mislukt {modelType} {identification}", stopwatch.Elapsed, failure);
            }
        }
    }

    private static DrawingBitmap CreateBitmapFromBgra(byte[] bytes, int width, int height)
    {
        var bitmap = new DrawingBitmap(width, height, DrawingPixelFormat.Format32bppArgb);
        var bounds = new DrawingRectangle(0, 0, width, height);
        var data = bitmap.LockBits(bounds, DrawingImageLockMode.WriteOnly, DrawingPixelFormat.Format32bppArgb);
        try
        {
            Marshal.Copy(bytes, 0, data.Scan0, Math.Min(bytes.Length, Math.Abs(data.Stride) * height));
        }
        finally
        {
            bitmap.UnlockBits(data);
        }

        return bitmap;
    }

    private static DrawingBitmap CropBroProfileBitmap(DrawingBitmap bitmap, string modelType, string identification)
    {
        var bounds = FindNonWhiteBounds(bitmap);
        if (bounds.Width <= 0 || bounds.Height <= 0)
        {
            return new DrawingBitmap(bitmap);
        }

        var margin = 26;
        var crop = new DrawingRectangle(
            Math.Max(0, bounds.Left - margin),
            Math.Max(0, bounds.Top - margin),
            Math.Min(bitmap.Width - Math.Max(0, bounds.Left - margin), bounds.Width + margin * 2),
            Math.Min(bitmap.Height - Math.Max(0, bounds.Top - margin), bounds.Height + margin * 2));

        return bitmap.Clone(crop, DrawingPixelFormat.Format32bppArgb);
    }

    private static DrawingBitmap CombineBroProfilePages(IReadOnlyList<DrawingBitmap> pages)
    {
        var validPages = pages.Where(page => page.Width > 1 && page.Height > 1).ToList();
        if (validPages.Count == 0) return new DrawingBitmap(1, 1, DrawingPixelFormat.Format32bppArgb);
        if (validPages.Count == 1) return new DrawingBitmap(validPages[0]);

        const int padding = 22;
        const int gap = 18;
        var width = validPages.Sum(page => page.Width) + gap * (validPages.Count - 1) + padding * 2;
        var height = validPages.Max(page => page.Height) + padding * 2;
        var combined = new DrawingBitmap(width, height, DrawingPixelFormat.Format32bppArgb);
        using var graphics = System.Drawing.Graphics.FromImage(combined);
        graphics.Clear(System.Drawing.Color.White);

        var x = padding;
        foreach (var page in validPages)
        {
            var y = padding + Math.Max(0, (height - padding * 2 - page.Height) / 2);
            graphics.DrawImage(page, x, y, page.Width, page.Height);
            x += page.Width + gap;
        }

        return combined;
    }

    private static bool ShouldRegenerateBroProfileImage(string imagePath)
    {
        if (string.IsNullOrWhiteSpace(imagePath) || !File.Exists(imagePath)) return true;

        try
        {
            using var image = DrawingBitmap.FromFile(imagePath);
            return image.Height < 420 || image.Width < 420;
        }
        catch
        {
            return true;
        }
    }

    private static DrawingRectangle FindNonWhiteBounds(DrawingBitmap bitmap)
    {
        var minX = bitmap.Width;
        var minY = bitmap.Height;
        var maxX = -1;
        var maxY = -1;

        for (var y = 0; y < bitmap.Height; y++)
        {
            for (var x = 0; x < bitmap.Width; x++)
            {
                var color = bitmap.GetPixel(x, y);
                if (color.A < 20) continue;
                if (color.R > 248 && color.G > 248 && color.B > 248) continue;

                if (x < minX) minX = x;
                if (y < minY) minY = y;
                if (x > maxX) maxX = x;
                if (y > maxY) maxY = y;
            }
        }

        return maxX < minX || maxY < minY
            ? DrawingRectangle.Empty
            : DrawingRectangle.FromLTRB(minX, minY, maxX + 1, maxY + 1);
    }

    private static string ReadBroPdfValue(string text, string pattern)
    {
        var match = Regex.Match(text, pattern, RegexOptions.IgnoreCase | RegexOptions.CultureInvariant);
        return match.Success ? Regex.Replace(match.Groups["value"].Value, @"\s+", " ").Trim() : "";
    }

    private static double? ParseBroPdfDouble(string value)
    {
        if (string.IsNullOrWhiteSpace(value)) return null;
        var cleaned = Regex.Replace(value, @"[^0-9,.\-]", "").Replace(',', '.');
        return double.TryParse(cleaned, NumberStyles.Float, CultureInfo.InvariantCulture, out var number)
            ? number
            : null;
    }

    private static string DetectBroProfileModelType(string modelName, string fallbackModelType)
    {
        if (modelName.Contains("REGIS", StringComparison.OrdinalIgnoreCase)) return BroRegisModelType;
        if (modelName.Contains("DGM", StringComparison.OrdinalIgnoreCase)) return BroDgmModelType;
        return NormalizeBroModelType(fallbackModelType);
    }

    private static string BuildBroPdfExtractSummary(string text)
    {
        var lines = text
            .Split(['\r', '\n'], StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .Select(line => Regex.Replace(line, @"\s+", " ").Trim())
            .Where(line => !string.IsNullOrWhiteSpace(line))
            .Where(line => !line.Equals("Diepte t.o.v maaiveld in meters", StringComparison.OrdinalIgnoreCase))
            .Distinct(StringComparer.OrdinalIgnoreCase)
            .Take(28)
            .ToList();

        return lines.Count == 0 ? "" : string.Join("\n", lines);
    }

    private void MergeImportedBroProfilesIntoSoundings(string modelType, IReadOnlyList<BroImportedProfileRecord>? profiles = null, bool selectImported = false)
    {
        var normalized = NormalizeBroModelType(modelType);
        if (!SupportsImportedBroProfiles(normalized)) return;

        profiles ??= ReadBroImportedProfiles(normalized);
        if (profiles.Count == 0) return;

        var current = GetBroSoundings(normalized).ToList();
        var traceRows = GetTraceRowsForProfile();
        var traceDistances = traceRows.Count >= 2 ? BuildTraceDistances(traceRows) : [];
        foreach (var profile in profiles)
        {
            if (current.Any(item => item.Id.Equals(profile.Identification, StringComparison.OrdinalIgnoreCase) ||
                                    item.Code.Equals(profile.Identification, StringComparison.OrdinalIgnoreCase)))
            {
                continue;
            }

            var sounding = BuildBroSoundingPointFromImportedProfile(profile, traceRows, traceDistances);
            if (sounding is not null)
            {
                current.Add(sounding);
            }
        }

        SetBroSoundings(normalized, current
            .OrderBy(item => Math.Abs(item.Offset))
            .ThenBy(item => item.Code, StringComparer.OrdinalIgnoreCase)
            .ToList());

        if (selectImported)
        {
            SetSelectedBroSoundingIds(normalized, profiles.Select(profile => profile.Identification));
        }
    }

    private BroSoundingPoint? BuildBroSoundingPointFromImportedProfile(
        BroImportedProfileRecord profile,
        IReadOnlyList<TracePointRow> traceRows,
        IReadOnlyList<double> traceDistances)
    {
        if (profile.X is not double x || profile.Y is not double y) return null;
        if (!double.IsFinite(x) || !double.IsFinite(y)) return null;

        var wgs = RdToWgs84(x, y);
        var reference = traceRows.Count >= 2
            ? ProjectPointOnTraceSigned(new RdPoint(x, y), traceRows, traceDistances)
            : new KlicPlanPoint(0, 0);

        return new BroSoundingPoint(
            profile.Identification,
            profile.Identification,
            profile.Identification,
            x,
            y,
            wgs[0],
            wgs[1],
            Math.Round(reference.Station, 2),
            Math.Round(reference.Offset, 2),
            profile.SurfaceNap,
            profile.DepthBottom,
            profile.ExtractedSummary,
            $"BRO/DINOloket PDF-import: {profile.FileName}",
            profile.ImportedAt.ToString("dd-MM-yyyy", CultureInfo.InvariantCulture),
            "Geimporteerd uit PDF",
            profile.ModelType,
            profile.ModelName,
            []);
    }

    private void RenderKnowledgeLibraryPanel()
    {
        if (_selectedProject is null)
        {
            KnowledgeLibraryStatusText.Text = "Open eerst een project om documentatie te koppelen.";
            KnowledgeDocumentsList.Children.Clear();
            return;
        }

        var documents = ReadKnowledgeDocuments();
        var indexed = documents.Count(document => !string.IsNullOrWhiteSpace(document.ExtractedText));
        KnowledgeLibraryStatusText.Text = documents.Count == 0
            ? "Nog geen documentatie gekoppeld. Voeg PDF, DOCX, TXT of Markdown toe."
            : $"{documents.Count} document(en) gekoppeld, {indexed} met tekstindex. Deze documentatie wordt meegenomen bij het genereren van inleidingen en voorwoord.";

        KnowledgeDocumentsList.Children.Clear();
        foreach (var document in documents.OrderByDescending(document => document.ImportedAt))
        {
            KnowledgeDocumentsList.Children.Add(CreateKnowledgeDocumentCard(document));
        }
    }

    private Border CreateKnowledgeDocumentCard(KnowledgeDocumentRecord document)
    {
        var card = new Border
        {
            Background = Brush("#F8FAFB"),
            BorderBrush = Brush("#E3ECF3"),
            BorderThickness = new Thickness(1),
            CornerRadius = new CornerRadius(3),
            Padding = new Thickness(8),
            Margin = new Thickness(0, 0, 0, 8)
        };

        var panel = new DockPanel { LastChildFill = true };
        var removeButton = new Button
        {
            Content = "x",
            Tag = document.Id,
            Width = 26,
            Height = 24,
            Padding = new Thickness(0),
            Margin = new Thickness(8, 0, 0, 0),
            Background = Brushes.White,
            Foreground = Brush("#587080"),
            BorderBrush = Brush("#CBD5E1"),
            ToolTip = "Documentatie verwijderen"
        };
        removeButton.Click += RemoveKnowledgeDocument_OnClick;
        DockPanel.SetDock(removeButton, Dock.Right);
        panel.Children.Add(removeButton);

        var textPanel = new StackPanel();
        textPanel.Children.Add(new TextBlock
        {
            Text = document.DisplayName,
            Foreground = Brush("#071422"),
            FontSize = 12,
            FontWeight = FontWeights.SemiBold,
            TextWrapping = TextWrapping.Wrap
        });
        textPanel.Children.Add(new TextBlock
        {
            Text = $"{FormatFileSize(document.SizeBytes)} - {document.ImportStatus}",
            Foreground = Brush("#587080"),
            FontSize = 10,
            TextWrapping = TextWrapping.Wrap,
            Margin = new Thickness(0, 3, 0, 0)
        });
        panel.Children.Add(textPanel);
        card.Child = panel;
        return card;
    }

    private static string FormatFileSize(long bytes)
    {
        if (bytes >= 1024 * 1024) return $"{bytes / 1024d / 1024d:N1} MB";
        return $"{Math.Max(1, bytes / 1024d):N0} KB";
    }

    private async void AddKnowledgeDocument_OnClick(object sender, RoutedEventArgs e)
    {
        if (_selectedProject is null)
        {
            OutputText.Text = "Open eerst een project om documentatie toe te voegen.";
            return;
        }

        var dialog = new OpenFileDialog
        {
            Title = "Voeg norm, richtlijn of referentiedocument toe",
            Filter = "Documentatie (*.pdf;*.docx;*.txt;*.md)|*.pdf;*.docx;*.txt;*.md|Alle bestanden (*.*)|*.*",
            Multiselect = true
        };
        if (dialog.ShowDialog(this) != true) return;

        BeginBackgroundTask("Documentatie indexeren...");
        try
        {
            var current = ReadKnowledgeDocuments().ToList();
            var imported = await Task.Run(() => dialog.FileNames.Select(ImportKnowledgeDocument).ToList());
            current.AddRange(imported);
            SaveKnowledgeDocuments(current);
            RenderKnowledgeLibraryPanel();
            OutputText.Text = $"{imported.Count} document(en) toegevoegd aan de documentatiebibliotheek.";
        }
        catch (Exception exception)
        {
            OutputText.Text = $"Documentatie toevoegen is niet gelukt\n\n{exception.Message}";
        }
        finally
        {
            EndBackgroundTask();
        }
    }

    private async void RefreshKnowledgeLibrary_OnClick(object sender, RoutedEventArgs e)
    {
        if (_selectedProject is null)
        {
            OutputText.Text = "Open eerst een project om documentatie te vernieuwen.";
            return;
        }

        BeginBackgroundTask("Documentatie opnieuw indexeren...");
        try
        {
            var refreshed = await Task.Run(() => ReadKnowledgeDocuments()
                .Select(document =>
                {
                    var text = File.Exists(document.LocalPath) ? ExtractKnowledgeDocumentText(document.LocalPath) : "";
                    return document with
                    {
                        IndexedAt = DateTimeOffset.Now,
                        ExtractedText = TruncateKnowledgeText(text, MaxKnowledgeDocumentTextChars),
                        ImportStatus = string.IsNullOrWhiteSpace(text)
                            ? "Bestand gekoppeld; er kon geen tekst worden geindexeerd."
                            : $"Tekst geindexeerd ({text.Length:N0} tekens)."
                    };
                })
                .ToList());
            SaveKnowledgeDocuments(refreshed);
            RenderKnowledgeLibraryPanel();
            OutputText.Text = "Documentatiebibliotheek opnieuw geindexeerd.";
        }
        catch (Exception exception)
        {
            OutputText.Text = $"Documentatie vernieuwen is niet gelukt\n\n{exception.Message}";
        }
        finally
        {
            EndBackgroundTask();
        }
    }

    private void RemoveKnowledgeDocument_OnClick(object sender, RoutedEventArgs e)
    {
        if (_selectedProject is null || (sender as Button)?.Tag is not Guid id) return;

        var documents = ReadKnowledgeDocuments().ToList();
        var document = documents.FirstOrDefault(document => document.Id == id);
        if (document is null) return;

        documents.RemoveAll(item => item.Id == id);
        SaveKnowledgeDocuments(documents);
        if (!string.IsNullOrWhiteSpace(document.LocalPath) && File.Exists(document.LocalPath))
        {
            try { File.Delete(document.LocalPath); }
            catch { /* Verwijderen van de lokale kopie is niet kritisch voor de rapportdata. */ }
        }

        RenderKnowledgeLibraryPanel();
        OutputText.Text = $"Documentatie verwijderd: {document.DisplayName}.";
    }

    private void KnowledgeLibrary_OnClick(object sender, RoutedEventArgs e)
    {
        KnowledgeLibraryButton.Visibility = Visibility.Collapsed;
        SidebarKnowledgeTab.Visibility = Visibility.Collapsed;
        SetSidebarTab("reportInfo");
    }

    private string BuildKnowledgeGuidanceForText(string subject, string details)
    {
        var documents = ReadKnowledgeDocuments()
            .Where(document => !string.IsNullOrWhiteSpace(document.ExtractedText))
            .Take(MaxKnowledgeDocumentsForPrompt)
            .ToList();
        if (documents.Count == 0) return "";

        var terms = BuildKnowledgeSearchTerms(subject, details).ToList();
        var matchedSentences = documents
            .SelectMany(document => SelectKnowledgeSentences(document, terms))
            .OrderByDescending(item => item.Score)
            .ThenBy(item => item.Text.Length)
            .Take(2)
            .Select(item => item.Text)
            .Where(text => !string.IsNullOrWhiteSpace(text))
            .ToList();

        var names = string.Join(", ", documents.Select(document => System.IO.Path.GetFileNameWithoutExtension(document.DisplayName)).Take(3));
        var focus = terms.Count == 0 ? "de technische randvoorwaarden" : string.Join(", ", terms.Take(5));
        var builder = new StringBuilder();
        builder.Append($"De gekoppelde documentatie ({names}) is gebruikt als referentiekader voor {subject.ToLower(CultureInfo.CurrentCulture)}. ");
        builder.Append($"De beoordeling houdt daardoor nadrukkelijk rekening met {focus}.");
        if (matchedSentences.Count > 0)
        {
            builder.Append(" Relevante aandachtspunten uit de documentatie zijn verwerkt in de controle op uitgangspunten, risico's en vervolgstappen.");
        }

        return builder.ToString();
    }

    private static IEnumerable<string> BuildKnowledgeSearchTerms(string subject, string details)
    {
        var source = $"{subject} {details}";
        var tokens = Regex.Matches(source.ToLowerInvariant(), @"[a-z0-9\-]{4,}")
            .Select(match => match.Value.Trim('-'))
            .Where(token => token.Length >= 4)
            .Where(token => token is not "deze" and not "voor" and not "project" and not "status" and not "rapportdata" and not "belangrijkste")
            .Distinct(StringComparer.OrdinalIgnoreCase)
            .Take(12)
            .ToList();

        if (source.Contains("boorlijn", StringComparison.OrdinalIgnoreCase) || source.Contains("hdd", StringComparison.OrdinalIgnoreCase))
        {
            tokens.AddRange(["hdd", "boring", "trac", "boorlijn"]);
        }
        if (source.Contains("klic", StringComparison.OrdinalIgnoreCase) || source.Contains("kabel", StringComparison.OrdinalIgnoreCase) || source.Contains("leiding", StringComparison.OrdinalIgnoreCase))
        {
            tokens.AddRange(["klic", "kabel", "leiding", "afstand"]);
        }
        if (source.Contains("oppervlak", StringComparison.OrdinalIgnoreCase) || source.Contains("bgt", StringComparison.OrdinalIgnoreCase) || source.Contains("maaiveld", StringComparison.OrdinalIgnoreCase))
        {
            tokens.AddRange(["bgt", "maaiveld", "verharding", "hoogte"]);
        }
        if (source.Contains("grond", StringComparison.OrdinalIgnoreCase) || source.Contains("sondering", StringComparison.OrdinalIgnoreCase))
        {
            tokens.AddRange(["grond", "sondering", "geotechnisch"]);
        }

        return tokens
            .Where(token => !string.IsNullOrWhiteSpace(token))
            .Distinct(StringComparer.OrdinalIgnoreCase);
    }

    private static IEnumerable<(int Score, string Text)> SelectKnowledgeSentences(KnowledgeDocumentRecord document, IReadOnlyList<string> terms)
    {
        if (terms.Count == 0 || string.IsNullOrWhiteSpace(document.ExtractedText)) yield break;

        var sentences = Regex.Split(document.ExtractedText, @"(?<=[\.\?!])\s+|\n+")
            .Select(sentence => Regex.Replace(sentence.Trim(), @"\s+", " "))
            .Where(sentence => sentence.Length is >= 50 and <= 380);

        foreach (var sentence in sentences)
        {
            var score = terms.Count(term => sentence.Contains(term, StringComparison.OrdinalIgnoreCase));
            if (score <= 0) continue;
            yield return (score, sentence);
        }
    }

    private async Task RunUiBackgroundOperationAsync(string busyText, Func<Task<string>> operation)
    {
        var stopwatch = Stopwatch.StartNew();
        Exception? failure = null;
        BeginBackgroundTask(busyText);
        try
        {
            await Dispatcher.Yield(DispatcherPriority.Background);
            OutputText.Text = await operation();
        }
        catch (Exception exception)
        {
            failure = exception;
            OutputText.Text = $"{busyText} is niet gelukt\n\n{exception.Message}";
        }
        finally
        {
            stopwatch.Stop();
            LogPerformanceTiming(busyText, stopwatch.Elapsed, failure);
            EndBackgroundTask();
        }
    }

    private static void LogPerformanceTiming(string action, TimeSpan elapsed, Exception? exception = null)
    {
        try
        {
            var logDirectory = System.IO.Path.Combine(
                Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData),
                "Borevexa",
                "PrescanNative",
                "Logs");
            Directory.CreateDirectory(logDirectory);

            var status = exception is null ? "ok" : "error";
            var message = exception?.Message ?? "";
            var line = string.Join('\t',
                DateTimeOffset.Now.ToString("O", CultureInfo.InvariantCulture),
                elapsed.TotalMilliseconds.ToString("0", CultureInfo.InvariantCulture),
                status,
                SanitizePerformanceLogValue(action),
                SanitizePerformanceLogValue(message));
            File.AppendAllText(
                System.IO.Path.Combine(logDirectory, "performance.log"),
                line + Environment.NewLine,
                Encoding.UTF8);
            Debug.WriteLine($"Borevexa performance: {line}");
        }
        catch
        {
            // Performance logging must never interrupt the workflow.
        }
    }

    private static void LogPerformanceTimingIfSlow(string action, TimeSpan elapsed, double minimumMilliseconds)
    {
        if (elapsed.TotalMilliseconds < minimumMilliseconds)
        {
            return;
        }

        LogPerformanceTiming(action, elapsed);
    }

    private static string SanitizePerformanceLogValue(string value)
    {
        return string.IsNullOrWhiteSpace(value)
            ? "-"
            : value.Replace('\t', ' ').Replace('\r', ' ').Replace('\n', ' ').Trim();
    }

    private void BeginBackgroundTask(string text)
    {
        _backgroundTaskDepth++;
        GlobalBusyText.Text = text;
        GlobalBusyIndicator.Visibility = Visibility.Visible;
        SetBackgroundTaskControlsEnabled(false);
    }

    private void EndBackgroundTask()
    {
        _backgroundTaskDepth = Math.Max(0, _backgroundTaskDepth - 1);
        if (_backgroundTaskDepth > 0) return;

        GlobalBusyIndicator.Visibility = Visibility.Collapsed;
        SetBackgroundTaskControlsEnabled(true);
    }

    private void SetBackgroundTaskControlsEnabled(bool enabled)
    {
        UpdateStepNavigationButtons();
        HeaderStepSaveButton.IsEnabled = enabled;
        HeaderMapSaveButton.IsEnabled = enabled;
        MapToolbarSaveButton.IsEnabled = enabled;
        FinalReportExportButton.IsEnabled = enabled;
        FinalReportRegenerateButton.IsEnabled = enabled;
        ActionButtonsPanel.IsEnabled = enabled;
        StepSpecificRibbonPanel.IsEnabled = enabled;
        WorkflowSubstepsPanel.IsEnabled = enabled;
        WorkflowPartsPanel.IsEnabled = enabled;
    }

    private void UpdateStepNavigationButtons(IReadOnlyList<StepNavigationItem>? selectableItems = null, int? currentNavigationIndex = null)
    {
        PreviousStepButton.Visibility = Visibility.Visible;
        NextStepButton.Visibility = Visibility.Visible;

        if (_selectedProject is null || _selectedStep is null || _backgroundTaskDepth > 0)
        {
            PreviousStepButton.IsEnabled = false;
            NextStepButton.IsEnabled = false;
            return;
        }

        selectableItems ??= _stepNavigationItems.Where(item => item.IsSelectable && !item.IsReportPreview).ToList();
        var currentIndex = currentNavigationIndex ?? selectableItems.ToList().FindIndex(IsCurrentStepNavigationItem);

        PreviousStepButton.IsEnabled = currentIndex > 0;
        NextStepButton.IsEnabled = currentIndex >= 0 && currentIndex < selectableItems.Count - 1;
    }

    private void RenderWorkspace()
    {
        if (_selectedStep is null) return;
        _activeWorkflowPartKey = null;
        var workspace = _workspaces[_selectedStep.Number];
        var reportPreviewStepNumber = _selectedReportPreviewStepNumber;

        var selectableItems = _stepNavigationItems.Where(item => item.IsSelectable && !item.IsReportPreview).ToList();
        var workflowStepCount = _stepNavigationItems.Count(item => item.IsWorkflowStep);
        var currentNavigationIndex = selectableItems.FindIndex(IsCurrentStepNavigationItem);
        StepCounterText.Text = reportPreviewStepNumber is null
            ? _selectedSubstep is null
                ? $"Stap {DisplayStepNumber(workspace.StepNumber)} van {workflowStepCount}"
                : $"Substap {DisplaySubstepNumber(_selectedSubstep)} van stap {DisplayStepNumber(workspace.StepNumber)}"
            : $"Stap {DisplayStepNumber(workspace.StepNumber)} rapportpreview";
        StepHeaderTitle.Text = reportPreviewStepNumber is null
            ? _selectedSubstep is null ? workspace.Title : DisplayReportSectionTitle(_selectedSubstep)
            : $"{workspace.Title} - Rapport preview";
        UpdateStepNavigationButtons(selectableItems, currentNavigationIndex);
        WorkspaceTitle.Text = $"Stap {DisplayStepNumber(workspace.StepNumber)}: {workspace.Title}";
        WorkspaceSubtitle.Text = workspace.Subtitle;
        MapTitle.Text = workspace.MapTitle;
        MapSubtitle.Text = workspace.MapSubtitle;
        ActionsSubtitle.Text = $"Stap {DisplayStepNumber(workspace.StepNumber)} acties";
        NativeNotes.Text = GetNativeNote(workspace.StepNumber);
        RefreshWorkflowReportStatus(workspace.StepNumber);

        if (reportPreviewStepNumber is not null)
        {
            StepZeroPanel.Visibility = Visibility.Collapsed;
            StepOnePanel.Visibility = Visibility.Collapsed;
            StepTwoPanel.Visibility = Visibility.Collapsed;
            StepThreePanel.Visibility = Visibility.Collapsed;
            MapWorkspaceGrid.Visibility = Visibility.Collapsed;
            StepTenReportGrid.Visibility = Visibility.Visible;
            StepElevenWorkDrawingGrid.Visibility = Visibility.Collapsed;
            SubstepIntroductionEditorPanel.Visibility = Visibility.Collapsed;
            StepRibbonHost.Visibility = Visibility.Collapsed;
            HeaderMapSaveButton.Visibility = Visibility.Collapsed;
            ApplyStepFilterSidebarState(false);
            ApplyInlineReportPreviewState();
            StepCardsPanel.Children.Clear();
            RenderWorkflowParts(workspace);
            RenderStepReportPreview(reportPreviewStepNumber.Value);
            ActionButtonsPanel.Children.Clear();
            OutputText.Text = $"Rapportpreview stap {workspace.StepNumber} geopend.";
            return;
        }

        RenderSubstepIntroductionEditor();

        var isChapterIntroductionSubstep =
            _selectedSubstep is not null && IsChapterOpeningSubstep(workspace.StepNumber, _selectedSubstep);

        StepZeroPanel.Visibility = workspace.StepNumber == 0 && !isChapterIntroductionSubstep
            ? Visibility.Visible
            : Visibility.Collapsed;

        if (isChapterIntroductionSubstep)
        {
            StepOnePanel.Visibility = Visibility.Collapsed;
            StepTwoPanel.Visibility = Visibility.Collapsed;
            StepThreePanel.Visibility = Visibility.Collapsed;
            MapWorkspaceGrid.Visibility = Visibility.Collapsed;
            StepTenReportGrid.Visibility = Visibility.Collapsed;
            StepElevenWorkDrawingGrid.Visibility = Visibility.Collapsed;
            StepRibbonHost.Visibility = Visibility.Collapsed;
            HeaderMapSaveButton.Visibility = Visibility.Collapsed;
            MachineSidebarHost.Visibility = Visibility.Collapsed;
            ApplyStepFilterSidebarState(true);
            SidebarToolsTabsPanel.Visibility = Visibility.Visible;
            SidebarToolContentHost.Visibility = Visibility.Visible;
            ApplySidebarToolTabAvailability(false);
            if (_activeSidebarTab is not "reportInfo" and not "knowledge" and not "projectInfo")
            {
                _activeSidebarTab = "reportInfo";
            }
        }
        else
        {
            StepOnePanel.Visibility = workspace.StepNumber == 1 ? Visibility.Visible : Visibility.Collapsed;
            StepTwoPanel.Visibility = workspace.StepNumber == 2 ? Visibility.Visible : Visibility.Collapsed;
            var usesMapLibreWorkspace = workspace.StepNumber is >= 3 and <= ThreeDStepNumber && workspace.StepNumber != ReportStepNumber;
            var usesReportMapLock = IsMapWorkspaceStep(workspace.StepNumber);
            var usesSidebarTools = usesMapLibreWorkspace || workspace.StepNumber == WorkDrawingStepNumber;
            var usesRightSidebar = true;
            var usesStepRibbon = workspace.StepNumber >= 5 && workspace.StepNumber != WorkDrawingStepNumber && workspace.StepNumber != ReportStepNumber;
            StepRibbonHost.Visibility = usesStepRibbon ? Visibility.Visible : Visibility.Collapsed;
            ApplyStepFilterSidebarState(usesRightSidebar);
            SidebarToolsTabsPanel.Visibility = Visibility.Visible;
            SidebarToolContentHost.Visibility = Visibility.Visible;
            ApplySidebarToolTabAvailability(usesSidebarTools);
            if (!usesSidebarTools)
            {
                MachineSidebarHost.Visibility = Visibility.Collapsed;
                if (_activeSidebarTab is not "reportInfo" and not "knowledge" and not "projectInfo")
                {
                    _activeSidebarTab = "reportInfo";
                }
            }
            HeaderMapSaveButton.Visibility = Visibility.Collapsed;
            if (usesReportMapLock) UpdateMapReportLockButton();
            StepThreePanel.Visibility = usesMapLibreWorkspace ? Visibility.Visible : Visibility.Collapsed;
            MapWorkspaceGrid.Visibility = workspace.StepNumber is >= 0 and <= WorkDrawingStepNumber ? Visibility.Collapsed : Visibility.Visible;
            StepTenReportGrid.Visibility = workspace.StepNumber == ReportStepNumber ? Visibility.Visible : Visibility.Collapsed;
            StepElevenWorkDrawingGrid.Visibility = workspace.StepNumber == WorkDrawingStepNumber ? Visibility.Visible : Visibility.Collapsed;
            if (workspace.StepNumber == 0)
            {
                RenderStepZero();
            }
            else if (workspace.StepNumber == 1)
            {
                RenderStepOne();
                ApplyStepOneSubstepLayout();
            }
            else if (workspace.StepNumber == 2)
            {
                RenderStepTwo();
            }
            else if (usesMapLibreWorkspace)
            {
                ApplyStoredMapStateForCurrentStep();
                ApplyStepThreeLayoutBounds();
                RenderStepThree();
            }
            else if (workspace.StepNumber == WorkDrawingStepNumber)
            {
                EnsureProfilePoints();
                RenderWorkDrawingStepSidebar();
                RenderWorkDrawingPreview();
            }
            else
            {
                if (usesStepRibbon)
                {
                    RenderGenericStepRibbon(workspace);
                }
                RenderGisMap(workspace);
            }
        }

        StepCardsPanel.Children.Clear();
        if (!isChapterIntroductionSubstep)
        {
            foreach (var card in workspace.Cards)
            {
                StepCardsPanel.Children.Add(CreateCard(card));
            }
            foreach (var substep in StepReportCatalog.GetSubsteps(workspace.StepNumber))
            {
                StepCardsPanel.Children.Add(CreateSubstepReportCard(substep));
            }
        }
        RenderWorkflowParts(workspace);
        // Navigating to a map step can land on a WebView2 whose WebGL context was
        // dropped while it was collapsed on another step/tab. Ask the map to repaint
        // (self-heals once the canvas is visible again) without a jarring host resize.
        NudgeMapRenderIfVisible();
        if (workspace.StepNumber == ReportStepNumber)
        {
            RenderFinalReportPanel(workspace.StepNumber);
            RenderStepTenReport();
        }
        else
        {
            StepFinalReportPanel.Visibility = Visibility.Collapsed;
        }
        ApplyInlineReportPreviewState();

        ActionButtonsPanel.Children.Clear();
        foreach (var action in workspace.Actions)
        {
            var button = new Button { Content = action, Tag = action };
            button.Click += StepAction_OnClick;
            ActionButtonsPanel.Children.Add(button);
        }

        OutputText.Text = $"Stap {workspace.StepNumber} geladen. Kies een actie om de native module te testen.";
    }

    private void ApplyStepOneSubstepLayout()
    {
        var substepNumber = _selectedSubstep?.Number;
        var showSingleSubstep = _selectedStep?.Number == 1 && !string.IsNullOrWhiteSpace(substepNumber);

        StepOneColumnSplitter.Visibility = showSingleSubstep ? Visibility.Collapsed : Visibility.Visible;
        StepOneLeftTopRowSplitter.Visibility = showSingleSubstep ? Visibility.Collapsed : Visibility.Visible;
        StepOneLeftBottomRowSplitter.Visibility = showSingleSubstep ? Visibility.Collapsed : Visibility.Visible;
        StepOneRightRowSplitter.Visibility = showSingleSubstep ? Visibility.Collapsed : Visibility.Visible;

        ResetStepOnePanelPlacement(StepOneProjectInfoPanel, 0, 0, 1, 1, new Thickness(0, 0, 8, 8));
        ResetStepOnePanelPlacement(StepOneContentPanel, 1, 0, 1, 1, new Thickness(0, 0, 8, 8));
        ResetStepOnePanelPlacement(StepOneFillPanel, 0, 1, 2, 1, new Thickness(0, 0, 0, 8));
        ResetStepOnePanelPlacement(StepOneMachinePanel, 2, 0, 1, 1, new Thickness(0, 0, 8, 0));
        ResetStepOnePanelPlacement(StepOneAiPanel, 2, 1, 1, 1, new Thickness(0));
        StepOneAiPanel.Visibility = Visibility.Collapsed;

        if (!showSingleSubstep)
        {
            StepOneProjectInfoPanel.Visibility = Visibility.Visible;
            StepOneContentPanel.Visibility = Visibility.Visible;
            StepOneFillPanel.Visibility = Visibility.Visible;
            StepOneMachinePanel.Visibility = Visibility.Visible;
            return;
        }

        if (IsChapterIntroductionSubstep(_selectedSubstep))
        {
            StepOneProjectInfoPanel.Visibility = Visibility.Collapsed;
            StepOneContentPanel.Visibility = Visibility.Collapsed;
            StepOneFillPanel.Visibility = Visibility.Collapsed;
            StepOneMachinePanel.Visibility = Visibility.Collapsed;
            return;
        }

        StepOneProjectInfoPanel.Visibility = substepNumber == "1.1" ? Visibility.Visible : Visibility.Collapsed;
        StepOneContentPanel.Visibility = substepNumber == "1.2" ? Visibility.Visible : Visibility.Collapsed;
        StepOneFillPanel.Visibility = substepNumber == "1.3" ? Visibility.Visible : Visibility.Collapsed;
        StepOneMachinePanel.Visibility = substepNumber == "1.4" ? Visibility.Visible : Visibility.Collapsed;

        var activePanel = substepNumber switch
        {
            "1.1" => StepOneProjectInfoPanel,
            "1.2" => StepOneContentPanel,
            "1.3" => StepOneFillPanel,
            "1.4" => StepOneMachinePanel,
            _ => StepOneProjectInfoPanel
        };

        Grid.SetRow(activePanel, 0);
        Grid.SetColumn(activePanel, 0);
        Grid.SetRowSpan(activePanel, 3);
        Grid.SetColumnSpan(activePanel, 2);
        activePanel.Margin = new Thickness(0);
    }

    private static void ResetStepOnePanelPlacement(FrameworkElement panel, int row, int column, int rowSpan, int columnSpan, Thickness margin)
    {
        Grid.SetRow(panel, row);
        Grid.SetColumn(panel, column);
        Grid.SetRowSpan(panel, rowSpan);
        Grid.SetColumnSpan(panel, columnSpan);
        panel.Margin = margin;
    }

    private void RenderStepReportPreview(int stepNumber)
    {
        var stopwatch = Stopwatch.StartNew();
        try
        {
            RenderFinalReportPanel(stepNumber);
            StepTenPreviewSurface.Visibility = Visibility.Visible;
            StepTenReportContent.Children.Clear();

            var pages = CreateStepReportPreviewPages(stepNumber).ToList();
            if (pages.Count == 0)
            {
                pages.Add(GetReportPreviewPage(stepNumber));
            }
            foreach (var page in pages)
            {
                StepTenReportContent.Children.Add(page);
            }

            var title = _workspaces.TryGetValue(stepNumber, out var workspace)
                ? workspace.Title
                : "Rapportonderdeel";
            ReportPreviewTitleText.Text = $"Stap {stepNumber} - rapportpreview";
            ReportExportHintText.Text = "PDF-achtige weergave van dit subonderdeel. De tekst hieronder komt terug in het eindrapport.";
            ReportPartEditorPanel.Visibility = Visibility.Collapsed;
            ReportPartEditorTitle.Text = $"Rapportdata stap {stepNumber}: {title}";
            ReportPreviewPartText.Text = "";
            ReportPreviewPartText.IsEnabled = false;
        }
        finally
        {
            stopwatch.Stop();
            LogPerformanceTimingIfSlow($"Rapportpreview stap {stepNumber}", stopwatch.Elapsed, 120);
        }
    }

    private IEnumerable<UIElement> CreateStepReportPreviewPages(int stepNumber)
    {
        if (_selectedProject is null) yield break;

        SaveStepReportDataForStep(stepNumber);
        TryReadStepReportRoot(stepNumber, out var root);
        foreach (var substep in StepReportCatalog.GetSubsteps(stepNumber))
        {
            foreach (var page in CreateInlineSubstepReportPagesCore(stepNumber, substep, root, expandFinalConclusionPreview: false))
            {
                yield return page;
            }
        }
    }

    private UIElement GetReportPreviewPage(int stepNumber)
    {
        for (var i = 0; i < StepTenReportContent.Children.Count; i++)
        {
            if (StepTenReportContent.Children[i] is FrameworkElement { Tag: int pageStepNumber } && pageStepNumber == stepNumber)
            {
                var page = StepTenReportContent.Children[i];
                StepTenReportContent.Children.RemoveAt(i);
                return page;
            }
        }

        var title = _workspaces.TryGetValue(stepNumber, out var workspace)
            ? $"Stap {stepNumber} - {workspace.Title}"
            : $"Stap {stepNumber}";
        var placeholder = new StackPanel();
        placeholder.Children.Add(CreateReportNote("Voor dit rapportonderdeel is nog geen automatische inhoud ingericht. Vul de rapporttekst hierboven om dit onderdeel alvast vast te leggen."));
        AddReportStepText(placeholder, stepNumber);
        return CreateReportPage(stepNumber, title, CreateReportSection(stepNumber, title, placeholder));
    }

    private void SaveReportPreviewPart_OnClick(object sender, RoutedEventArgs e)
    {
        if (_selectedProject is null || _selectedStep is null || _selectedReportPreviewStepNumber is null)
        {
            OutputText.Text = "Geen project actief. Open of maak eerst een project.";
            return;
        }

        var stepNumber = _selectedReportPreviewStepNumber.Value;
        var text = ReportPreviewPartText.Text.Trim();
        var payload = JsonSerializer.Serialize(new
        {
            text,
            updatedAt = DateTimeOffset.Now
        }, JsonOptions);
        SaveSelectedProjectStepData(stepNumber, ReportSectionDataKey, payload);
        OutputText.Text = string.IsNullOrWhiteSpace(text)
            ? $"Rapportonderdeel stap {stepNumber} leeg opgeslagen."
            : $"Rapportonderdeel stap {stepNumber} opgeslagen voor het eindrapport.";

        RenderStepReportPreview(stepNumber);
    }

    private void RefreshInlineReportPreviewIfVisible()
    {
        if (!CanRefreshInlineReportPreview())
        {
            return;
        }

        _inlineReportPreviewRefreshTimer.Stop();
        _inlineReportPreviewRefreshTimer.Start();
    }

    private bool IsReportPreviewWindowOpen() =>
        _reportPreviewWindow is { IsVisible: true } && _reportPreviewWindowContent is not null;

    private bool CanRefreshInlineReportPreview()
    {
        var inlineVisible = !_inlineReportPreviewCollapsed && InlineReportPreviewSidebar.Visibility == Visibility.Visible;
        if ((!inlineVisible && !IsReportPreviewWindowOpen()) ||
            _selectedProject is null ||
            _selectedStep is null ||
            _selectedReportPreviewStepNumber is not null)
        {
            return false;
        }

        return true;
    }

    private void InlineReportPreviewRefreshTimer_OnTick(object? sender, EventArgs e)
    {
        _inlineReportPreviewRefreshTimer.Stop();
        RefreshInlineReportPreviewIfVisibleNow();
    }

    private void RefreshInlineReportPreviewIfVisibleNow()
    {
        if (!CanRefreshInlineReportPreview() || _selectedStep is not { } selectedStep)
        {
            return;
        }

        SaveStepReportDataForStep(selectedStep.Number);
        if (!_inlineReportPreviewCollapsed && InlineReportPreviewSidebar.Visibility == Visibility.Visible)
        {
            RenderInlineReportPreview();
        }

        if (IsReportPreviewWindowOpen())
        {
            RefreshReportPreviewWindow();
        }
    }

    private void QueueLiveMapReportCapture(int stepNumber)
    {
        var runtime = GetCurrentMapWorkspaceRuntime(stepNumber, GetActiveMapReportVariantKey(stepNumber));
        _reportMapCapture.QueueLiveMapCapture(stepNumber, StepThreeMapView.CoreWebView2, refreshPreview: true, runtime.ScopedReportVariantKey);
    }

    // Guarantees the report shows the map 1-op-1 at the moment the user looks at it:
    // called right before opening a report preview or exporting, so the freshest
    // kaartbeeld is captured first (blank/mid-animation frames are rejected and then
    // the previous good capture simply stays in place).
    private async Task EnsureFreshMapReportCaptureAsync()
    {
        if (_selectedProject is null || _selectedStep is null) return;
        var stepNumber = _selectedStep.Number;
        if (!IsMapWorkspaceStep(stepNumber)) return;
        if (!_mapLibreLoaded || StepThreeMapView?.CoreWebView2 is null) return;
        if (StepThreeMapFrame.Visibility != Visibility.Visible) return;

        try
        {
            await CaptureLiveMapForReportPreviewAsync(stepNumber, refreshPreview: false, force: true);
        }
        catch (Exception exception)
        {
            AppendMapDiagnostic($"Verse rapportcapture voor preview/export mislukt: {exception.Message}");
        }
    }

    private async Task<string> CaptureLiveMapForReportPreviewAsync(int stepNumber, bool refreshPreview, bool force = false, string? variantKey = null)
    {
        var stopwatch = Stopwatch.StartNew();
        try
        {
            var runtime = GetCurrentMapWorkspaceRuntime(stepNumber, variantKey);
            if (runtime.Definition.SendsTraceBeforeCapture)
            {
                SendTraceStateToMap(reportStepNumber: stepNumber);
            }

            if (runtime.Definition.SendsSurfaceAnalysisBeforeCapture)
            {
                SendMapMessage(JsonSerializer.Serialize(new { type = "surfaceAnalysisRequest" }, JsonOptions));
            }

            return await _reportMapCapture.CaptureLiveMapAsync(stepNumber, StepThreeMapView.CoreWebView2, refreshPreview, force, runtime.ScopedReportVariantKey);
        }
        finally
        {
            stopwatch.Stop();
            LogPerformanceTimingIfSlow($"Kaartcapture stap {stepNumber} {variantKey ?? "standaard"}", stopwatch.Elapsed, 200);
        }
    }

    private string? GetActiveMapReportVariantKey(int stepNumber)
    {
        if (stepNumber != 6) return null;
        return GetSubsurfaceMapReportVariantKey(GetActiveUndergroundModelType());
    }

    private string? GetCurrentLiveMapVariantKey(int stepNumber, string? variantKey)
    {
        return GetCurrentMapWorkspaceRuntime(stepNumber, variantKey).ScopedReportVariantKey;
    }

    private object BuildLiveMapCaptureMetadata(int stepNumber)
    {
        var runtime = GetCurrentMapWorkspaceRuntime(stepNumber, GetActiveMapReportVariantKey(stepNumber));
        return new
        {
            baseLayer = _selectedMapBaseLayer,
            overlays = _mapOverlayStates,
            klicThemes = _klicThemeStates,
            bgtSurfaces = _bgtSurfaceStates,
            projectLayerVisibility = _projectLayerStates,
            camera = _lastMapCamera,
            mapScale = _workDrawingScale,
            workspace = new
            {
                runtime.Definition.StepNumber,
                purpose = runtime.Definition.Purpose.ToString(),
                runtime.ContextKey,
                runtime.NormalizedContextKey,
                runtime.ActiveReportVariantKey,
                runtime.ScopedReportVariantKey,
                runtime.HasScopedContext
            },
            substepNumber = _selectedSubstep?.Number,
            substepDisplayNumber = _selectedSubstep?.DisplayNumber,
            substepTitle = _selectedSubstep?.Title
        };
    }

    private void OnLiveMapCaptureCompleted(int stepNumber, string path)
    {
        if (string.IsNullOrWhiteSpace(path))
        {
            return;
        }

        Dispatcher.BeginInvoke(() =>
        {
            SaveStepReportDataForStep(stepNumber);
            RefreshWorkflowReportStatus(stepNumber);

            if (_selectedStep?.Number == stepNumber &&
                _selectedReportPreviewStepNumber is null)
            {
                RefreshInlineReportPreviewIfVisible();
            }

            // Keep an open Rapportpreview window in sync with the freshly captured
            // map image; otherwise it keeps showing the previous kaartbeeld.
            if (IsReportPreviewWindowOpen())
            {
                RefreshReportPreviewWindow();
            }
        });
    }

    private void ReportPreviewZoomOut_OnClick(object sender, RoutedEventArgs e)
    {
        _inlineReportPreviewZoom = Math.Max(0.30, _inlineReportPreviewZoom - 0.10);
        ApplyInlineReportPreviewZoom();
    }

    private void ReportPreviewZoomIn_OnClick(object sender, RoutedEventArgs e)
    {
        _inlineReportPreviewZoom = Math.Min(1.50, _inlineReportPreviewZoom + 0.10);
        ApplyInlineReportPreviewZoom();
    }

    private void ReportPreviewZoomReset_OnClick(object sender, RoutedEventArgs e)
    {
        _inlineReportPreviewZoom = 0.55;
        ApplyInlineReportPreviewZoom();
    }

    private void ApplyInlineReportPreviewZoom()
    {
        InlineReportPreviewContent.LayoutTransform = new ScaleTransform(_inlineReportPreviewZoom, _inlineReportPreviewZoom);
        ReportPreviewZoomTextButton.Content = $"{_inlineReportPreviewZoom * 100:N0}%";
        if (_reportPreviewWindowContent is not null)
        {
            _reportPreviewWindowContent.LayoutTransform = new ScaleTransform(_inlineReportPreviewZoom, _inlineReportPreviewZoom);
        }

        if (_reportPreviewWindowZoomButton is not null)
        {
            _reportPreviewWindowZoomButton.Content = $"{_inlineReportPreviewZoom * 100:N0}%";
        }
    }

    private void RenderInlineReportPreview()
    {
        var stopwatch = Stopwatch.StartNew();
        try
        {
            RenderCurrentReportPreviewInto(InlineReportPreviewTitle, InlineReportPreviewSubtitle, InlineReportPreviewContent, useSignatureCache: true);
            ApplyInlineReportPreviewZoom();
        }
        finally
        {
            stopwatch.Stop();
            LogPerformanceTimingIfSlow($"Inline rapportpreview {_selectedStep?.Number.ToString(CultureInfo.InvariantCulture) ?? "-"} {_selectedSubstep?.Number ?? ""}".Trim(), stopwatch.Elapsed, 100);
        }
    }

    private void RefreshReportPreviewWindow()
    {
        if (_reportPreviewWindowContent is null ||
            _reportPreviewWindowTitle is null ||
            _reportPreviewWindowSubtitle is null)
        {
            return;
        }

        RenderCurrentReportPreviewInto(_reportPreviewWindowTitle, _reportPreviewWindowSubtitle, _reportPreviewWindowContent, useSignatureCache: false);
        if (_reportPreviewWindow is not null)
        {
            _reportPreviewWindow.Title = $"Rapportpreview - {_reportPreviewWindowTitle.Text}";
        }

        ApplyInlineReportPreviewZoom();
    }

    private void RenderCurrentReportPreviewInto(TextBlock titleBlock, TextBlock subtitleBlock, StackPanel content, bool useSignatureCache)
    {
        if (_selectedProject is null || _selectedStep is null)
        {
            content.Children.Clear();
            if (useSignatureCache)
            {
                _lastInlineReportPreviewSignature = null;
            }

            titleBlock.Text = "Rapportpreview";
            subtitleBlock.Text = "Geen project actief";
            content.Children.Add(CreateReportPreviewPlaceholder("Open of maak eerst een project."));
            return;
        }

        var signature = BuildInlineReportPreviewSignature();
        if (useSignatureCache &&
            string.Equals(_lastInlineReportPreviewSignature, signature, StringComparison.Ordinal) &&
            content.Children.Count > 0)
        {
            return;
        }

        if (useSignatureCache)
        {
            _lastInlineReportPreviewSignature = signature;
        }

        content.Children.Clear();
        TryReadStepReportRoot(_selectedStep.Number, out var root);

        if (_reportPreviewWindowScope == ReportPreviewWindowScope.Chapter)
        {
            var chapterTitle = _workspaces.TryGetValue(_selectedStep.Number, out var chapterWorkspace)
                ? $"{DisplayStepNumber(_selectedStep.Number)} {chapterWorkspace.Title}"
                : $"Stap {DisplayStepNumber(_selectedStep.Number)}";
            titleBlock.Text = chapterTitle;
            subtitleBlock.Text = "Hoofdstuk in eindrapportage";

            var pages = CreateStepReportPreviewPages(_selectedStep.Number).ToList();
            if (pages.Count == 0)
            {
                pages.Add(CreateInlineStepReportPage(_selectedStep.Number, root));
            }

            foreach (var page in pages)
            {
                content.Children.Add(page);
            }

            return;
        }

        if (_selectedSubstep is not null)
        {
            titleBlock.Text = DisplayReportSectionTitle(_selectedSubstep);
            subtitleBlock.Text = "Substap in eindrapportage";
            foreach (var page in CreateInlineSubstepReportPages(_selectedStep.Number, _selectedSubstep, root))
            {
                content.Children.Add(page);
            }

            return;
        }

        var title = _workspaces.TryGetValue(_selectedStep.Number, out var workspace)
            ? $"{DisplayStepNumber(_selectedStep.Number)} {workspace.Title}"
            : $"Stap {DisplayStepNumber(_selectedStep.Number)}";
        titleBlock.Text = title;
        subtitleBlock.Text = "Stap in eindrapportage";
        content.Children.Add(CreateInlineStepReportPage(_selectedStep.Number, root));
    }

    private string BuildInlineReportPreviewSignature()
    {
        return string.Join(";",
            _selectedProject?.Id.ToString("N") ?? "geen-project",
            _selectedStep?.Number.ToString(CultureInfo.InvariantCulture) ?? "geen-stap",
            _selectedSubstep?.Number ?? "geen-substap",
            _reportPreviewWindowScope.ToString(),
            _reportUiDataVersion.ToString(CultureInfo.InvariantCulture),
            _projectFiles.Count.ToString(CultureInfo.InvariantCulture),
            _selectedMachineId ?? "",
            _profilePoints.Count.ToString(CultureInfo.InvariantCulture),
            _selectedBroModelType);
    }

    private IReadOnlyList<UIElement> CreateInlineSubstepReportPages(int stepNumber, PrescanSubstep substep, JsonElement root)
    {
        return CreateInlineSubstepReportPagesCore(stepNumber, substep, root, expandFinalConclusionPreview: true);
    }

    private IReadOnlyList<UIElement> CreateInlineSubstepReportPagesCore(
        int stepNumber,
        PrescanSubstep substep,
        JsonElement root,
        bool expandFinalConclusionPreview,
        bool includeChapterIntro = false)
    {
        if (stepNumber == 0)
        {
            return CreateInlineReportStartSubstepPages(substep);
        }

        if (IsChapterIntroductionSubstep(substep))
        {
            return
            [
                CreateInlineSubstepReportPage(
                    stepNumber,
                    substep,
                    root,
                    includeSubstepMedia: false,
                    includeChapterIntro: true)
            ];
        }

        if (expandFinalConclusionPreview && IsFinalConclusionReportSubstep(stepNumber, substep.Number))
        {
            return CreateCustomerFinalReportPreviewPages();
        }

        if (stepNumber == 6 &&
            (string.Equals(substep.Number, "6.1", StringComparison.OrdinalIgnoreCase) ||
             string.Equals(substep.Number, "6.2", StringComparison.OrdinalIgnoreCase)))
        {
            return CreateInlineBroProfileSourceReportPages(stepNumber, substep, root);
        }

        var pages = new List<UIElement>
        {
            CreateInlineSubstepReportPage(
                stepNumber,
                substep,
                root,
                includeSubstepMedia: !IsBoreTraceReportMapSubstep(stepNumber, substep.Number) &&
                                     !IsKlicReportMapSubstep(stepNumber, substep.Number),
                includeChapterIntro: includeChapterIntro)
        };

        if (TryGetSubstepElement(root, substep.Number, out var substepElement))
        {
            var data = JsonProperty(substepElement, "data") ?? default;
            if (IsBoreTraceReportMapSubstep(stepNumber, substep.Number))
            {
                pages.Add(CreateInlineBoreTraceMapReportPage(stepNumber, substep, data));
            }
            else if (IsKlicReportMapSubstep(stepNumber, substep.Number))
            {
                pages.Add(CreateInlineKlicMapReportPage(stepNumber, substep, data));
                pages.Add(CreateInlineKlicCrossingDetailReportPage(stepNumber, substep));
            }
            else if (IsSurfaceProfileReportSubstep(stepNumber, substep.Number))
            {
                pages.Add(CreateInlineBgtSurfaceProfileReportPage(stepNumber, substep));
            }
            else if (IsAhnSurfaceProfileReportSubstep(stepNumber, substep.Number))
            {
                pages.Add(CreateInlineAhnSurfaceProfileReportPage(stepNumber, substep));
            }
            else if (IsSubsurfaceMapReportSubstep(stepNumber, substep.Number))
            {
                pages.Add(CreateInlineSubsurfaceMapReportPage(stepNumber, substep, data));
                pages.AddRange(CreateInlineSubsurfaceLegendReportPages(stepNumber, substep));
            }
        }

        if (IsEnvironmentParcelReportSubstep(stepNumber, substep.Number))
        {
            pages.Add(CreateInlineEnvironmentParcelSegmentPage(stepNumber, substep));
            pages.AddRange(CreateReportParcelOwnerMapPages(BuildParcelOwnerAnalysis(), stepNumber));
        }
        else if (IsProfileReportSubstep(stepNumber, substep.Number))
        {
            pages.AddRange(CreateInlineProfileEngineeringReportPages(stepNumber, substep));
        }

        return pages;
    }

    private IReadOnlyList<UIElement> CreateCustomerFinalReportPreviewPages(bool refreshStepData = true)
    {
        if (_selectedProject is null) return [];

        var stopwatch = Stopwatch.StartNew();
        var pages = new List<UIElement>();
        var stepRootCache = new Dictionary<int, JsonElement>();
        int? currentChapterStep = null;
        try
        {
            if (refreshStepData)
            {
                _projectFiles = _projects.GetProjectFiles(_selectedProject.Id);
            }

            foreach (var (stepNumber, substep) in EnumerateFinalReportSubsteps())
            {
                var includeChapterIntro = stepNumber > 0 && currentChapterStep != stepNumber;
                if (includeChapterIntro) currentChapterStep = stepNumber;

                if (!stepRootCache.TryGetValue(stepNumber, out var root))
                {
                    if (refreshStepData)
                    {
                        SaveStepReportDataForStep(stepNumber, refreshProjectFiles: false);
                    }

                    TryReadStepReportRoot(stepNumber, out root);
                    stepRootCache[stepNumber] = root;
                }

                pages.AddRange(CreateInlineSubstepReportPagesCore(stepNumber, substep, root, expandFinalConclusionPreview: false, includeChapterIntro: includeChapterIntro));
            }

            if (pages.Count >= 3)
            {
                pages[2] = CreateReportContentsPage(3, BuildCustomerFinalReportContentsEntries(pages));
            }
            RenumberReportPreviewPages(pages);
            return pages;
        }
        finally
        {
            stopwatch.Stop();
            LogPerformanceTimingIfSlow($"Eindrapport preview-opbouw {pages.Count} pagina's", stopwatch.Elapsed, 200);
        }
    }

    private IReadOnlyList<ReportContentsEntry> BuildCustomerFinalReportContentsEntries(IReadOnlyList<UIElement> pages)
    {
        var entries = new List<ReportContentsEntry>();
        var groups = new List<(string Title, string Description, int FirstPage, int LastPage)>();

        for (var index = 0; index < pages.Count; index++)
        {
            var pageNumber = index + 1;
            var title = BuildContentsEntryTitle(pageNumber, ExtractReportPageTitle(pages[index]));
            var description = BuildContentsGroupDescription(title);
            if (groups.Count > 0 && string.Equals(groups[^1].Title, title, StringComparison.OrdinalIgnoreCase))
            {
                groups[^1] = (groups[^1].Title, groups[^1].Description, groups[^1].FirstPage, pageNumber);
            }
            else
            {
                groups.Add((title, description, pageNumber, pageNumber));
            }
        }

        foreach (var group in groups)
        {
            var pageText = group.FirstPage == group.LastPage
                ? group.FirstPage.ToString(CultureInfo.InvariantCulture)
                : $"{group.FirstPage}-{group.LastPage}";
            entries.Add(new ReportContentsEntry(pageText, group.Title, group.Description));
        }

        return entries;
    }

    private static string BuildContentsEntryTitle(int pageNumber, string pageTitle)
    {
        if (pageNumber == 1) return "Voorblad";
        if (pageNumber == 2) return "Voorwoord";
        if (pageNumber == 3) return "Inhoudsopgave";

        var title = Regex.Replace(pageTitle.Trim(), @"\s+", " ");
        if (string.IsNullOrWhiteSpace(title)) return "Rapportonderdeel";

        return title;
    }

    private static string BuildContentsGroupTitle(int pageNumber, string pageTitle)
    {
        if (pageNumber == 1) return "Voorblad";
        if (pageNumber == 2) return "Voorwoord";
        if (pageNumber == 3) return "Inhoudsopgave";

        var title = pageTitle.Trim();
        var stepMatch = Regex.Match(title, @"^(?<step>\d+)(?:\.\d+)?\b");
        if (!stepMatch.Success)
        {
            stepMatch = Regex.Match(title, @"^Stap\s+(?<step>\d+)\b", RegexOptions.IgnoreCase);
        }

        if (!stepMatch.Success || !int.TryParse(stepMatch.Groups["step"].Value, out var stepNumber))
        {
            return string.IsNullOrWhiteSpace(title) ? "Rapportonderdeel" : title;
        }

        return stepNumber switch
        {
            1 => "Stap 1 - Projectinformatie",
            2 => "Stap 2 - Ontwerp, KLIC, BAG & BGT inladen",
            3 => "Stap 3 - Boorlijn",
            4 => "Stap 4 - Oppervlakteanalyse",
            5 => "Stap 5 - Omgevingsmanagement",
            6 => "Stap 6 - Ondergrondanalyse",
            7 => "Stap 7 - Dwarsprofiel",
            8 => "Stap 8 - Machine locatie",
            9 => "Stap 9 - Sonderingen",
            10 => "Stap 10 - Eindrapport & Export",
            _ => $"Stap {stepNumber} - Rapportonderdeel"
        };
    }

    private static string BuildContentsGroupDescription(string title)
    {
        if (title.Equals("Voorblad", StringComparison.OrdinalIgnoreCase)) return "Project, locatie, opdrachtgever, boorlengte en rapportdatum.";
        if (title.Equals("Voorwoord", StringComparison.OrdinalIgnoreCase)) return "Toelichting op de prescan, uitgangspunten en rapportcontext.";
        if (title.Equals("Inhoudsopgave", StringComparison.OrdinalIgnoreCase)) return "Overzicht van de rapportonderdelen met actuele bladzijden.";
        if (title.Contains("Projectinformatie", StringComparison.OrdinalIgnoreCase)) return "Projectgegevens, productbundel, vulgraad, dwarsdoorsnede en machinekeuze.";
        if (title.Contains("Ontwerp", StringComparison.OrdinalIgnoreCase)) return "Ingeladen projectbestanden, documenten, GIS-lagen en KLIC-context.";
        if (title.Contains("Boorlijn", StringComparison.OrdinalIgnoreCase)) return "Vastgelegde boorlijn, kaartbijlagen en KLIC-kruisingen.";
        if (title.Contains("Oppervlakteanalyse", StringComparison.OrdinalIgnoreCase)) return "BGT-oppervlaktes, segmenten en AHN4-maaiveldprofiel.";
        if (title.Contains("Omgevingsmanagement", StringComparison.OrdinalIgnoreCase)) return "Perceelsegmenten, ZRO-controle en kaartuitsneden per perceel.";
        if (title.Contains("Ondergrondanalyse", StringComparison.OrdinalIgnoreCase)) return "BRO/DINOloket datasets, bronpunten en geselecteerde ondergrondinformatie.";
        if (title.Contains("Dwarsprofiel", StringComparison.OrdinalIgnoreCase)) return "Horizontaal profiel, profielstaat, boorpunten en KLIC-kruisingen.";
        if (title.Contains("Machine", StringComparison.OrdinalIgnoreCase)) return "Machine, werkvak en plaatsingen.";
        if (title.Contains("Sonderingen", StringComparison.OrdinalIgnoreCase)) return "Sonderingen en geotechnische aandachtspunten.";
        if (title.Contains("Eindrapport", StringComparison.OrdinalIgnoreCase)) return "Eindconclusie en resterende rapportcontrole.";
        return "Rapportonderdeel uit de opgeslagen processtappen.";
    }

    private IReadOnlyList<UIElement> CreateInlineReportStartSubstepPages(PrescanSubstep substep)
    {
        var context = BuildReportStartContext();
        return substep.Number switch
        {
            "0.1" => [CreateReportCoverPage(1, context.DocumentCount, context.LayerCount, context.ParcelCount, context.TraceLength, context.ReportLocation)],
            "0.2" => [CreateReportForewordPage(2, context.DocumentCount, context.ParcelCount, context.TraceLength)],
            "0.3" => [CreateReportContentsPage(3, context.ContentsEntries)],
            _ => [CreateInlineSubstepReportPage(0, substep, default)]
        };
    }

    private void RenderStepZero()
    {
        var settings = ReadReportStartSettings();
        ReportCoverTitleInput.Text = FirstNonEmpty(settings.CoverTitle, DefaultCoverTitle);
        ReportCoverSubtitleInput.Text = settings.CoverSubtitle;
        ReportCoverRevisionInput.Text = settings.CoverRevision;
        ReportCoverNoteInput.Text = settings.CoverNote;
        ReportForewordTextInput.Text = settings.ForewordText;
        ReportForewordScopeInput.Text = settings.ForewordScope;
        ReportContentsTitleInput.Text = settings.ContentsTitle;
        ReportContentsIntroInput.Text = settings.ContentsIntro;
        ReportContentsIncludeAppendicesInput.IsChecked = settings.IncludeAppendices;

        var substep = _selectedSubstep?.Number ?? "0.1";
        StepZeroCoverFields.Visibility = string.Equals(substep, "0.1", StringComparison.OrdinalIgnoreCase) ? Visibility.Visible : Visibility.Collapsed;
        StepZeroForewordFields.Visibility = string.Equals(substep, "0.2", StringComparison.OrdinalIgnoreCase) ? Visibility.Visible : Visibility.Collapsed;
        StepZeroContentsFields.Visibility = string.Equals(substep, "0.3", StringComparison.OrdinalIgnoreCase) ? Visibility.Visible : Visibility.Collapsed;
        StepZeroPrimaryHeader.Text = substep switch
        {
            "0.2" => "Voorwoord",
            "0.3" => "Inhoudsopgave",
            _ => "Voorblad"
        };
        StepZeroEditorTitle.Text = $"{DisplaySubstepNumber(substep)} {StepZeroPrimaryHeader.Text}";
        StepZeroEditorDescription.Text = substep switch
        {
            "0.2" => "Bewerk hier het voorwoord en de uitgangspunten voor pagina 2 van de eindrapportage.",
            "0.3" => "Bewerk hier de toelichting en instellingen voor de inhoudsopgave op pagina 3.",
            _ => "Bewerk hier optionele velden voor het voorblad. De vaste projectgegevens blijven uit het project komen."
        };
        RenderStepZeroInfoPanel(substep, settings);
    }

    private void RenderStepZeroInfoPanel(string substepNumber, ReportStartSettings settings)
    {
        StepZeroInfoPanel.Children.Clear();
        var context = BuildReportStartContext();
        StepZeroInfoPanel.Children.Add(CreateReportKeyValues(
            ("Project", _selectedProject?.Name ?? "-"),
            ("Locatie", context.ReportLocation),
            ("Documenten/bijlagen", context.DocumentCount.ToString(CultureInfo.InvariantCulture)),
            ("Kaartlagen", context.LayerCount.ToString(CultureInfo.InvariantCulture)),
            ("Gekruiste percelen", context.ParcelCount.ToString(CultureInfo.InvariantCulture)),
            ("Boorlengte", $"{context.TraceLength:N1} m")));

        StepZeroInfoPanel.Children.Add(CreateReportSubheading("Wat wordt opgeslagen?"));
        var text = substepNumber switch
        {
            "0.2" => "Voorwoordtekst en uitgangspunten/scope. Deze tekst wordt gebruikt op pagina 2 en in de rapportpreview van 00.2.",
            "0.3" => "Titel, toelichting en of bijlagen/documenten in de inhoudsopgave worden getoond. De hoofdstukken zelf worden automatisch uit de stappen opgebouwd.",
            _ => "Optionele rapporttitel, subtitel, revisiestatus en voorbladopmerking. Projectnaam, locatie, opdrachtgever, status en boorlengte blijven gekoppeld aan de projectdata."
        };
        StepZeroInfoPanel.Children.Add(CreateReportNote(text));

        StepZeroInfoPanel.Children.Add(CreateReportSubheading("Huidige invulling"));
        StepZeroInfoPanel.Children.Add(CreateReportKeyValues(
            ("Voorblad titel", FirstNonEmpty(settings.CoverTitle, DefaultCoverTitle)),
            ("Voorwoord", string.IsNullOrWhiteSpace(settings.ForewordText) ? "Automatische standaardtekst" : "Eigen tekst opgeslagen"),
            ("Inhoudsopgave titel", FirstNonEmpty(settings.ContentsTitle, "Inhoudsopgave")),
            ("Bijlagen tonen", settings.IncludeAppendices ? "Ja" : "Nee")));
    }

    private void GenerateForeword_OnClick(object sender, RoutedEventArgs e)
    {
        if (_selectedProject is null)
        {
            OutputText.Text = "Geen project actief.";
            return;
        }

        var context = BuildReportStartContext();
        ReportForewordTextInput.Text = GenerateDefaultForewordText(context.DocumentCount, context.ParcelCount, context.TraceLength);
        ReportForewordScopeInput.Text = GenerateDefaultForewordScope(context.DocumentCount, context.ParcelCount, context.TraceLength);
        OutputText.Text = "Voorwoord gegenereerd. Pas de tekst eventueel aan en klik daarna op Rapportstart opslaan.";
    }

    private void SaveReportStart_OnClick(object sender, RoutedEventArgs e)
    {
        if (_selectedProject is null)
        {
            OutputText.Text = "Geen project actief.";
            return;
        }

        var settings = new ReportStartSettings(
            ReportCoverTitleInput.Text.Trim(),
            ReportCoverSubtitleInput.Text.Trim(),
            ReportCoverRevisionInput.Text.Trim(),
            ReportCoverNoteInput.Text.Trim(),
            ReportForewordTextInput.Text.Trim(),
            ReportForewordScopeInput.Text.Trim(),
            ReportContentsTitleInput.Text.Trim(),
            ReportContentsIntroInput.Text.Trim(),
            ReportContentsIncludeAppendicesInput.IsChecked != false);
        SaveSelectedProjectStepData(0, ReportStartSettingsDataKey, JsonSerializer.Serialize(settings, JsonOptions));
        SaveStepReportDataForStep(0);
        RefreshWorkflowReportStatus(0);
        RenderStepZeroInfoPanel(_selectedSubstep?.Number ?? "0.1", settings);
        RenderInlineReportPreview();
        OutputText.Text = "Rapportstart opgeslagen voor 00.1, 00.2 en 00.3.";
    }

    private static bool IsBoreTraceReportMapSubstep(int stepNumber, string substepNumber) =>
        stepNumber == 3 && string.Equals(substepNumber, "3.1", StringComparison.OrdinalIgnoreCase);

    private static bool IsKlicReportMapSubstep(int stepNumber, string substepNumber) =>
        stepNumber == 3 && string.Equals(substepNumber, "3.2", StringComparison.OrdinalIgnoreCase);

    private static bool IsSurfaceSegmentsReportSubstep(int stepNumber, string substepNumber) =>
        stepNumber == 4 && string.Equals(substepNumber, "4.1", StringComparison.OrdinalIgnoreCase);

    private static bool IsSurfaceProfileReportSubstep(int stepNumber, string substepNumber) =>
        stepNumber == 4 && string.Equals(substepNumber, "4.2", StringComparison.OrdinalIgnoreCase);

    private static bool IsAhnSurfaceProfileReportSubstep(int stepNumber, string substepNumber) =>
        stepNumber == 4 && string.Equals(substepNumber, "4.3", StringComparison.OrdinalIgnoreCase);

    private static bool IsEnvironmentParcelReportSubstep(int stepNumber, string substepNumber) =>
        stepNumber == EnvironmentStepNumber &&
        string.Equals(substepNumber, "5.1", StringComparison.OrdinalIgnoreCase);

    private static bool IsProfileReportSubstep(int stepNumber, string substepNumber) =>
        stepNumber == ProfileStepNumber &&
        string.Equals(substepNumber, "7.1", StringComparison.OrdinalIgnoreCase);

    private static bool IsFinalConclusionReportSubstep(int stepNumber, string substepNumber) =>
        stepNumber == ReportStepNumber &&
        string.Equals(substepNumber, "10.2", StringComparison.OrdinalIgnoreCase);

    private static bool IsSubsurfaceMapReportSubstep(int stepNumber, string substepNumber) =>
        stepNumber == 6 && SubsurfaceModelTypeForSubstep(substepNumber) is not null;

    private static string? SubsurfaceModelTypeForSubstep(string substepNumber) =>
        substepNumber switch
        {
            "6.1" => BroDgmModelType,
            "6.2" => BroRegisModelType,
            "6.3" => BroGeomorphologyModelType,
            "6.4" => BroSoilMapModelType,
            "6.5" or "6.5.1" => BroGroundwaterGhgModelType,
            "6.5.2" => BroGroundwaterGlgModelType,
            "6.5.3" => BroGroundwaterGvgModelType,
            "6.5.4" => BroGroundwaterGtModelType,
            "6.5.5" => BroGroundwaterDocumentationModelType,
            _ => null
        };

    private UIElement CreateInlineSubstepReportPage(
        int stepNumber,
        PrescanSubstep substep,
        JsonElement root,
        bool includeSubstepMedia = true,
        bool includeChapterIntro = false)
    {
        var panel = new StackPanel();
        var substepTitle = DisplayReportSectionTitle(substep);
        var sectionTitle = includeChapterIntro
            ? $"{DisplayStepNumber(stepNumber)} {GetReportStepTitle(stepNumber)}"
            : substepTitle;
        var quality = _selectedProject is null
            ? ReportQualitySummary.FromIssues([])
            : _reportQuality.EvaluateSubstep(_selectedProject.Id, stepNumber, substep.Number);
        if (IsChapterIntroductionSubstep(substep))
        {
            if (_workspaces.TryGetValue(stepNumber, out var workspace) && !string.IsNullOrWhiteSpace(workspace.Subtitle))
            {
                panel.Children.Add(CreateReportChapterIntro(workspace.Subtitle));
            }

            panel.Children.Add(CreateSubstepIntroductionReportBlock(stepNumber, substep, root));
            return CreateReportPage(stepNumber, sectionTitle, CreateReportSection(stepNumber, sectionTitle, panel));
        }

        if (includeChapterIntro)
        {
            if (_workspaces.TryGetValue(stepNumber, out var workspace) && !string.IsNullOrWhiteSpace(workspace.Subtitle))
            {
                panel.Children.Add(CreateReportChapterIntro(workspace.Subtitle));
            }

            panel.Children.Add(CreateReportSubstepHeading(substep));
        }

        if (TryGetSubstepElement(root, substep.Number, out var substepElement))
        {
            if (ShouldShowChapterTextSections(stepNumber, substep, includeChapterIntro))
            {
                panel.Children.Add(CreateSubstepIntroductionReportBlock(stepNumber, substep, root));
            }
            panel.Children.Add(CreateReportSubheading("Inhoud"));
            var data = JsonProperty(substepElement, "data") ?? default;
            panel.Children.Add(CreateReadableSubstepReportContent(substep.Number, data, includeSubstepMedia));
        }
        else
        {
            if (ShouldShowChapterTextSections(stepNumber, substep, includeChapterIntro))
            {
                panel.Children.Add(CreateSubstepIntroductionReportBlock(stepNumber, substep, root));
            }
            panel.Children.Add(CreateReportNote("Sla het project op om deze substap in de eindrapportage te vullen."));
        }

        return CreateReportPage(stepNumber, sectionTitle, CreateReportSection(stepNumber, sectionTitle, panel));
    }

    private static UIElement CreateReportChapterIntro(string text) => new TextBlock
    {
        Text = text,
        TextWrapping = TextWrapping.Wrap,
        Foreground = Brush("#333333"),
        FontSize = 10.2,
        LineHeight = 14.2,
        Margin = new Thickness(0, 0, 0, 14)
    };

    private static UIElement CreateReportSubstepHeading(PrescanSubstep substep)
    {
        var header = new Grid { Margin = new Thickness(0, 2, 0, 7) };
        header.ColumnDefinitions.Add(new ColumnDefinition { Width = new GridLength(44) });
        header.ColumnDefinitions.Add(new ColumnDefinition { Width = new GridLength(1, GridUnitType.Star) });
        header.Children.Add(new TextBlock
        {
            Text = DisplaySubstepNumber(substep),
            Foreground = Brush("#333333"),
            FontSize = 10.6,
            FontWeight = FontWeights.SemiBold,
            Margin = new Thickness(0, 0, 8, 0)
        });
        var title = new TextBlock
        {
            Text = substep.Title,
            Foreground = Brush("#333333"),
            FontSize = 10.6,
            FontWeight = FontWeights.SemiBold,
            TextWrapping = TextWrapping.Wrap
        };
        Grid.SetColumn(title, 1);
        header.Children.Add(title);
        return header;
    }

    private UIElement CreateCompactReportChapterHeader(int stepNumber)
    {
        var title = $"{DisplayStepNumber(stepNumber)} {GetReportStepTitle(stepNumber)}";
        var subtitle = _workspaces.TryGetValue(stepNumber, out var workspace)
            ? workspace.Subtitle
            : "Rapportonderdelen uit deze processtap.";
        var panel = new StackPanel();
        panel.Children.Add(new TextBlock
        {
            Text = title,
            Foreground = Brush("#071422"),
            FontSize = 20,
            FontWeight = FontWeights.SemiBold,
            TextWrapping = TextWrapping.Wrap
        });
        panel.Children.Add(new TextBlock
        {
            Text = subtitle,
            Foreground = Brush("#587080"),
            FontSize = 10.5,
            LineHeight = 14,
            Margin = new Thickness(0, 4, 0, 0),
            TextWrapping = TextWrapping.Wrap
        });

        return new Border
        {
            BorderBrush = Brush("#D7E8FA"),
            BorderThickness = new Thickness(0, 0, 0, 1),
            Padding = new Thickness(0, 0, 0, 12),
            Margin = new Thickness(0, 0, 0, 14),
            Child = panel
        };
    }

    private static UIElement CreateCompactSubstepMetaBlock(PrescanSubstep substep, string status, ReportQualitySummary quality)
    {
        var panel = new StackPanel();
        panel.Children.Add(new TextBlock
        {
            Text = $"{DisplaySubstepNumber(substep)} · {status}",
            Foreground = Brush("#555555"),
            FontSize = 8.8,
            FontWeight = FontWeights.SemiBold,
            TextWrapping = TextWrapping.Wrap
        });
        panel.Children.Add(new TextBlock
        {
            Text = quality.IsReady
                ? "Rapportstatus: compleet"
                : $"Rapportstatus: {CustomerReportQualityLabel(quality)}",
            Foreground = quality.IsReady ? Brush("#555555") : Brush(quality.StatusColor),
            FontSize = 8.4,
            TextWrapping = TextWrapping.Wrap,
            Margin = new Thickness(0, 2, 0, 0)
        });

        return new Border
        {
            Background = Brushes.Transparent,
            BorderThickness = new Thickness(0),
            Padding = new Thickness(0),
            Margin = new Thickness(0, 0, 0, 8),
            Child = panel
        };
    }

    private UIElement CreateSubstepIntroductionReportBlock(int stepNumber, PrescanSubstep substep, JsonElement root)
    {
        var panel = new StackPanel();
        var sections = GetSubstepTextSections(stepNumber, substep, root);
        foreach (var definition in SubstepTextSectionDefinitions)
        {
            if (!sections.TryGetValue(definition.Key, out var text) || string.IsNullOrWhiteSpace(text))
            {
                continue;
            }

            panel.Children.Add(CreateReportSubheading(definition.Title));
            panel.Children.Add(CreateReportStepPreviewText(CleanCustomerReportIntroduction(text)));
        }

        return panel;
    }

    private static bool ShouldShowChapterTextSections(int stepNumber, PrescanSubstep substep, bool includeChapterIntro = false)
    {
        return stepNumber > 0 && IsChapterIntroductionSubstep(substep);
    }

    private static bool IsChapterOpeningSubstep(int stepNumber, PrescanSubstep substep)
    {
        return stepNumber > 0 && IsChapterIntroductionSubstep(substep);
    }

    private static bool IsChapterIntroductionSubstep(PrescanSubstep? substep) =>
        substep?.IsChapterIntroduction == true;

