    private static Border CreateBgtSurfaceLegendBlock(IReadOnlyList<BgtSurfaceSegment> segments, double total)
    {
        var grouped = segments
            .GroupBy(segment => segment.Label, StringComparer.OrdinalIgnoreCase)
            .Select(group => new
            {
                Label = group.Key,
                Color = group.First().Color,
                Length = group.Sum(segment => Math.Max(0, segment.Length))
            })
            .OrderByDescending(item => item.Length)
            .ToList();

        var panel = new StackPanel();
        panel.Children.Add(new TextBlock
        {
            Text = "Legenda BGT-oppervlakken",
            Foreground = Brush("#333333"),
            FontSize = 10,
            FontWeight = FontWeights.SemiBold,
            Margin = new Thickness(0, 0, 0, 6)
        });

        if (grouped.Count == 0)
        {
            panel.Children.Add(new TextBlock
            {
                Text = "Geen BGT-oppervlaktesegmenten beschikbaar.",
                Foreground = Brush("#64748B"),
                FontSize = 9,
                TextWrapping = TextWrapping.Wrap
            });
        }
        else
        {
            foreach (var item in grouped.Take(12))
            {
                var row = new Grid { Margin = new Thickness(0, 2, 0, 2) };
                row.ColumnDefinitions.Add(new ColumnDefinition { Width = GridLength.Auto });
                row.ColumnDefinitions.Add(new ColumnDefinition { Width = new GridLength(1, GridUnitType.Star) });
                row.ColumnDefinitions.Add(new ColumnDefinition { Width = GridLength.Auto });

                var swatch = new Border
                {
                    Width = 10,
                    Height = 10,
                    Background = Brush(item.Color),
                    BorderBrush = Brush("#CBD5E1"),
                    BorderThickness = new Thickness(0.6),
                    Margin = new Thickness(0, 2, 8, 0)
                };
                Grid.SetColumn(swatch, 0);
                row.Children.Add(swatch);

                var label = new TextBlock
                {
                    Text = item.Label,
                    Foreground = Brush("#333333"),
                    FontSize = 9,
                    TextWrapping = TextWrapping.Wrap
                };
                Grid.SetColumn(label, 1);
                row.Children.Add(label);

                var length = new TextBlock
                {
                    Text = total > 0 ? $"{item.Length:N1} m" : "-",
                    Foreground = Brush("#475569"),
                    FontSize = 9,
                    FontWeight = FontWeights.SemiBold,
                    Margin = new Thickness(12, 0, 0, 0)
                };
                Grid.SetColumn(length, 2);
                row.Children.Add(length);

                panel.Children.Add(row);
            }
        }

        return new Border
        {
            Background = Brushes.White,
            BorderBrush = Brush("#E5EDF3"),
            BorderThickness = new Thickness(0, 1, 0, 1),
            Padding = new Thickness(0, 8, 0, 8),
            Margin = new Thickness(0, 8, 0, 6),
            Child = panel
        };
    }

    private void AddKlicCrossingReportMedia(Panel panel)
    {
        if (_selectedProject is null)
        {
            return;
        }

        var crossings = GetCurrentKlicPlanCrossings();

        panel.Children.Add(CreateReportSubheading("KLIC kruisingen"));
        panel.Children.Add(CreateReportKlicPlanCrossingTable(crossings));
        panel.Children.Add(CreateReportNote(crossings.Count == 0
            ? "Er zijn nog geen KLIC-kruisingen met de boorlijn gevonden. Controleer of KLIC-lagen en themafilters zichtbaar zijn in de blauwe KLIC-zijbalk."
            : "De KLIC-kruisingen worden automatisch bepaald op basis van de vastgelegde boorlijn en de gekoppelde KLIC-lagen. De kaartbeelden staan op de KLIC-kaartbijlage."));
    }

    private IReadOnlyList<KlicPlanCrossing> GetCurrentKlicPlanCrossings()
    {
        if (_selectedProject is null) return [];
        var traceRows = GetTraceRowsForProfile();
        if (traceRows.Count < 2) return [];

        _projectFiles = _projects.GetProjectFiles(_selectedProject.Id);
        var layers = BuildProjectMapLayers(_projectFiles);
        SyncProjectLayerStates(_projectFiles);
        SyncKlicThemeStates(layers);
        return BuildKlicPlanCrossings(traceRows, layers);
    }

    private UIElement CreateReportRenderBlock(ReportRenderBlock block)
    {
        return block switch
        {
            ReportRenderKeyValuesBlock keyValues => CreateReportKeyValues(keyValues.Rows.Select(row => (row.Label, row.Value)).ToArray()),
            ReportRenderTableBlock table => CreateReportRenderTable(table),
            ReportRenderHeadingBlock heading => CreateReportSubheading(heading.Text),
            ReportRenderCardsBlock cards => CreateReportRenderCards(cards),
            ReportRenderSoundingProfileBlock profile => CreateReportSoundingProfile(profile),
            ReportRenderNoteBlock note => CreateReportNote(note.Text),
            _ => CreateReportNote("Onbekend rapportblok.")
        };
    }

    private static Border CreateReportRenderTable(ReportRenderTableBlock block)
    {
        var table = CreateReportTable(block.Headers.ToArray());
        foreach (var row in block.Rows)
        {
            AddReportTableRow(table, row.ToArray());
        }
        return table;
    }

    private static StackPanel CreateReportRenderCards(ReportRenderCardsBlock block)
    {
        var panel = new StackPanel();
        foreach (var cardModel in block.Cards)
        {
            var card = new StackPanel();
            var header = new DockPanel { LastChildFill = true };
            header.Children.Add(new TextBlock
            {
                Text = cardModel.Title,
                FontWeight = FontWeights.SemiBold,
                Foreground = Brush("#333333"),
                FontSize = 10.2,
                TextWrapping = TextWrapping.Wrap
            });
            card.Children.Add(header);

            foreach (var line in cardModel.Lines)
            {
                var row = new DockPanel { Margin = new Thickness(12, 5, 0, 0), LastChildFill = true };
                row.Children.Add(new TextBlock
                {
                    Text = line.Text,
                    Foreground = Brush("#333333"),
                    FontSize = 9.4,
                    TextWrapping = TextWrapping.Wrap
                });
                card.Children.Add(row);
            }

            panel.Children.Add(new Border
            {
                Background = Brushes.Transparent,
                BorderBrush = Brush("#E5EDF3"),
                BorderThickness = new Thickness(0, 1, 0, 1),
                Padding = new Thickness(0, 8, 0, 8),
                Margin = new Thickness(0, 0, 0, 8),
                Child = card
            });
        }

        return panel;
    }

