    private void SendMachineStateToMap()
    {
        if (!_mapLibreLoaded || StepThreeMapView.CoreWebView2 is null)
        {
            QueueMapSync();
            return;
        }
        var visible = _mapOverlayStates.TryGetValue("machines", out var machineVisible) && machineVisible;
