    private string? GetStoredMachinePlacementsJson()
    {
        if (_selectedProject is null) return null;
        var json =
            _projects.GetStepData(_selectedProject.Id, MachineStepNumber, "machine_placements") ??
            _projects.GetStepData(_selectedProject.Id, LegacyMachineStepNumber, "machine_placements") ??
            _projects.GetStepData(_selectedProject.Id, 9, "machine_placements");
        if (string.IsNullOrWhiteSpace(json)) return null;
        try
        {
            using var document = JsonDocument.Parse(json);
            if (document.RootElement.ValueKind == JsonValueKind.Array)
            {
                _currentMachinePlacementsJson = document.RootElement.GetRawText();
                return _currentMachinePlacementsJson;
            }
        }
        catch
        {
            return null;
        }

        return null;
    }

    private string? GetStoredBoreTraceJson()
    {
        if (_selectedProject is null) return null;
        var json = _projects.GetStepData(_selectedProject.Id, 3, "boortrace_geojson") ??
                   _projects.GetStepData(_selectedProject.Id, 4, "boortrace_geojson") ??
                   _projects.GetStepData(_selectedProject.Id, 5, "boortrace_geojson");
        if (string.IsNullOrWhiteSpace(json) || json.Trim().Equals("null", StringComparison.OrdinalIgnoreCase)) return null;

        try
        {
            using var document = JsonDocument.Parse(json);
            var root = document.RootElement;
            if (root.TryGetProperty("type", out var type) && type.GetString() == "LineString")
            {
                return root.GetRawText();
            }

            if (ReadTracePointRows(root).Count >= 2)
            {
                return root.GetRawText();
            }
        }
        catch
        {
            return null;
        }

        return null;
    }

    private void EnsureStoredBoreTraceLoaded()
    {
        if (_selectedProject is null || _currentBoreTracePoints.Count >= 2) return;

        var traceJson = GetStoredBoreTraceJson();
        if (string.IsNullOrWhiteSpace(traceJson))
        {
            _currentBoreTraceJson = null;
            _currentBoreTracePoints = [];
            return;
        }

        try
        {
            using var document = JsonDocument.Parse(traceJson);
            var points = ReadTracePointRows(document.RootElement);
            if (points.Count == 0)
            {
                _currentBoreTraceJson = null;
                _currentBoreTracePoints = [];
                return;
            }

            _currentBoreTraceJson = traceJson;
            _currentBoreTracePoints = points;
        }
        catch
        {
            _currentBoreTraceJson = null;
            _currentBoreTracePoints = [];
        }
    }

    private string StartBoreTraceMode()
    {
        if (!IsBorelineStep(_selectedStep?.Number)) return "Tekenmodus is alleen beschikbaar in stap Boorlijn.";
        if (IsSelectedStepThreeKlicSubstep()) return "Deze KLIC-controlesubstap is alleen-lezen. Pas de boorlijn aan in 3.1 Boorlijn ingetekend.";
        SendTraceStateToMap(drawing: true);
        return "Tekenmodus gestart\n\nKlik op de kaart om punten toe te voegen. Sleep punten om ze te verplaatsen. Gebruik Kaart verplaatsen om de kaart zelf te pannen.";
    }

    private string RequestBoreTraceSave()
    {
        if (!IsBorelineStep(_selectedStep?.Number)) return "Boorlijn opslaan is alleen beschikbaar in stap Boorlijn.";
        if (IsSelectedStepThreeKlicSubstep()) return "Deze KLIC-controlesubstap is alleen-lezen. Sla de boorlijn op in 3.1 Boorlijn ingetekend.";
        if (_selectedProject is not null &&
            _currentBoreTracePoints.Count >= 2 &&
            !string.IsNullOrWhiteSpace(_currentBoreTraceJson))
        {
            SaveBoreTraceGeoJson(_currentBoreTraceJson);
            _profileScreenMetrics = null;
            ClearEnvironmentAnalysisCache();
            RenderTracePointsTable();
            RefreshWorkflowReportStatus(_selectedStep?.Number ?? 3);
            SaveStepReportDataForStep(3);
            return $"Boorlijn opgeslagen\n\nProject: {_selectedProject.Name}\nPunten: {_currentBoreTracePoints.Count}\nLengte: {TraceLengthMeters(_currentBoreTracePoints):N1} m\nLokale database: stap Boorlijn / boortrace_geojson";
        }

        SendMapMessage("{\"type\":\"traceSaveRequest\"}");
        return "Boorlijn opslaan aangevraagd\n\nDe kaart stuurt de actuele trace terug naar de lokale database.";
    }

    private string ClearBoreTrace()
    {
        if (_selectedProject is null) return "Geen project actief.";
        if (IsSelectedStepThreeKlicSubstep()) return "Deze KLIC-controlesubstap is alleen-lezen. Verwijder of wijzig de boorlijn in 3.1 Boorlijn ingetekend.";
        SaveBoreTraceGeoJson("null");
        _currentBoreTraceJson = null;
        _currentBoreTracePoints = [];
        ClearEnvironmentAnalysisCache();
        RenderTracePointsTable();
        SendMapMessage("{\"type\":\"traceClear\"}");
        return "Boorlijn verwijderd\n\nDe trace is uit stap Boorlijn gewist en lokaal opgeslagen.";
    }

    private void SaveBoreTraceFromMap(string message)
    {
        if (_selectedProject is null) return;

        try
        {
            using var document = JsonDocument.Parse(message);
            var root = document.RootElement;
            var geojson = root.TryGetProperty("geojson", out var geojsonElement) && geojsonElement.ValueKind == JsonValueKind.Object
                ? geojsonElement.GetRawText()
                : "null";
            var points = root.TryGetProperty("points", out var pointsElement) && pointsElement.TryGetInt32(out var pointCount) ? pointCount : 0;
            var length = root.TryGetProperty("length", out var lengthElement) && lengthElement.TryGetDouble(out var lengthMeters) ? lengthMeters : 0;

            SaveBoreTraceGeoJson(geojson);
            _currentBoreTraceJson = geojson == "null" ? null : geojson;
            _currentBoreTracePoints = ReadTracePointRows(root);
            _profileScreenMetrics = null;
            ClearEnvironmentAnalysisCache();
            RenderTracePointsTable();
            RefreshWorkflowReportStatus(_selectedStep?.Number ?? 3);
            SaveStepReportDataForStep(3);
            OutputText.Text = $"Boorlijn opgeslagen\n\nProject: {_selectedProject.Name}\nPunten: {points}\nLengte: {length:N1} m\nLokale database: stap Boorlijn / boortrace_geojson";
        }
        catch (Exception exception)
        {
            OutputText.Text = $"Boorlijn opslaan mislukt\n\n{exception.Message}";
        }
    }

    private void SaveBoreTraceGeoJson(string geojson)
    {
        if (_selectedProject is null) return;
        SaveSelectedProjectStepData(3, "boortrace_geojson", geojson);
        SaveSelectedProjectStepData(4, "boortrace_geojson", geojson);
    }

    private static string FormatTraceStatusMessage(string message)
    {
        try
        {
            using var document = JsonDocument.Parse(message);
            var root = document.RootElement;
            var points = root.TryGetProperty("points", out var pointsElement) && pointsElement.TryGetInt32(out var pointCount) ? pointCount : 0;
            var length = root.TryGetProperty("length", out var lengthElement) && lengthElement.TryGetDouble(out var lengthMeters) ? lengthMeters : 0;
            return $"Boorlijn bijgewerkt\n\nPunten: {points}\nLengte: {length:N1} m\nKlik op 'Boorlijn opslaan' om de trace lokaal vast te leggen.";
        }
        catch
        {
            return $"Boorlijn bijgewerkt\n\n{message}";
        }
    }

    private void CaptureCurrentBoreTrace(string message)
    {
        try
        {
            using var document = JsonDocument.Parse(message);
            var root = document.RootElement;
            _currentBoreTraceJson = root.TryGetProperty("geojson", out var geojsonElement) && geojsonElement.ValueKind == JsonValueKind.Object
                ? geojsonElement.GetRawText()
                : null;
            _currentBoreTracePoints = ReadTracePointRows(root);
            _profileScreenMetrics = null;
            _mapBgtSurfaceSamples = [];
            ClearEnvironmentAnalysisCache();
            RenderTracePointsTable();
        }
        catch
        {
            _currentBoreTraceJson = null;
            _currentBoreTracePoints = [];
            _mapBgtSurfaceSamples = [];
            ClearEnvironmentAnalysisCache();
            RenderTracePointsTable();
        }
    }

    private void CaptureProfileScreenMetrics(string message)
    {
        try
        {
            if (_profileLayoutLocked && _profileScreenMetrics is not null && !_surfaceAnalysisMetricsRefreshPending)
            {
                return;
            }

            using var document = JsonDocument.Parse(message);
            var root = document.RootElement;
            var mapWidth = root.TryGetProperty("mapWidth", out var mapWidthElement) && mapWidthElement.TryGetDouble(out var mapWidthValue)
                ? mapWidthValue
                : 0;

            if (mapWidth <= 0 || !root.TryGetProperty("points", out var pointsElement) || pointsElement.ValueKind != JsonValueKind.Array)
            {
                return;
            }

            var points = pointsElement.EnumerateArray()
                .Select(pointElement =>
                {
                    var index = pointElement.TryGetProperty("index", out var indexElement) && indexElement.TryGetInt32(out var indexValue)
                        ? indexValue
                        : 0;
                    var x = pointElement.TryGetProperty("x", out var xElement) && xElement.TryGetDouble(out var xValue)
                        ? xValue
                        : double.NaN;
                    return new ProfileScreenPoint(index, x);
                })
                .Where(point => point.Index > 0 && double.IsFinite(point.X))
                .OrderBy(point => point.Index)
                .ToList();

            if (points.Count < 2) return;

            _profileScreenMetrics = new ProfileScreenMetrics(mapWidth, points);
            _mapBgtSurfaceSamples = ReadMapBgtSurfaceSamples(root);
            if (_selectedProject is not null && _selectedStep?.Number == 4)
            {
                EnsureProfilePoints();
                var total = _profilePoints.Count >= 2 ? Math.Max(1, _profilePoints[^1].Distance) : Math.Max(1, _selectedProject.BoreLengthMeters);
                var segments = GetBgtSurfaceSegments(total);
                if (_surfaceAnalysisMetricsRefreshPending && segments.Count == 0)
                {
                    _surfaceAnalysisMetricsRefreshPending = false;
                    ActivateWorkflowPart(4, "oppervlakte");
                    SurfaceAnalysisBarCanvas.Children.Clear();
                    SurfaceAnalysisTablePanel.Children.Clear();
                    SurfaceAnalysisSummaryBar.Visibility = Visibility.Visible;
                    SurfaceAnalysisSummaryBarText.Text = "Geen actuele BGT-kaartmeting ontvangen.";
                    SurfaceAnalysisSummaryText.Text = "Controleer of BGT import zichtbaar is en voer de analyse opnieuw uit. Er is niets overschreven in de rapportdata.";
                    return;
                }

                _surfaceAnalysisMetricsRefreshPending = false;
                SaveSurfaceAnalysisSnapshot(total, segments);
                UpdateSurfaceAnalysisSummaryBar(segments, total);
                ActivateWorkflowPart(4, "oppervlakte");
                RenderSurfaceAnalysisPanel();
                RefreshWorkflowReportStatus(4);
                if (_selectedReportPreviewStepNumber == 4)
                {
                    RenderStepReportPreview(4);
                }
            }
            else
            {
                _surfaceAnalysisMetricsRefreshPending = false;
            }
            if ((_selectedStep?.Number == ProfileStepNumber || _selectedStep?.Number == WorkDrawingStepNumber) && _profileAlignedToMap)
            {
                RenderProfilePanel();
            }
        }
        catch
        {
            _profileScreenMetrics = null;
            _surfaceAnalysisMetricsRefreshPending = false;
        }
    }

    private static IReadOnlyList<BgtSurfaceSample> ReadMapBgtSurfaceSamples(JsonElement root)
    {
        if (!root.TryGetProperty("bgtSurfaceSamples", out var samplesElement) || samplesElement.ValueKind != JsonValueKind.Array)
        {
            return [];
        }

        var samples = new List<BgtSurfaceSample>();
        foreach (var sampleElement in samplesElement.EnumerateArray())
        {
            var distance = sampleElement.TryGetProperty("distance", out var distanceElement) && distanceElement.TryGetDouble(out var distanceValue)
                ? distanceValue
                : double.NaN;
            var label = sampleElement.TryGetProperty("label", out var labelElement)
            ? labelElement.GetString() ?? "Onbekend"
                : "Onbekend";
            var color = sampleElement.TryGetProperty("color", out var colorElement)
            ? colorElement.GetString() ?? "#F8FAFC"
                : "#F8FAFC";

            if (double.IsFinite(distance))
            {
                samples.Add(new BgtSurfaceSample(distance, label, color));
            }
        }

        return samples.OrderBy(sample => sample.Distance).ToList();
    }

    private static IReadOnlyList<TracePointRow> ReadTracePointRows(JsonElement root)
    {
        if (root.TryGetProperty("geojson", out var geoJsonElement) && geoJsonElement.ValueKind == JsonValueKind.Object)
        {
            var rowsFromGeoJson = ReadTracePointRowsFromLineString(geoJsonElement);
            if (rowsFromGeoJson.Count >= 2) return rowsFromGeoJson;
        }

        var directRowsFromGeoJson = ReadTracePointRowsFromLineString(root);
        if (directRowsFromGeoJson.Count >= 2) return directRowsFromGeoJson;

        if (!root.TryGetProperty("rdPoints", out var pointsElement) || pointsElement.ValueKind != JsonValueKind.Array)
        {
            return [];
        }

        var rows = new List<TracePointRow>();
        foreach (var pointElement in pointsElement.EnumerateArray())
        {
            var index = pointElement.TryGetProperty("index", out var indexElement) && indexElement.TryGetInt32(out var pointIndex)
                ? pointIndex
                : rows.Count + 1;
            var role = pointElement.TryGetProperty("role", out var roleElement)
                ? FormatTraceRole(roleElement.GetString())
                : "Tussenpunt";
            var x = pointElement.TryGetProperty("x", out var xElement) && xElement.TryGetDouble(out var xValue) ? xValue : 0;
            var y = pointElement.TryGetProperty("y", out var yElement) && yElement.TryGetDouble(out var yValue) ? yValue : 0;
            rows.Add(new TracePointRow(index, role, x, y));
        }

        return rows;
    }

    private static IReadOnlyList<TracePointRow> ReadTracePointRowsFromLineString(JsonElement lineStringElement)
    {
        if (!lineStringElement.TryGetProperty("type", out var typeElement) ||
            !string.Equals(typeElement.GetString(), "LineString", StringComparison.OrdinalIgnoreCase) ||
            !lineStringElement.TryGetProperty("coordinates", out var coordinatesElement) ||
            coordinatesElement.ValueKind != JsonValueKind.Array)
        {
            return [];
        }

        var rows = new List<TracePointRow>();
        foreach (var coordinateElement in coordinatesElement.EnumerateArray())
        {
            if (coordinateElement.ValueKind != JsonValueKind.Array || coordinateElement.GetArrayLength() < 2) continue;
            var rd = CoordinateToRdPoint(coordinateElement[0].GetDouble(), coordinateElement[1].GetDouble());
            if (!IsValidRdPoint(rd)) continue;

            var index = rows.Count + 1;
            rows.Add(new TracePointRow(index, index == 1 ? "Intrede" : "Tussenpunt", rd.X, rd.Y));
        }

        if (rows.Count >= 2) rows[^1] = rows[^1] with { Role = "Uittrede" };
        return rows;
    }

    private static IReadOnlyList<TracePointRow> NormalizeTraceRowsToRd(IReadOnlyList<TracePointRow> rows)
    {
        return rows.Select(row =>
        {
            if (LooksLikeRd(row.X, row.Y)) return row;
            if (LooksLikeLonLat(row.X, row.Y))
            {
                var rd = Wgs84ToRd(row.X, row.Y);
                return row with { X = rd.X, Y = rd.Y };
            }

            return row;
        }).ToList();
    }

    private static RdPoint CoordinateToRdPoint(double x, double y) =>
        LooksLikeRd(x, y) ? new RdPoint(x, y) : Wgs84ToRd(x, y);

    private static bool LooksLikeLonLat(double x, double y) =>
        x is >= -180 and <= 180 && y is >= -90 and <= 90;

    private static string FormatTraceRole(string? role) => role switch
    {
        "intrede" => "Intrede",
        "uittrede" => "Uittrede",
        _ => "Tussenpunt"
    };

    private void EnsureProfilePoints(bool regenerate = false)
    {
        if (_selectedProject is null) return;
        LoadProfileVisualSettings();
        if (!regenerate && _profilePoints.Count >= 2) return;

        if (!regenerate)
        {
            var loaded = ReadStoredProfile(
                _projects.GetStepData(_selectedProject.Id, ProfileStepNumber, "diepteprofiel_3d") ??
                _projects.GetStepData(_selectedProject.Id, LegacyProfileStepNumber, "diepteprofiel_3d"));
            if (loaded.Count >= 2)
            {
                _profilePoints = RefreshProfileSurfaces(loaded, preferStoredFallback: true);
                _profileHasUnsavedChanges = false;
                _profileGeometryDirty = false;
                return;
            }
        }

        EnsureStoredBoreTraceLoaded();
        var traceRows = GetTraceRowsForProfile();
        if (traceRows.Count < 2)
        {
            _profilePoints = [];
            return;
        }

        var distances = new List<double> { 0 };
        for (var i = 1; i < traceRows.Count; i++)
        {
            var previous = traceRows[i - 1];
            var current = traceRows[i];
            distances.Add(distances[^1] + Math.Sqrt(Math.Pow(current.X - previous.X, 2) + Math.Pow(current.Y - previous.Y, 2)));
        }

        var total = Math.Max(1, distances[^1]);
        var depthDistances = new[] { 0, total * 0.25, total * 0.65, total };
        _profilePoints = depthDistances.Select((distance, index) =>
        {
            var xy = InterpolateTracePoint(traceRows, distances, distance);
            var surface = GetProfileSurfaceNap(xy.X, xy.Y, distance, total, index);
            var depth = index == 0 || index == depthDistances.Length - 1
                ? 0
                : Math.Max(2.0, Math.Min(5.5, 1.4 + 3.2 * Math.Sin(Math.PI * distance / total)));
            var role = index == 0 ? "Intrede" : index == depthDistances.Length - 1 ? "Uittrede" : "Dieptepunt";
            return new ProfilePointRow(index + 1, role, xy.X, xy.Y, Math.Round(distance, 2), Math.Round(depth, 2), Math.Round(surface - depth, 2), surface);
        }).ToList();
        _profileHasUnsavedChanges = true;
        _profileGeometryDirty = false;
    }

    private List<ProfilePointRow> RefreshProfileSurfaces(IReadOnlyList<ProfilePointRow> points, bool preferStoredFallback = false)
    {
        if (points.Count == 0) return [];
        var total = Math.Max(1, points[^1].Distance);
        return points.Select((point, index) =>
        {
            var hasStoredSurface = double.IsFinite(point.Surface) && point.Surface > -100 && point.Surface < 400;
            var surface = preferStoredFallback && hasStoredSurface
                ? Math.Round(point.Surface, 2)
                : GetProfileSurfaceNap(point.X, point.Y, point.Distance, total, index, point.Surface);
            return point with
            {
                Surface = surface,
                Nap = Math.Round(surface - point.Depth, 2)
            };
        }).ToList();
    }

    private static TracePointRow InterpolateTracePoint(IReadOnlyList<TracePointRow> traceRows, IReadOnlyList<double> distances, double targetDistance)
    {
        if (traceRows.Count == 0) return new TracePointRow(1, "Dieptepunt", 0, 0);
        if (targetDistance <= 0) return traceRows[0];
        if (targetDistance >= distances[^1]) return traceRows[^1];

        for (var i = 1; i < distances.Count; i++)
        {
            if (targetDistance > distances[i]) continue;
            var previousDistance = distances[i - 1];
            var segmentLength = Math.Max(0.001, distances[i] - previousDistance);
            var ratio = (targetDistance - previousDistance) / segmentLength;
            var previous = traceRows[i - 1];
            var next = traceRows[i];
            return new TracePointRow(0, "Dieptepunt", previous.X + (next.X - previous.X) * ratio, previous.Y + (next.Y - previous.Y) * ratio);
        }

        return traceRows[^1];
    }

    private List<ProfilePointRow> ReadStoredProfile(string? json)
    {
        if (string.IsNullOrWhiteSpace(json)) return [];
        try
        {
            using var document = JsonDocument.Parse(json);
            if (!document.RootElement.TryGetProperty("points", out var pointsElement) || pointsElement.ValueKind != JsonValueKind.Array) return [];
            var rows = new List<ProfilePointRow>();
            foreach (var point in pointsElement.EnumerateArray())
            {
                rows.Add(new ProfilePointRow(
                    GetJsonInt(point, "index", rows.Count + 1),
            point.TryGetProperty("role", out var roleElement) ? roleElement.GetString() ?? "Dieptepunt" : "Dieptepunt",
                    GetJsonDouble(point, "x", 0),
                    GetJsonDouble(point, "y", 0),
                    GetJsonDouble(point, "distance", 0),
                    GetJsonDouble(point, "depth", 0),
                    GetJsonDouble(point, "nap", 0),
                    GetJsonDouble(point, "surface", 0)));
            }
            return rows.OrderBy(row => row.Distance).Select((row, index) => row with
            {
                Index = index + 1,
                Role = index == 0 ? "Intrede" : index == rows.Count - 1 ? "Uittrede" : "Dieptepunt"
            }).ToList();
        }
        catch
        {
            return [];
        }
    }

    private void LoadProfileVisualSettings()
    {
        if (_selectedProject is null || _profileVisualSettingsProjectId == _selectedProject.Id) return;
        _profileVisualSettingsProjectId = _selectedProject.Id;
        var json =
            _projects.GetStepData(_selectedProject.Id, ProfileStepNumber, "profile_visual_settings") ??
            _projects.GetStepData(_selectedProject.Id, LegacyProfileStepNumber, "profile_visual_settings");
        if (string.IsNullOrWhiteSpace(json)) return;
        try
        {
            using var document = JsonDocument.Parse(json);
            var root = document.RootElement;
            if (root.TryGetProperty("smooth", out var smooth)) _profileSmoothBore = smooth.GetBoolean();
            if (root.TryGetProperty("expanded", out var expanded)) _profileExpanded = expanded.GetBoolean();
            if (root.TryGetProperty("layoutLocked", out var locked)) _profileLayoutLocked = locked.GetBoolean();
            if (root.TryGetProperty("alignedToMap", out var aligned)) _profileAlignedToMap = aligned.GetBoolean();
            if (root.TryGetProperty("viewZoom", out var zoom) && zoom.TryGetDouble(out var zoomValue))
            {
                _profileViewZoom = Math.Clamp(zoomValue, 0.55, 3.0);
            }
        }
        catch
        {
            // Ignore invalid legacy visual settings.
        }
    }

    private void SaveProfileVisualSettings()
    {
        if (_selectedProject is null) return;
        var payload = JsonSerializer.Serialize(new
        {
            smooth = _profileSmoothBore,
            expanded = _profileExpanded,
            layoutLocked = _profileLayoutLocked,
            alignedToMap = _profileAlignedToMap,
            viewZoom = Math.Round(_profileViewZoom, 3),
            savedAt = DateTimeOffset.Now
        }, JsonOptions);
        SaveSelectedProjectStepData(ProfileStepNumber, "profile_visual_settings", payload);
    }

    private void LoadTraceVisualSettings()
    {
        if (_selectedProject is null || _traceVisualSettingsProjectId == _selectedProject.Id) return;
        _traceVisualSettingsProjectId = _selectedProject.Id;
        _traceSmoothBore = false;
        var json = _projects.GetStepData(_selectedProject.Id, 4, "boortrace_visual_settings");
        if (string.IsNullOrWhiteSpace(json)) return;
        try
        {
            using var document = JsonDocument.Parse(json);
            var root = document.RootElement;
            if (root.TryGetProperty("smooth", out var smooth) && smooth.ValueKind is JsonValueKind.True or JsonValueKind.False)
            {
                _traceSmoothBore = smooth.GetBoolean();
            }
        }
        catch
        {
            _traceSmoothBore = false;
        }
    }

    private void SaveTraceVisualSettings()
    {
        if (_selectedProject is null) return;
        var payload = JsonSerializer.Serialize(new
        {
            smooth = _traceSmoothBore,
            savedAt = DateTimeOffset.Now
        }, JsonOptions);
        SaveSelectedProjectStepData(4, "boortrace_visual_settings", payload);
    }

    private static int GetJsonInt(JsonElement element, string property, int fallback) =>
        element.TryGetProperty(property, out var value) && value.TryGetInt32(out var result) ? result : fallback;

    private static double GetJsonDouble(JsonElement element, string property, double fallback) =>
        element.TryGetProperty(property, out var value) && value.TryGetDouble(out var result) ? result : fallback;

    private IReadOnlyList<TracePointRow> GetTraceRowsForProfile()
    {
        if (_selectedProject is not null && _currentBoreTracePoints.Count < 2 && string.IsNullOrWhiteSpace(_currentBoreTraceJson))
        {
            EnsureStoredBoreTraceLoaded();
        }

        var traceJson = _currentBoreTraceJson ?? GetStoredBoreTraceJson();
        if (!string.IsNullOrWhiteSpace(traceJson))
        {
            try
            {
                using var document = JsonDocument.Parse(traceJson);
                var rows = ReadTracePointRows(document.RootElement);
                if (rows.Count >= 2) return rows;
            }
            catch
            {
                // Fall back to the live RD cache below.
            }
        }

        return NormalizeTraceRowsToRd(_currentBoreTracePoints).Where(row => IsValidRdPoint(new RdPoint(row.X, row.Y))).ToList();
    }

    private IReadOnlyList<TracePointRow> GetReportLocationMapTraceRows(IReadOnlyList<TracePointRow> fallbackTraceRows)
    {
        EnsureProfilePoints();
        if (_profileAlignedToMap && _profilePoints.Count >= 2 && _profilePoints.All(point => IsValidRdPoint(new RdPoint(point.X, point.Y))))
        {
            return _profilePoints
                .OrderBy(point => point.Distance)
                .Select((point, index) => new TracePointRow(
                    index + 1,
                    index == 0 ? "Intrede" : index == _profilePoints.Count - 1 ? "Uittrede" : "Tussenpunt",
                    point.X,
                    point.Y))
                .ToList();
        }

        return fallbackTraceRows;
    }

    private static UIElement CreateReportLocationMapTraceDetails(IReadOnlyList<TracePointRow> traceRows)
    {
        if (traceRows.Count < 2) return CreateReportNote("Geen volledige boorlijn beschikbaar voor lengte en begin-/eindcoördinaten.");
        var distances = BuildTraceDistances(traceRows);
        var start = traceRows[0];
        var end = traceRows[^1];
        return CreateReportKeyValues(
            ("Boorlijnlengte", $"{distances[^1]:N1} m"),
            ("Beginpunt RD", $"X {start.X:N2} / Y {start.Y:N2}"),
            ("Eindpunt RD", $"X {end.X:N2} / Y {end.Y:N2}"));
    }

    private static string BuildReportLocationMapTraceDetailsHtml(IReadOnlyList<TracePointRow> traceRows)
    {
        if (traceRows.Count < 2) return "";
        var distances = BuildTraceDistances(traceRows);
        var start = traceRows[0];
        var end = traceRows[^1];
        static string H(string value) => System.Net.WebUtility.HtmlEncode(value);
        var lengthText = H($"{distances[^1]:N1} m");
        var startText = H($"X {start.X:N2} / Y {start.Y:N2}");
        var endText = H($"X {end.X:N2} / Y {end.Y:N2}");
        return $"""
<div class="mapbox" style="margin-top:-12px;background:#fbfcfd">
<div class="maptitle">Boorlijngegevens</div>
<table class="kv">
<tbody>
<tr><th>Boorlijnlengte</th><td>{lengthText}</td></tr>
<tr><th>Beginpunt RD</th><td>{startText}</td></tr>
<tr><th>Eindpunt RD</th><td>{endText}</td></tr>
</tbody>
</table>
</div>
""";
    }

    private static double DemoSurfaceNap(double distance, double total, int index)
    {
        var ratio = distance / Math.Max(1, total);
        return Math.Round(1.0 - 3.5 * ratio + 0.45 * Math.Sin(ratio * Math.PI * 2) + 0.06 * index, 2);
    }

    private double GetProfileSurfaceNap(double x, double y, double distance, double total, int index, double? storedFallback = null)
    {
        if (TryFetchAhn4DtmSurfaceNap(x, y, out var surfaceNap))
        {
            return Math.Round(surfaceNap, 2);
        }

        if (storedFallback is double fallback && fallback is > -100 and < 400)
        {
            return Math.Round(fallback, 2);
        }

        return DemoSurfaceNap(distance, total, index);
    }

    private bool TryFetchAhn4DtmSurfaceNap(double rdX, double rdY, out double surfaceNap)
    {
        surfaceNap = 0;
        if (!LooksLikeRd(rdX, rdY)) return false;
        if (DateTime.UtcNow < _ahnSurfaceSamplingSuspendedUntilUtc) return false;

        var cacheKey = $"{Math.Round(rdX, 1):0.0}:{Math.Round(rdY, 1):0.0}";
        if (_ahnSurfaceNapCache.TryGetValue(cacheKey, out surfaceNap)) return true;

        try
        {
            const double halfPixelWindow = 1.0;
            var minX = (rdX - halfPixelWindow).ToString("0.###", CultureInfo.InvariantCulture);
            var minY = (rdY - halfPixelWindow).ToString("0.###", CultureInfo.InvariantCulture);
            var maxX = (rdX + halfPixelWindow).ToString("0.###", CultureInfo.InvariantCulture);
            var maxY = (rdY + halfPixelWindow).ToString("0.###", CultureInfo.InvariantCulture);
            var url =
                "https://service.pdok.nl/rws/ahn/wms/v1_0?" +
                "SERVICE=WMS&VERSION=1.1.1&REQUEST=GetFeatureInfo" +
                "&LAYERS=dtm_05m&QUERY_LAYERS=dtm_05m&STYLES=" +
                "&SRS=EPSG:28992" +
                $"&BBOX={minX},{minY},{maxX},{maxY}" +
                "&WIDTH=101&HEIGHT=101&X=50&Y=50&INFO_FORMAT=text/html";

            var content = AhnHeightHttpClient.GetStringAsync(url).GetAwaiter().GetResult();
            if (!TryParseAhnHeight(content, out surfaceNap)) return false;

            _ahnSurfaceNapCache[cacheKey] = surfaceNap;
            return true;
        }
        catch (Exception ex)
        {
            Debug.WriteLine($"AHN4 DTM sampling failed: {ex.Message}");
            _ahnSurfaceSamplingSuspendedUntilUtc = DateTime.UtcNow.AddSeconds(20);
            return false;
        }
    }

    private static bool TryParseAhnHeight(string content, out double surfaceNap)
    {
        surfaceNap = 0;
        if (string.IsNullOrWhiteSpace(content)) return false;

        var match = Regex.Match(content, @"<td>\s*(-?\d+(?:[\.,]\d+)?)\s*</td>", RegexOptions.IgnoreCase);
        if (!match.Success)
        {
            match = Regex.Match(content, @"value(?:_list)?[^-\d]*(-?\d+(?:[\.,]\d+)?)", RegexOptions.IgnoreCase);
        }

        if (!match.Success) return false;
        var raw = match.Groups[1].Value.Replace(',', '.');
        if (!double.TryParse(raw, NumberStyles.Float, CultureInfo.InvariantCulture, out var value)) return false;
        if (double.IsNaN(value) || double.IsInfinity(value) || value is <= -100 or >= 400) return false;

        surfaceNap = value;
        return true;
    }

    private IReadOnlyList<ProfilePointRow> GetTraceReferenceProfilePoints(double profileTotal)
    {
        var traceRows = GetTraceRowsForProfile();
        if (traceRows.Count < 2) return [];

        var distances = new List<double> { 0 };
        for (var i = 1; i < traceRows.Count; i++)
        {
            var previous = traceRows[i - 1];
            var current = traceRows[i];
            distances.Add(distances[^1] + Math.Sqrt(Math.Pow(current.X - previous.X, 2) + Math.Pow(current.Y - previous.Y, 2)));
        }

        var traceTotal = Math.Max(1, distances[^1]);
        return traceRows.Select((point, index) =>
        {
            var distance = profileTotal * distances[index] / traceTotal;
            var surface = GetProfileSurfaceNap(point.X, point.Y, distance, Math.Max(1, profileTotal), index);
            return new ProfilePointRow(index + 1, "Tracepunt", point.X, point.Y, distance, 0, surface, surface);
        }).ToList();
    }

    private IReadOnlyList<KlicProfileCrossing> GetVisibleKlicProfileCrossings(double profileTotal)
    {
        var workDrawingStep = _selectedStep?.Number == WorkDrawingStepNumber;
        if ((!workDrawingStep && (!_mapOverlayStates.TryGetValue("klic", out var showKlic) || !showKlic)) || _selectedProject is null) return [];

        var traceRows = GetTraceRowsForProfile();
        if (traceRows.Count < 2) return [];

        var traceDistances = BuildTraceDistances(traceRows);
        if (traceDistances.Count < 2 || traceDistances[^1] <= 0) return [];

        _projectFiles = _projects.GetProjectFiles(_selectedProject.Id);
        var layers = BuildProjectMapLayers(_projectFiles)
            .Where(layer => layer.Type.Contains("KLIC", StringComparison.OrdinalIgnoreCase))
            .ToList();
        SyncKlicThemeStates(layers);

        var crossings = new List<KlicProfileCrossing>();
        foreach (var layer in layers)
        {
            foreach (var feature in layer.FeatureCollection.Features)
            {
                var theme = feature.Properties.TryGetValue("theme", out var themeValue) ? themeValue?.ToString() ?? "overig" : "overig";
                if (!workDrawingStep && _klicThemeStates.TryGetValue(theme, out var visible) && !visible) continue;

                foreach (var sourceLine in EnumerateGeometryLines(feature.Geometry))
                {
                    var rdLine = sourceLine.Select(ToRdPoint).Where(point => point.X > 0 && point.Y > 0).ToList();
                    if (rdLine.Count < 2) continue;

                    for (var klicIndex = 1; klicIndex < rdLine.Count; klicIndex++)
                    {
                        var klicA = rdLine[klicIndex - 1];
                        var klicB = rdLine[klicIndex];

                        for (var traceIndex = 1; traceIndex < traceRows.Count; traceIndex++)
                        {
                            var traceA = traceRows[traceIndex - 1];
                            var traceB = traceRows[traceIndex];
                            var hasIntersection = TrySegmentIntersection(
                                traceA.X, traceA.Y, traceB.X, traceB.Y,
                                klicA.X, klicA.Y, klicB.X, klicB.Y,
                                out var traceRatio);

                            if (!hasIntersection)
                            {
                                continue;
                            }

                            var traceSegmentLength = Math.Max(0.001, traceDistances[traceIndex] - traceDistances[traceIndex - 1]);
                            var distanceOnTrace = traceDistances[traceIndex - 1] + traceSegmentLength * traceRatio;
                            var normalizedDistance = profileTotal * distanceOnTrace / Math.Max(1, traceDistances[^1]);
                            var depth = KlicThemeDepth(theme);
                            var nap = InterpolateSurfaceNap(normalizedDistance) - depth;
                            var label = BuildKlicProfileLabel(feature, theme);
                            crossings.Add(new KlicProfileCrossing(
                                Math.Round(normalizedDistance, 2),
                                Math.Round(nap, 2),
                                label,
                                theme,
                                KlicThemeColor(theme),
                                Math.Round(depth, 2),
                                true));
                        }
                    }
                }
            }
        }

        return crossings
            .GroupBy(crossing => $"{crossing.Theme}|{Math.Round(crossing.Distance, 1)}|{crossing.Label}")
            .Select(group => group.First())
            .OrderBy(crossing => crossing.Distance)
            .ThenBy(crossing => crossing.Nap)
            .Take(80)
            .ToList();
    }

    private double InterpolateSurfaceNap(double distance)
    {
        if (_profilePoints.Count == 0) return 0;
        if (distance <= _profilePoints[0].Distance) return _profilePoints[0].Surface;
        if (distance >= _profilePoints[^1].Distance) return _profilePoints[^1].Surface;

        for (var i = 1; i < _profilePoints.Count; i++)
        {
            var previous = _profilePoints[i - 1];
            var next = _profilePoints[i];
            if (distance > next.Distance) continue;

            var length = Math.Max(0.001, next.Distance - previous.Distance);
            var ratio = (distance - previous.Distance) / length;
            return previous.Surface + (next.Surface - previous.Surface) * ratio;
        }

        return _profilePoints[^1].Surface;
    }

    private static double KlicThemeDepth(string? theme) => theme switch
    {
        "laagspanning" => 0.8,
        "middenspanning" => 1.0,
        "hoogspanning" => 1.2,
        "gasLageDruk" => 0.9,
        "gasHogeDruk" => 1.1,
        "water" => 1.3,
        "datatransport" => 0.7,
        "rioolVrijverval" => 1.8,
        "rioolOnderOverOfOnderdruk" => 1.6,
        "warmte" => 1.1,
        _ => 1.4
    };

    private static IEnumerable<IReadOnlyList<double[]>> EnumerateGeometryLines(GeoJsonGeometry geometry)
    {
        if (geometry.Type.Equals("LineString", StringComparison.OrdinalIgnoreCase))
        {
            var line = ExtractCoordinateList(geometry.Coordinates);
            if (line.Count >= 2) yield return line;
        }
        else if (geometry.Type.Equals("MultiLineString", StringComparison.OrdinalIgnoreCase) ||
                 geometry.Type.Equals("Polygon", StringComparison.OrdinalIgnoreCase))
        {
            foreach (var child in ExtractNestedCoordinateLists(geometry.Coordinates))
            {
                if (child.Count >= 2) yield return child;
            }
        }
        else if (geometry.Type.Equals("MultiPolygon", StringComparison.OrdinalIgnoreCase) &&
                 geometry.Coordinates is System.Collections.IEnumerable polygons &&
                 geometry.Coordinates is not string)
        {
            foreach (var polygon in polygons)
            {
                foreach (var child in ExtractNestedCoordinateLists(polygon))
                {
                    if (child.Count >= 2) yield return child;
                }
            }
        }
    }

    private static List<double[]> ExtractCoordinateList(object? coordinates)
    {
        var result = new List<double[]>();
        if (coordinates is IEnumerable<double[]> direct)
        {
            result.AddRange(direct);
            return result;
        }

        if (coordinates is not System.Collections.IEnumerable enumerable || coordinates is string) return result;
        foreach (var item in enumerable)
        {
            if (TryGetCoordinate(item, out var coordinate))
            {
                result.Add(coordinate);
            }
        }

        return result;
    }

    private static IEnumerable<List<double[]>> ExtractNestedCoordinateLists(object? coordinates)
    {
        if (coordinates is not System.Collections.IEnumerable enumerable || coordinates is string) yield break;
        foreach (var item in enumerable)
        {
            var line = ExtractCoordinateList(item);
            if (line.Count >= 2)
            {
                yield return line;
            }
        }
    }

    private static bool TryGetCoordinate(object? value, out double[] coordinate)
    {
        switch (value)
        {
            case double[] array when array.Length >= 2:
                coordinate = [array[0], array[1]];
                return true;
            case IReadOnlyList<double> list when list.Count >= 2:
                coordinate = [list[0], list[1]];
                return true;
            case System.Collections.IEnumerable enumerable when value is not string:
            {
                var values = enumerable.OfType<double>().Take(2).ToArray();
                if (values.Length >= 2)
                {
                    coordinate = [values[0], values[1]];
                    return true;
                }
                break;
            }
        }

        coordinate = [];
        return false;
    }

    private RdPoint ToRdPoint(double[] coordinate)
    {
        if (coordinate.Length < 2) return new RdPoint(0, 0);
        return CoordinateToRdPoint(coordinate[0], coordinate[1]);
    }

    private static RdPoint Wgs84ToRd(double longitude, double latitude)
    {
        var dLat = 0.36 * (latitude - 52.15517440);
        var dLon = 0.36 * (longitude - 5.38720621);
        var x = 155000.0
            + 190094.945 * Math.Pow(dLon, 1)
            - 11832.228 * Math.Pow(dLat, 1) * Math.Pow(dLon, 1)
            - 114.221 * Math.Pow(dLat, 2) * Math.Pow(dLon, 1)
            - 32.391 * Math.Pow(dLon, 3)
            - 0.705 * Math.Pow(dLat, 1)
            - 2.340 * Math.Pow(dLat, 3) * Math.Pow(dLon, 1)
            - 0.608 * Math.Pow(dLat, 1) * Math.Pow(dLon, 3)
            - 0.008 * Math.Pow(dLon, 2)
            + 0.148 * Math.Pow(dLat, 2) * Math.Pow(dLon, 3);

        var y = 463000.0
            + 309056.544 * Math.Pow(dLat, 1)
            + 3638.893 * Math.Pow(dLon, 2)
            + 73.077 * Math.Pow(dLat, 2)
            - 157.984 * Math.Pow(dLat, 1) * Math.Pow(dLon, 2)
            + 59.788 * Math.Pow(dLat, 3)
            + 0.433 * Math.Pow(dLon, 1)
            - 6.439 * Math.Pow(dLat, 2) * Math.Pow(dLon, 2)
            - 0.032 * Math.Pow(dLat, 1) * Math.Pow(dLon, 1)
            + 0.092 * Math.Pow(dLon, 4)
            - 0.054 * Math.Pow(dLat, 1) * Math.Pow(dLon, 4);

        return new RdPoint(x, y);
    }

    private static TraceProjection ProjectPointOnTrace(double x, double y, IReadOnlyList<TracePointRow> traceRows, IReadOnlyList<double> distances)
    {
        var bestDistance = 0d;
        var bestOffset = double.MaxValue;
        for (var i = 1; i < traceRows.Count; i++)
        {
            var a = traceRows[i - 1];
            var b = traceRows[i];
            var dx = b.X - a.X;
            var dy = b.Y - a.Y;
            var lengthSquared = dx * dx + dy * dy;
            if (lengthSquared <= 0.0001) continue;

            var t = Math.Max(0, Math.Min(1, ((x - a.X) * dx + (y - a.Y) * dy) / lengthSquared));
            var px = a.X + dx * t;
            var py = a.Y + dy * t;
            var offset = Math.Sqrt(Math.Pow(x - px, 2) + Math.Pow(y - py, 2));
            if (offset >= bestOffset) continue;

            bestOffset = offset;
            bestDistance = distances[i - 1] + Math.Sqrt(lengthSquared) * t;
        }

        return new TraceProjection(bestDistance, bestOffset);
    }

    private static bool TrySegmentIntersection(
        double ax,
        double ay,
        double bx,
        double by,
        double cx,
        double cy,
        double dx,
        double dy,
        out double traceRatio)
    {
        traceRatio = 0;
        var rx = bx - ax;
        var ry = by - ay;
        var sx = dx - cx;
        var sy = dy - cy;
        var denominator = rx * sy - ry * sx;
        if (Math.Abs(denominator) < 0.000001) return false;

        var qpx = cx - ax;
        var qpy = cy - ay;
        var t = (qpx * sy - qpy * sx) / denominator;
        var u = (qpx * ry - qpy * rx) / denominator;
        if (t is < 0 or > 1 || u is < 0 or > 1) return false;

        traceRatio = t;
        return true;
    }

    private static SegmentClosest ClosestPointBetweenSegments(TracePointRow traceA, TracePointRow traceB, RdPoint klicA, RdPoint klicB)
    {
        var bestRatio = 0d;
        var bestOffset = double.MaxValue;
        for (var step = 0; step <= 20; step++)
        {
            var ratio = step / 20d;
            var x = traceA.X + (traceB.X - traceA.X) * ratio;
            var y = traceA.Y + (traceB.Y - traceA.Y) * ratio;
            var offset = DistancePointToSegment(x, y, klicA.X, klicA.Y, klicB.X, klicB.Y);
            if (offset >= bestOffset) continue;

            bestOffset = offset;
            bestRatio = ratio;
        }

        return new SegmentClosest(bestRatio, bestOffset);
    }

    private static double DistancePointToSegment(double px, double py, double ax, double ay, double bx, double by)
    {
        var dx = bx - ax;
        var dy = by - ay;
        var lengthSquared = dx * dx + dy * dy;
        if (lengthSquared <= 0.0001) return Math.Sqrt(Math.Pow(px - ax, 2) + Math.Pow(py - ay, 2));

        var t = Math.Max(0, Math.Min(1, ((px - ax) * dx + (py - ay) * dy) / lengthSquared));
        var x = ax + dx * t;
        var y = ay + dy * t;
        return Math.Sqrt(Math.Pow(px - x, 2) + Math.Pow(py - y, 2));
    }

    private void RenderProfilePanel()
    {
        if (_selectedStep?.Number != ProfileStepNumber && _selectedStep?.Number != WorkDrawingStepNumber) return;
        if (_profilePoints.Count < 2)
        {
            EnsureProfilePoints();
        }

        ProfileCanvas.Children.Clear();
        ProfilePointsPanel.Children.Clear();
        ProfileEngineeringPanel.Children.Clear();
        var pointsInSidebar = _selectedStep?.Number == WorkDrawingStepNumber;
        ProfilePointsTitle.Visibility = pointsInSidebar ? Visibility.Collapsed : Visibility.Visible;
        ProfilePointsScroll.Visibility = pointsInSidebar ? Visibility.Collapsed : Visibility.Visible;
        WorkDrawingTitleBlock.Visibility = pointsInSidebar ? Visibility.Visible : Visibility.Collapsed;
        UpdateWorkDrawingTitleBlock();

        if (_profilePoints.Count < 2)
        {
            ProfileSummaryText.Text = $"Teken en sla eerst een boorlijn op in stap {DisplayStepNumber(3)}.1.";
            if (pointsInSidebar) RenderWorkDrawingProfileRowsSidebar();
            return;
        }

        if (_profileGeometryDirty)
        {
            RecalculateProfileRolesAndNap();
            _profileGeometryDirty = false;
        }
        UpdateWorkDrawingTitleBlock();
        ProfileSummaryText.Text = $"{_profilePoints.Count} punt(en) - {_profilePoints[^1].Distance:N1} m - laagste boorlijn {_profilePoints.Min(p => p.Nap):N2} m NAP - boring Ø{GetBoringDiameterMillimeters()} mm";
        if (_profileHasUnsavedChanges)
        {
            ProfileSummaryText.Text += " - niet opgeslagen";
        }
        DrawProfileCanvas();
        RenderProfileEngineeringTable();
        RenderProfileRows();
        if (pointsInSidebar) RenderWorkDrawingProfileRowsSidebar();
    }

    private void UpdateWorkDrawingTitleBlock()
    {
        if (_selectedStep?.Number != WorkDrawingStepNumber) return;
        var project = _selectedProject?.Name ?? "Werktekening HDD";
        var location = _selectedProject?.Location ?? string.Empty;
        WorkDrawingTitleProject.Text = string.IsNullOrWhiteSpace(location) ? project : $"{project} - {location}";
        WorkDrawingTitleScale.Text = $"1:{_workDrawingScale}";
        WorkDrawingTitleBoring.Text = $"Ø{GetBoringDiameterMillimeters()} mm";
        var trace = _profilePoints.Count > 0 ? _profilePoints[^1].Distance : 0;
        WorkDrawingTitleTrace.Text = $"{trace:N1} m";
    }
    private void DrawProfileCanvas()
    {
        var viewportWidth = ProfileCanvasViewport.ActualWidth > 40 ? ProfileCanvasViewport.ActualWidth - 4 : 760;
        var width = Math.Clamp(viewportWidth, 620d, _profileExpanded ? 1080d : 920d);
        var height = CalculateProfileCanvasHeight(width, _profileExpanded);
        ProfileCanvas.Width = width;
        ProfileCanvas.Height = height;
        ProfileCanvas.LayoutTransform = new ScaleTransform(_profileViewZoom, _profileViewZoom);
        ProfileCanvasViewport.Height = CalculateProfileViewportHeight(height, _profileExpanded);
        ProfileExpandButton.Content = _profileExpanded ? "Dwarsprofiel inklappen" : "Dwarsprofiel vergroten";
        ProfileZoomText.Text = $"{_profileViewZoom * 100:0}%";
        // The profile is only truly map-aligned while the GIS map is visible next
        // to it. In the tabbed 7.2 layout the map is hidden on the profile tab, so
        // use the normal (wider right margin) distance-based layout in that case.
        var effectiveAligned = _profileAlignedToMap
            && StepThreeMapFrame.Visibility == Visibility.Visible
            && StepThreeMapFrame.ActualWidth >= 40;
        var left = 96d;
        var right = effectiveAligned ? 14d : 80d;
        const double top = 46;
        const double surfaceStripTop = 18;
        const double surfaceStripHeight = 20;
        const double bottom = 34;
        var plotWidth = Math.Max(100, width - left - right);
        var plotHeight = Math.Max(100, height - top - bottom);
        var total = Math.Max(1, _profilePoints[^1].Distance);
        var klicCrossings = GetVisibleKlicProfileCrossings(total);
        var klicNaps = klicCrossings.Select(crossing => crossing.Nap).ToList();
        var profileMin = Math.Min(_profilePoints.Min(p => p.Nap), _profilePoints.Min(p => p.Surface));
        var profileMax = Math.Max(_profilePoints.Max(p => p.Nap), _profilePoints.Max(p => p.Surface));
        if (klicNaps.Count > 0)
        {
            profileMin = Math.Min(profileMin, klicNaps.Min());
            profileMax = Math.Max(profileMax, klicNaps.Max());
        }

        var minY = Math.Floor(profileMin - 1);
        var maxY = Math.Ceiling(profileMax + 1);
        if (Math.Abs(maxY - minY) < 1) maxY = minY + 1;

        double FallbackX(double distance) => left + plotWidth * distance / total;
        double XDistance(double distance) => ProfileXFromMapMetrics(distance, FallbackX(distance), width, total);
        double X(ProfilePointRow point) => XDistance(point.Distance);
        double Y(double nap) => top + plotHeight * (maxY - nap) / (maxY - minY);
        var labelBounds = new List<Rect>();

        ProfileCanvas.Children.Add(new Rectangle { Width = width, Height = height, Fill = Brushes.White });
        DrawBgtSurfaceStrip(XDistance, surfaceStripTop, surfaceStripHeight, total, left, plotWidth);
        for (var i = 0; i <= 4; i++)
        {
            var y = top + plotHeight * i / 4;
            ProfileCanvas.Children.Add(new Line { X1 = left, X2 = left + plotWidth, Y1 = y, Y2 = y, Stroke = Brush("#E5ECF0"), StrokeThickness = 1 });
            var label = new TextBlock { Text = $"{maxY - (maxY - minY) * i / 4:N1}", Foreground = Brush("#8FA6B2"), FontSize = 10 };
            Canvas.SetLeft(label, 5);
            Canvas.SetTop(label, y - 8);
            ProfileCanvas.Children.Add(label);
        }

        var surface = new Polyline { Stroke = Brush("#4B5563"), StrokeThickness = 2 };
        var boringDiameterMeters = Math.Max(0.075, GetBoringDiameterMillimeters() / 1000d);
        var boreBandThickness = Math.Max(2, boringDiameterMeters * plotHeight / Math.Max(0.1, maxY - minY));
        var boreBand = new Polyline
        {
            Stroke = Brush("#FDA4AF"),
            StrokeThickness = boreBandThickness,
            StrokeStartLineCap = PenLineCap.Round,
            StrokeEndLineCap = PenLineCap.Round,
            StrokeLineJoin = PenLineJoin.Round,
            Opacity = 0.55
        };
        var bore = new Polyline { Stroke = Brush("#F97316"), StrokeThickness = 3, StrokeDashArray = new DoubleCollection([5, 3]) };
        var borePoints = new List<Point>();
        foreach (var point in _profilePoints)
        {
            var borePoint = new Point(X(point), Y(point.Nap));
            surface.Points.Add(new Point(X(point), Y(point.Surface)));
            boreBand.Points.Add(borePoint);
            bore.Points.Add(borePoint);
            borePoints.Add(borePoint);
        }
        ProfileCanvas.Children.Add(surface);
        DrawMachineSideSymbolOnProfile(XDistance, Y);

        var crossingIndex = 0;
        var showKlicBuffer = _mapOverlayStates.TryGetValue("klicBuffer", out var bufferVisible) && bufferVisible;
        foreach (var crossing in klicCrossings)
        {
            var x = XDistance(crossing.Distance);
            var y = Y(crossing.Nap);
            if (showKlicBuffer)
            {
                var radiusX = Math.Max(8, plotWidth / total);
                var radiusY = Math.Max(8, plotHeight / Math.Max(1, maxY - minY));
                var buffer = new Ellipse
                {
                    Width = radiusX * 2,
                    Height = radiusY * 2,
                    Fill = Brushes.Transparent,
                    Stroke = Brush(crossing.Color),
                    StrokeThickness = 1.5,
                    StrokeDashArray = new DoubleCollection([3, 3]),
                    Opacity = 0.8
                };
                Canvas.SetLeft(buffer, x - radiusX);
                Canvas.SetTop(buffer, y - radiusY);
                ProfileCanvas.Children.Add(buffer);
            }

            var marker = new Ellipse
            {
                Width = 12,
                Height = 12,
                Fill = Brush(crossing.Color),
                Stroke = Brushes.White,
                StrokeThickness = 2
            };
            Canvas.SetLeft(marker, x - 6);
            Canvas.SetTop(marker, y - 6);
            ProfileCanvas.Children.Add(marker);

            var stem = new Line
            {
                X1 = x,
                X2 = x,
                Y1 = Math.Max(top, y - 18),
                Y2 = Math.Min(top + plotHeight, y + 18),
                Stroke = Brush(crossing.Color),
                StrokeThickness = 1,
                StrokeDashArray = new DoubleCollection([2, 2]),
                Opacity = 0.85
            };
            ProfileCanvas.Children.Add(stem);

            var key = $"K{crossingIndex + 1}";
            var label = new Border
            {
                Background = Brushes.White,
                BorderBrush = Brush(crossing.Color),
                BorderThickness = new Thickness(1),
                CornerRadius = new CornerRadius(3),
                Padding = new Thickness(4, 1, 4, 1),
                Child = new TextBlock
                {
                    Text = key,
                    Foreground = Brush(crossing.Color),
                    FontSize = 9,
                    FontWeight = FontWeights.Bold
                }
            };
            var labelPoint = PlaceProfileLabel(
                x - 11,
                y - 28 - (crossingIndex % 4) * 15,
                30,
                18,
                left,
                top,
                left + plotWidth,
                top + plotHeight,
                labelBounds);
            Canvas.SetLeft(label, labelPoint.X);
            Canvas.SetTop(label, labelPoint.Y);
            ProfileCanvas.Children.Add(label);
            crossingIndex++;
        }

        if (_profileSmoothBore && borePoints.Count >= 3)
        {
            ProfileCanvas.Children.Add(CreateSmoothProfilePath(borePoints, Brush("#FDA4AF"), boreBandThickness, null, 0.55));
            ProfileCanvas.Children.Add(CreateSmoothProfilePath(borePoints, Brush("#F97316"), 3, new DoubleCollection([5, 3]), 1));
        }
        else
        {
            ProfileCanvas.Children.Add(boreBand);
            ProfileCanvas.Children.Add(bore);
        }

        DrawProfileEngineeringMarkers(XDistance, Y);
        DrawProfileAngleCallout("Intrede", SegmentAngle(0), X(_profilePoints[0]), Y(_profilePoints[0].Nap), 24, -30);
        DrawProfileAngleCallout("Uittrede", SegmentAngle(_profilePoints.Count - 2), X(_profilePoints[^1]), Y(_profilePoints[^1].Nap), -122, -44);

        for (var i = 0; i < _profilePoints.Count - 1; i++)
        {
            var a = _profilePoints[i];
            var b = _profilePoints[i + 1];
            var midX = (X(a) + X(b)) / 2;
            var midY = (Y(a.Nap) + Y(b.Nap)) / 2;
            var angle = SegmentAngle(i);
            var color = angle < -8 ? "#DC2626" : angle > 8 ? "#16A34A" : "#F97316";
            if (SegmentDistance(i) < 2.5) continue;
            var labelText = $"{SegmentDistance(i):N1} m  {angle:+0.0;-0.0;0.0}°";
            var label = new Border
            {
                Background = Brushes.White,
                BorderBrush = Brush(color),
                BorderThickness = new Thickness(1),
                CornerRadius = new CornerRadius(4),
                Padding = new Thickness(5, 2, 5, 2),
                Child = new TextBlock
                {
                    Text = labelText,
                    Foreground = Brush(color),
                    FontSize = 10,
                    FontWeight = FontWeights.Bold
                }
            };
            var labelPoint = PlaceProfileLabel(
                midX - 42,
                midY - 28 - (i % 2) * 20,
                86,
                22,
                left,
                top,
                left + plotWidth,
                top + plotHeight,
                labelBounds);
            Canvas.SetLeft(label, labelPoint.X);
            Canvas.SetTop(label, labelPoint.Y);
            ProfileCanvas.Children.Add(label);
        }

        if (_mapOverlayStates.TryGetValue("profileTracePoints", out var showTracePoints) && showTracePoints)
        {
            foreach (var point in GetTraceReferenceProfilePoints(total))
            {
                var x = XDistance(point.Distance);
                var y = Y(point.Surface) - 20;
                var dot = new Ellipse { Width = 11, Height = 11, Fill = Brushes.White, Stroke = Brush("#E11D48"), StrokeThickness = 2 };
                Canvas.SetLeft(dot, x - 5.5);
                Canvas.SetTop(dot, y - 5.5);
                ProfileCanvas.Children.Add(dot);
                var label = new TextBlock { Text = point.Index.ToString(CultureInfo.InvariantCulture), Foreground = Brush("#E11D48"), FontSize = 9, FontWeight = FontWeights.Bold };
                Canvas.SetLeft(label, x - 4);
                Canvas.SetTop(label, y - 20);
                ProfileCanvas.Children.Add(label);
            }
        }

        foreach (var point in _profilePoints)
        {
            var x = X(point);
            var y = Y(point.Nap);
            var dot = new Ellipse
            {
                Width = 13,
                Height = 13,
                Fill = point.Index == 1 ? Brush("#4B5563") : point.Index == _profilePoints.Count ? Brush("#DC2626") : Brush("#F97316"),
                Stroke = Brushes.White,
                StrokeThickness = 2
            };
            Canvas.SetLeft(dot, x - 6.5);
            Canvas.SetTop(dot, y - 6.5);
            ProfileCanvas.Children.Add(dot);

            var label = new TextBlock
            {
                Text = point.Index == 1 ? "S" : point.Index == _profilePoints.Count ? "E" : point.Index.ToString(CultureInfo.InvariantCulture),
                Foreground = Brush("#071422"),
                FontSize = 10,
                FontWeight = FontWeights.Bold
            };
            Canvas.SetLeft(label, x - 5);
            Canvas.SetTop(label, y - 24);
            ProfileCanvas.Children.Add(label);
        }
    }

    private static double CalculateProfileCanvasHeight(double width, bool expanded)
    {
        var target = width * (expanded ? 0.56 : 0.48);
        return expanded
            ? Math.Clamp(target, 430d, 610d)
            : Math.Clamp(target, 300d, 390d);
    }

    private static double CalculateProfileViewportHeight(double canvasHeight, bool expanded)
    {
        var target = canvasHeight + 28;
        return expanded
            ? Math.Clamp(target, 460d, 650d)
            : Math.Clamp(target, 330d, 420d);
    }

    private static Point PlaceProfileLabel(
        double desiredX,
        double desiredY,
        double width,
        double height,
        double minX,
        double minY,
        double maxX,
        double maxY,
        IList<Rect> occupied)
    {
        var candidates = new[]
        {
            desiredY,
            desiredY - height,
            desiredY + height,
            desiredY - 2 * height,
            desiredY + 2 * height,
            minY + 2,
            maxY - height - 2
        };

        foreach (var candidateY in candidates)
        {
            var x = Math.Clamp(desiredX, minX + 2, maxX - width - 2);
            var y = Math.Clamp(candidateY, minY + 2, maxY - height - 2);
            var rect = new Rect(x, y, width, height);
            if (occupied.Any(existing => existing.IntersectsWith(rect))) continue;
            occupied.Add(rect);
            return new Point(x, y);
        }

        var fallbackX = Math.Clamp(desiredX, minX + 2, maxX - width - 2);
        var fallbackY = Math.Clamp(desiredY, minY + 2, maxY - height - 2);
        var fallback = new Rect(fallbackX, fallbackY, width, height);
        occupied.Add(fallback);
        return new Point(fallbackX, fallbackY);
    }

    private void DrawMachineSideSymbolOnProfile(Func<double, double> xDistance, Func<double, double> yNap)
    {
        // The machine footprint box only belongs on the formal werktekening; the
        // dwarsprofiel (stap 7) shows the profile itself without the machine block.
        if (_selectedStep?.Number != WorkDrawingStepNumber || _profilePoints.Count < 2) return;

        var start = _profilePoints[0];
        var anchorX = xDistance(start.Distance);
        var anchorY = yNap(start.Surface);
        const double machineHeightMeters = 2.0;
        var machineLengthMeters = Math.Max(1, _machineLengthMeters);
        var machineWidthMeters = Math.Max(0.5, _machineWidthMeters);
        var rectWidth = Math.Max(56, Math.Abs(xDistance(Math.Min(_profilePoints[^1].Distance, machineLengthMeters)) - xDistance(0)));
        var rectHeight = Math.Max(22, Math.Abs(yNap(start.Surface + machineHeightMeters) - yNap(start.Surface)));
        var rectLeft = anchorX - rectWidth - 8;
        var rectTop = anchorY - rectHeight - 4;
        var machineStroke = Brush("#A52A08");

        var machineBox = new Rectangle
        {
            Width = rectWidth,
            Height = rectHeight,
            Fill = Brush("#FFF7ED"),
            Stroke = machineStroke,
            StrokeThickness = 2,
            Opacity = 0.95
        };
        Canvas.SetLeft(machineBox, rectLeft);
        Canvas.SetTop(machineBox, rectTop);
        ProfileCanvas.Children.Add(machineBox);

        ProfileCanvas.Children.Add(new Line
        {
            X1 = rectLeft + rectWidth,
            Y1 = rectTop + rectHeight,
            X2 = anchorX,
            Y2 = anchorY,
            Stroke = machineStroke,
            StrokeThickness = 2,
            StrokeStartLineCap = PenLineCap.Round,
            StrokeEndLineCap = PenLineCap.Round
        });

        var anchor = new Ellipse
        {
            Width = 7,
            Height = 7,
            Fill = Brushes.White,
            Stroke = machineStroke,
            StrokeThickness = 1.8
        };
        Canvas.SetLeft(anchor, anchorX - 3.5);
        Canvas.SetTop(anchor, anchorY - 3.5);
        ProfileCanvas.Children.Add(anchor);

        var label = new Border
        {
            Background = Brushes.White,
            BorderBrush = machineStroke,
            BorderThickness = new Thickness(1),
            CornerRadius = new CornerRadius(3),
            Padding = new Thickness(4, 1, 4, 1),
            Child = new TextBlock
            {
                Text = $"Machine {machineLengthMeters:0.##} x {machineWidthMeters:0.##} x {machineHeightMeters:0.##} m",
                Foreground = machineStroke,
                FontSize = 9,
                FontWeight = FontWeights.SemiBold
            }
        };
        Canvas.SetLeft(label, rectLeft);
        Canvas.SetTop(label, Math.Max(2, rectTop - 20));
        ProfileCanvas.Children.Add(label);
    }

    private void DrawProfileAngleCallout(string label, double angle, double x, double y, double offsetX, double offsetY)
    {
        if (!double.IsFinite(angle)) return;
        var color = Math.Abs(angle) >= 8 ? "#B91C1C" : "#B45309";
        var lineLength = 34d;
        var direction = offsetX >= 0 ? 1 : -1;
        ProfileCanvas.Children.Add(new Line
        {
            X1 = x,
            Y1 = y,
            X2 = x + direction * lineLength,
            Y2 = y,
            Stroke = Brush("#111827"),
            StrokeThickness = 1,
            Opacity = 0.75
        });
        ProfileCanvas.Children.Add(new Line
        {
            X1 = x,
            Y1 = y,
            X2 = x + direction * 28,
            Y2 = y + Math.Tan(angle * Math.PI / 180) * 28,
            Stroke = Brush(color),
            StrokeThickness = 1.6,
            StrokeStartLineCap = PenLineCap.Round,
            StrokeEndLineCap = PenLineCap.Round
        });

        var border = new Border
        {
            Background = Brushes.White,
            BorderBrush = Brush(color),
            BorderThickness = new Thickness(1),
            CornerRadius = new CornerRadius(4),
            Padding = new Thickness(5, 2, 5, 2),
            Child = new TextBlock
            {
                Text = $"{label} {angle:+0.0;-0.0;0.0}°",
                Foreground = Brush(color),
                FontSize = 10,
                FontWeight = FontWeights.Bold
            }
        };
        Canvas.SetLeft(border, Math.Clamp(x + offsetX, 2d, Math.Max(2d, ProfileCanvas.Width - 132d)));
        Canvas.SetTop(border, Math.Clamp(y + offsetY, 2d, Math.Max(2d, ProfileCanvas.Height - 28d)));
        ProfileCanvas.Children.Add(border);
    }

    private void DrawProfileEngineeringMarkers(Func<double, double> xDistance, Func<double, double> yNap)
    {
        foreach (var sample in BuildProfileEngineeringSamples())
        {
            var point = ProfileBorePointAtDistance(sample.Distance, xDistance, yNap);
            var x = point.X;
            var y = point.Y;
            var dot = new Ellipse
            {
                Width = 8,
                Height = 8,
                Fill = Brush("#64748B"),
                Stroke = Brushes.White,
                StrokeThickness = 1.5
            };
            Canvas.SetLeft(dot, x - 4);
            Canvas.SetTop(dot, y - 4);
            ProfileCanvas.Children.Add(dot);

            var label = new TextBlock
            {
                Text = sample.Code,
                Foreground = Brush("#475569"),
                FontSize = 9,
                FontWeight = FontWeights.Bold
            };
            Canvas.SetLeft(label, x - 4);
            Canvas.SetTop(label, y + 7);
            ProfileCanvas.Children.Add(label);
        }
    }

    private Point ProfileBorePointAtDistance(double distance, Func<double, double> xDistance, Func<double, double> yNap)
    {
        if (!_profileSmoothBore || _profilePoints.Count < 3)
        {
            return new Point(xDistance(distance), yNap(InterpolateProfileValue(distance, point => point.Nap)));
        }

        if (distance <= _profilePoints[0].Distance)
        {
            return new Point(xDistance(_profilePoints[0].Distance), yNap(_profilePoints[0].Nap));
        }
        if (distance >= _profilePoints[^1].Distance)
        {
            return new Point(xDistance(_profilePoints[^1].Distance), yNap(_profilePoints[^1].Nap));
        }

        for (var i = 0; i < _profilePoints.Count - 1; i++)
        {
            var row1 = _profilePoints[i];
            var row2 = _profilePoints[i + 1];
            if (distance > row2.Distance && i < _profilePoints.Count - 2) continue;

            var row0 = i == 0 ? row1 : _profilePoints[i - 1];
            var row3 = i + 2 < _profilePoints.Count ? _profilePoints[i + 2] : row2;
            var p0 = new Point(xDistance(row0.Distance), yNap(row0.Nap));
            var p1 = new Point(xDistance(row1.Distance), yNap(row1.Nap));
            var p2 = new Point(xDistance(row2.Distance), yNap(row2.Nap));
            var p3 = new Point(xDistance(row3.Distance), yNap(row3.Nap));
            var c1 = new Point(p1.X + (p2.X - p0.X) / 6, p1.Y + (p2.Y - p0.Y) / 6);
            var c2 = new Point(p2.X - (p3.X - p1.X) / 6, p2.Y - (p3.Y - p1.Y) / 6);
            var segment = Math.Max(0.001, row2.Distance - row1.Distance);
            var t = Math.Clamp((distance - row1.Distance) / segment, 0, 1);
            return CubicBezier(p1, c1, c2, p2, t);
        }

        return new Point(xDistance(distance), yNap(InterpolateProfileValue(distance, point => point.Nap)));
    }

    private static Point CubicBezier(Point p0, Point c1, Point c2, Point p3, double t)
    {
        var u = 1 - t;
        var tt = t * t;
        var uu = u * u;
        var uuu = uu * u;
        var ttt = tt * t;
        return new Point(
            uuu * p0.X + 3 * uu * t * c1.X + 3 * u * tt * c2.X + ttt * p3.X,
            uuu * p0.Y + 3 * uu * t * c1.Y + 3 * u * tt * c2.Y + ttt * p3.Y);
    }

    private static System.Windows.Shapes.Path CreateSmoothProfilePath(IReadOnlyList<Point> points, Brush stroke, double thickness, DoubleCollection? dashArray, double opacity)
    {
        var figure = new PathFigure { StartPoint = points[0], IsClosed = false, IsFilled = false };
        for (var i = 0; i < points.Count - 1; i++)
        {
            var p0 = i == 0 ? points[i] : points[i - 1];
            var p1 = points[i];
            var p2 = points[i + 1];
            var p3 = i + 2 < points.Count ? points[i + 2] : p2;
            var c1 = new Point(p1.X + (p2.X - p0.X) / 6, p1.Y + (p2.Y - p0.Y) / 6);
            var c2 = new Point(p2.X - (p3.X - p1.X) / 6, p2.Y - (p3.Y - p1.Y) / 6);
            figure.Segments.Add(new BezierSegment(c1, c2, p2, true));
        }

        return new System.Windows.Shapes.Path
        {
            Data = new PathGeometry([figure]),
            Stroke = stroke,
            StrokeThickness = thickness,
            StrokeStartLineCap = PenLineCap.Round,
            StrokeEndLineCap = PenLineCap.Round,
            StrokeLineJoin = PenLineJoin.Round,
            StrokeDashArray = dashArray,
            Opacity = opacity
        };
    }

    private static string SmoothSvgPathData(IReadOnlyList<Point> points, Func<double, string> format)
    {
        var builder = new StringBuilder();
        builder.Append($"M {format(points[0].X)} {format(points[0].Y)}");
        for (var i = 0; i < points.Count - 1; i++)
        {
            var p0 = i == 0 ? points[i] : points[i - 1];
            var p1 = points[i];
            var p2 = points[i + 1];
            var p3 = i + 2 < points.Count ? points[i + 2] : p2;
            var c1 = new Point(p1.X + (p2.X - p0.X) / 6, p1.Y + (p2.Y - p0.Y) / 6);
            var c2 = new Point(p2.X - (p3.X - p1.X) / 6, p2.Y - (p3.Y - p1.Y) / 6);
            builder.Append(CultureInfo.InvariantCulture, $" C {format(c1.X)} {format(c1.Y)}, {format(c2.X)} {format(c2.Y)}, {format(p2.X)} {format(p2.Y)}");
        }

        return builder.ToString();
    }

    private void DrawBgtSurfaceStrip(Func<double, double> xDistance, double top, double height, double total, double left, double plotWidth)
    {
        var segments = GetBgtSurfaceSegments(total);
        if (segments.Count == 0) return;

        var title = new TextBlock
        {
            Text = "Oppervlak",
            Foreground = Brush("#5F7785"),
            FontSize = 9,
            FontWeight = FontWeights.Bold
        };
        Canvas.SetLeft(title, 5);
        Canvas.SetTop(title, top + 2);
        ProfileCanvas.Children.Add(title);

        foreach (var segment in segments)
        {
            var startX = xDistance(segment.Start);
            var endX = xDistance(segment.End);
            var width = Math.Max(3, endX - startX);
            var rect = new Rectangle
            {
                Width = width,
                Height = height,
                Fill = Brush(segment.Color),
                Stroke = Brush("#FFFFFF"),
                StrokeThickness = 1,
                Opacity = 0.78
            };
            Canvas.SetLeft(rect, startX);
            Canvas.SetTop(rect, top);
            ProfileCanvas.Children.Add(rect);

            if (segment.Start > 0.1)
            {
                ProfileCanvas.Children.Add(new Line
                {
                    X1 = startX,
                    X2 = startX,
                    Y1 = top,
                    Y2 = top + height + 12,
                    Stroke = Brush("#64748B"),
                    StrokeThickness = 1,
                    StrokeDashArray = new DoubleCollection([2, 2]),
                    Opacity = 0.75
                });
            }

            if (width > 44)
            {
                var label = new TextBlock
                {
                    Text = $"{segment.Length:N0} m {segment.Label}",
                    Foreground = Brush("#071422"),
                    FontSize = 9,
                    FontWeight = FontWeights.Bold,
                    TextTrimming = TextTrimming.CharacterEllipsis,
                    Width = Math.Max(20, width - 6)
                };
                Canvas.SetLeft(label, startX + 3);
                Canvas.SetTop(label, top + 3);
                ProfileCanvas.Children.Add(label);
            }
        }

        ProfileCanvas.Children.Add(new Line
        {
            X1 = left,
            X2 = left + plotWidth,
            Y1 = top + height,
            Y2 = top + height,
            Stroke = Brush("#CBD5E1"),
            StrokeThickness = 1
        });
    }

    private void RenderProfileRows()
    {
        ProfilePointsPanel.Children.Add(ProfileGridRow(["#", "Pos.", "Diepte", "NAP", "Segment", "Acties"], true, -1));
        for (var i = 0; i < _profilePoints.Count; i++)
        {
            var point = _profilePoints[i];
            var segment = i < _profilePoints.Count - 1 ? $"{SegmentDistance(i):N1} m / {SegmentAngle(i):N1}°" : "einde";
            ProfilePointsPanel.Children.Add(ProfileGridRow([
                point.Index == 1 ? "S" : point.Index == _profilePoints.Count ? "E" : point.Index.ToString(CultureInfo.InvariantCulture),
                $"{point.Distance:N1}",
                $"{point.Depth:N2}",
                $"{point.Nap:N2}",
                segment,
                ""
            ], false, i));
        }
    }

