    private void ProfilePointAction_OnClick(object sender, RoutedEventArgs e)
    {
        if ((sender as Button)?.Tag is not string tag) return;
        var parts = tag.Split(':');
        if (parts.Length != 2 || !int.TryParse(parts[1], out var index) || index < 0 || index >= _profilePoints.Count) return;

        var point = _profilePoints[index];
        switch (parts[0])
        {
            case "up":
                point = point with { Depth = Math.Max(0, point.Depth - 0.1) };
                _profilePoints[index] = point with { Nap = Math.Round(point.Surface - point.Depth, 2) };
                _profileHasUnsavedChanges = true;
                RenderProfilePanel();
                return;
            case "down":
                point = point with { Depth = point.Depth + 0.1 };
                _profilePoints[index] = point with { Nap = Math.Round(point.Surface - point.Depth, 2) };
                _profileHasUnsavedChanges = true;
                RenderProfilePanel();
                return;
            case "left" when index > 0:
                point = point with { Distance = Math.Max(_profilePoints[index - 1].Distance + 0.1, point.Distance - 1) };
                break;
            case "right" when index < _profilePoints.Count - 1:
                point = point with { Distance = Math.Min(_profilePoints[index + 1].Distance - 0.1, point.Distance + 1) };
                break;
            case "delete" when index > 0 && index < _profilePoints.Count - 1:
                _profilePoints.RemoveAt(index);
                _profileGeometryDirty = true;
                _profileHasUnsavedChanges = true;
                RenderProfilePanel();
                return;
        }

        _profilePoints[index] = point;
        _profileGeometryDirty = true;
        _profileHasUnsavedChanges = true;
        RenderProfilePanel();
    }

    private void RecalculateProfileRolesAndNap()
    {
        var ordered = _profilePoints.OrderBy(point => point.Distance).ToList();
        var count = ordered.Count;
        var total = count > 0 ? Math.Max(1, ordered[^1].Distance) : 1;
        var traceRows = GetTraceRowsForProfile();
        var traceDistances = BuildTraceDistances(traceRows);
        _profilePoints = ordered.Select((point, index) =>
        {
            var role = index == 0 ? "Intrede" : index == count - 1 ? "Uittrede" : "Dieptepunt";
            var xy = traceRows.Count >= 2 ? InterpolateTracePoint(traceRows, traceDistances, point.Distance) : new TracePointRow(0, role, point.X, point.Y);
            var surface = GetProfileSurfaceNap(xy.X, xy.Y, point.Distance, total, index, point.Surface);
            return point with { Index = index + 1, Role = role, X = xy.X, Y = xy.Y, Surface = surface, Nap = Math.Round(surface - point.Depth, 2) };
        }).ToList();
    }

    private static List<double> BuildTraceDistances(IReadOnlyList<TracePointRow> traceRows)
    {
        if (traceRows.Count == 0) return [];
        var distances = new List<double> { 0 };
        for (var i = 1; i < traceRows.Count; i++)
        {
            var previous = traceRows[i - 1];
            var current = traceRows[i];
            distances.Add(distances[^1] + Math.Sqrt(Math.Pow(current.X - previous.X, 2) + Math.Pow(current.Y - previous.Y, 2)));
        }

        return distances;
    }

    private double ProfileXFromMapMetrics(double profileDistance, double fallbackX, double profileCanvasWidth, double profileTotal)
    {
        // Map-aligned X positions only make sense while the GIS map is actually
        // rendered next to the profile. With the tabbed 7.2 layout the map is
        // collapsed whenever the Dwarsprofiel/Profielstaat tab is active, leaving
        // stale screen metrics that bunch every point against one edge. Fall back
        // to the deterministic distance-based layout whenever the map is hidden.
        if (!_profileAlignedToMap
            || _profileScreenMetrics is null
            || _profileScreenMetrics.Points.Count < 2
            || StepThreeMapFrame.Visibility != Visibility.Visible
            || StepThreeMapFrame.ActualWidth < 40)
        {
            return fallbackX;
        }

        var traceRows = GetTraceRowsForProfile();
        if (traceRows.Count < 2 || traceRows.Count != _profileScreenMetrics.Points.Count)
        {
            return fallbackX;
        }

        var traceDistances = BuildTraceDistances(traceRows);
        if (traceDistances.Count != traceRows.Count || traceDistances[^1] <= 0 || profileTotal <= 0)
        {
            return fallbackX;
        }

        var targetDistance = traceDistances[^1] * profileDistance / profileTotal;
        var mapToCanvasOffset = Math.Max(0, (_profileScreenMetrics.MapWidth - profileCanvasWidth) / 2);

        for (var i = 1; i < traceDistances.Count; i++)
        {
            if (targetDistance > traceDistances[i] && i < traceDistances.Count - 1) continue;

            var segmentLength = Math.Max(0.001, traceDistances[i] - traceDistances[i - 1]);
            var ratio = Math.Clamp((targetDistance - traceDistances[i - 1]) / segmentLength, 0, 1);
            var from = _profileScreenMetrics.Points[i - 1].X;
            var to = _profileScreenMetrics.Points[i].X;
            return Math.Clamp(from + (to - from) * ratio - mapToCanvasOffset, 0, profileCanvasWidth);
        }

        return Math.Clamp(_profileScreenMetrics.Points[^1].X - mapToCanvasOffset, 0, profileCanvasWidth);
    }

    private IReadOnlyList<BgtSurfaceSegment> GetBgtSurfaceSegments(double profileTotal)
    {
        if (_mapOverlayStates.TryGetValue("bgt", out var bgtVisible) && !bgtVisible)
        {
            return [];
        }

        var traceRows = GetTraceRowsForProfile();
        if (traceRows.Count < 2 || profileTotal <= 0) return [];

        var traceDistances = BuildTraceDistances(traceRows);
        if (traceDistances.Count < 2 || traceDistances[^1] <= 0) return [];

        // The geometric polygon analysis does an exact point-in-polygon test against
        // the actual BGT surface polygons, so it matches the BGT precisely. The
        // MapLibre "rendered" sampling is only an approximation: it queries rendered
        // pixels and votes across a perpendicular band, which in ditch-rich areas
        // (e.g. polders) picks up neighbouring water and grossly over-reports it.
        // Trust the polygon analysis whenever it has solid coverage of the boorlijn.
        var polygonSegments = BuildBgtSurfaceSegmentsFromProjectPolygons(profileTotal, traceRows, traceDistances);
        if (polygonSegments.Count > 0 && KnownSurfaceFraction(polygonSegments, profileTotal) >= 0.6)
        {
            return polygonSegments;
        }

        var mapSegments = BuildCurrentMapBgtSurfaceSegments(profileTotal);
        var savedSegments = ReadSavedBgtSurfaceSegments(profileTotal);

        var bestCurrent = ChooseBestBgtSurfaceSegments(mapSegments, polygonSegments, profileTotal);
        return ChooseBestBgtSurfaceSegments(bestCurrent, savedSegments, profileTotal);
    }

    // Realistic upper bound for a single BGT surface tile the boorlijn can cross.
    // Above this a "surface" polygon is almost certainly a corrupt merged/multi-part
    // ring (e.g. every ditch in the tile fused into one 45 ha "water" polygon) whose
    // even-odd interior spuriously swallows the surrounding grass.
    private const double MaxBgtSurfaceTileArea = 300000d;

    private IReadOnlyList<BgtSurfaceSegment> BuildBgtSurfaceSegmentsFromProjectPolygons(
        double profileTotal,
        IReadOnlyList<TracePointRow> traceRows,
        IReadOnlyList<double> traceDistances)
    {
        _projectFiles = _selectedProject is null ? _projectFiles : _projects.GetProjectFiles(_selectedProject.Id);
        var polygons = BuildBgtSurfacePolygons();
        if (polygons.Count == 0)
        {
            return [];
        }

        var sampleStep = Math.Max(0.75, Math.Min(2.0, profileTotal / 80));
        var samples = new List<BgtSurfaceSample>();
        for (var distance = 0d; distance <= profileTotal + 0.001; distance += sampleStep)
        {
            var clampedDistance = Math.Min(profileTotal, distance);
            var traceDistance = traceDistances[^1] * clampedDistance / profileTotal;
            var point = InterpolateTracePoint(traceRows, traceDistances, traceDistance);
            // BGT surface (terreindeel) polygons tile the plane without overlap, so a
            // point sits in exactly one real surface. The GML parser can, however,
            // emit small spurious fragments; picking the *smallest* containing polygon
            // then latches onto those fragments (e.g. a 23 m² phantom "water" sliver on
            // top of a 16 000 m² grass field). Restrict to genuine surface types and
            // take the largest containing polygon so the real tiled surface wins.
            var polygon = polygons
                .Where(candidate => BgtSurfaceContains(candidate, point.X, point.Y))
                .Where(candidate => IsBgtSurfaceVisible(candidate.Label))
                .Where(candidate => IsRealBgtSurface(candidate.Label))
                // Guard against corrupt merged/parser-fabricated surface polygons: a
                // single BGT surface tile crossing the boorlijn is realistically well
                // under a few hectares. A giant multi-part ring (e.g. all ditches in
                // the tile fused into one 45 ha "water" polygon whose even-odd interior
                // swallows the surrounding grass) must not be treated as a real surface.
                .Where(candidate => candidate.Area <= MaxBgtSurfaceTileArea)
                .OrderByDescending(candidate => candidate.Area)
                .FirstOrDefault();
            samples.Add(polygon is null
                ? new BgtSurfaceSample(clampedDistance, "Onbekend", "#F8FAFC")
                : new BgtSurfaceSample(clampedDistance, polygon.Label, polygon.Color));
        }

        return BuildBgtSurfaceSegmentsFromSamples(samples, profileTotal);
    }

    private IReadOnlyList<BgtSurfaceSegment> BuildCurrentMapBgtSurfaceSegments(double profileTotal)
    {
        if (_mapBgtSurfaceSamples.Count < 2 || profileTotal <= 0)
        {
            return [];
        }

        return BuildBgtSurfaceSegmentsFromSamples(
            _mapBgtSurfaceSamples.Where(sample => IsBgtSurfaceVisible(sample.Label)).ToList(),
            profileTotal);
    }

    private IReadOnlyList<BgtSurfaceSegment> ReadSavedBgtSurfaceSegments(double profileTotal)
    {
        if (_selectedProject is null || profileTotal <= 0)
        {
            return [];
        }

        var json = _projects.GetStepData(_selectedProject.Id, 4, "surface_analysis_generated") ??
                   _projects.GetStepData(_selectedProject.Id, 5, "surface_analysis_generated");
        if (string.IsNullOrWhiteSpace(json))
        {
            return [];
        }

        try
        {
            using var document = JsonDocument.Parse(json);
            var root = document.RootElement;
            var segmentsElement = JsonProperty(root, "segments");
            if (segmentsElement is not { ValueKind: JsonValueKind.Array })
            {
                return [];
            }

            var result = new List<BgtSurfaceSegment>();
            foreach (var segmentElement in segmentsElement.Value.EnumerateArray())
            {
                var label = JsonText(segmentElement, "label", "");
                if (string.IsNullOrWhiteSpace(label) ||
                    !IsBgtSurfaceVisible(label))
                {
                    continue;
                }

                var start = Math.Clamp(JsonDouble(segmentElement, "start", 0), 0, profileTotal);
                var end = Math.Clamp(JsonDouble(segmentElement, "end", start), 0, profileTotal);
                var length = JsonDouble(segmentElement, "length", 0);
                if (end <= start && length > 0)
                {
                    end = Math.Clamp(start + length, 0, profileTotal);
                }

                if (end <= start)
                {
                    continue;
                }

                var color = JsonText(segmentElement, "color", BgtSurfaceColorForLabel(label));
                result.Add(new BgtSurfaceSegment(start, end, label, color));
            }

            return result
                .OrderBy(segment => segment.Start)
                .ToList();
        }
        catch
        {
            return [];
        }
    }

    private static IReadOnlyList<BgtSurfaceSegment> ChooseBestBgtSurfaceSegments(
        IReadOnlyList<BgtSurfaceSegment> mapSegments,
        IReadOnlyList<BgtSurfaceSegment> polygonSegments,
        double profileTotal)
    {
        if (mapSegments.Count == 0) return polygonSegments;
        if (polygonSegments.Count == 0) return mapSegments;

        var mapDominant = DominantSurfaceFraction(mapSegments, profileTotal);
        var polygonDominant = DominantSurfaceFraction(polygonSegments, profileTotal);
        var mapKnown = KnownSurfaceFraction(mapSegments, profileTotal);
        var polygonKnown = KnownSurfaceFraction(polygonSegments, profileTotal);
        var mapVariety = SurfaceVariety(mapSegments);
        var polygonVariety = SurfaceVariety(polygonSegments);

        if (!ContainsSurface(mapSegments, "water") && ContainsSurface(polygonSegments, "water"))
        {
            return polygonSegments;
        }

        if (ContainsSurface(polygonSegments, "water") && TotalSurfaceLength(polygonSegments, "water") > TotalSurfaceLength(mapSegments, "water") + 0.5)
        {
            return polygonSegments;
        }

        if (!ContainsSurface(mapSegments, "asfalt") && ContainsSurface(polygonSegments, "asfalt"))
        {
            return polygonSegments;
        }

        if (ContainsSurface(polygonSegments, "asfalt") && TotalSurfaceLength(polygonSegments, "asfalt") > TotalSurfaceLength(mapSegments, "asfalt") + 0.5)
        {
            return polygonSegments;
        }

        if (mapVariety <= 1 && mapDominant > 0.90 && polygonVariety > 1 && polygonKnown >= mapKnown - 0.10)
        {
            return polygonSegments;
        }

        if (mapDominant > 0.76 && polygonVariety > mapVariety && polygonDominant < mapDominant - 0.08)
        {
            return polygonSegments;
        }

        if (mapSegments.Count <= 2 && polygonSegments.Count >= mapSegments.Count + 2 && polygonKnown >= mapKnown - 0.05)
        {
            return polygonSegments;
        }

        return mapSegments;
    }

    private static double DominantSurfaceFraction(IReadOnlyList<BgtSurfaceSegment> segments, double profileTotal)
    {
        if (segments.Count == 0 || profileTotal <= 0) return 1;
        return segments
            .GroupBy(segment => NormalizeBgtSurfaceKey(segment.Label))
            .Max(group => group.Sum(segment => segment.Length)) / profileTotal;
    }

    private static double KnownSurfaceFraction(IReadOnlyList<BgtSurfaceSegment> segments, double profileTotal)
    {
        if (segments.Count == 0 || profileTotal <= 0) return 0;
        return segments
            .Where(segment => !segment.Label.Equals("Onbekend", StringComparison.OrdinalIgnoreCase))
            .Sum(segment => segment.Length) / profileTotal;
    }

    private static int SurfaceVariety(IReadOnlyList<BgtSurfaceSegment> segments) =>
        segments.Select(segment => NormalizeBgtSurfaceKey(segment.Label)).Distinct(StringComparer.OrdinalIgnoreCase).Count();

    private static bool ContainsSurface(IReadOnlyList<BgtSurfaceSegment> segments, string surface)
    {
        return segments.Any(segment => NormalizeBgtSurfaceKey(segment.Label).Equals(surface, StringComparison.OrdinalIgnoreCase));
    }

    private static double TotalSurfaceLength(IReadOnlyList<BgtSurfaceSegment> segments, string surface)
    {
        return segments
            .Where(segment => NormalizeBgtSurfaceKey(segment.Label).Equals(surface, StringComparison.OrdinalIgnoreCase))
            .Sum(segment => segment.Length);
    }

    private static IReadOnlyList<BgtSurfaceSegment> BuildBgtSurfaceSegmentsFromSamples(IReadOnlyList<BgtSurfaceSample> sourceSamples, double profileTotal)
    {
        var samples = sourceSamples
            .Where(sample => double.IsFinite(sample.Distance) && sample.Distance >= 0 && sample.Distance <= profileTotal + 0.001)
            .OrderBy(sample => sample.Distance)
            .ToList();
        if (samples.Count == 0) return [];
        if (samples[0].Distance > 0.001)
        {
            samples.Insert(0, samples[0] with { Distance = 0 });
        }
        if (samples[^1].Distance < profileTotal)
        {
            samples.Add(samples[^1] with { Distance = profileTotal });
        }

        var segments = new List<BgtSurfaceSegment>();
        var start = 0d;
        var current = samples[0];
        for (var i = 1; i < samples.Count; i++)
        {
            var sample = samples[i];
            if (sample.Label.Equals(current.Label, StringComparison.OrdinalIgnoreCase) && sample.Color.Equals(current.Color, StringComparison.OrdinalIgnoreCase))
            {
                continue;
            }

            var end = Math.Max(start, (samples[i - 1].Distance + sample.Distance) / 2);
            if (end - start >= 0.5)
            {
                segments.Add(new BgtSurfaceSegment(start, end, current.Label, current.Color));
            }

            start = end;
            current = sample;
        }

        if (profileTotal - start >= 0.5)
        {
            segments.Add(new BgtSurfaceSegment(start, profileTotal, current.Label, current.Color));
        }

        return segments.Where(segment => !segment.Label.Equals("Onbekend", StringComparison.OrdinalIgnoreCase) || segment.Length >= 3).ToList();
    }

    private IReadOnlyList<BgtSurfacePolygon> BuildBgtSurfacePolygons()
    {
        if (_mapOverlayStates.TryGetValue("bgt", out var bgtVisible) && !bgtVisible)
        {
            return [];
        }

        var polygons = new List<BgtSurfacePolygon>();
        foreach (var layer in BuildProjectMapLayers(_projectFiles)
                     .Where(layer => layer.Type.Equals("BGT", StringComparison.OrdinalIgnoreCase))
                     .Where(layer => IsProjectLayerVisible(layer.Id)))
        {
            foreach (var feature in layer.FeatureCollection.Features)
            {
                foreach (var coordinateRings in EnumeratePolygonCoordinateRings(feature.Geometry))
                {
                    var rings = coordinateRings
                        .Select(ring => ring.Select(ToRdPoint).Where(point => point.X > 0 && point.Y > 0).ToList())
                        .Where(ring => ring.Count >= 4)
                        .ToList();

                    if (rings.Count == 0)
                    {
                        continue;
                    }

                    var outerRing = rings[0];
                    var holes = rings.Skip(1).ToList();
                    var area = PolygonArea(outerRing) - holes.Sum(PolygonArea);
                    polygons.Add(new BgtSurfacePolygon(outerRing, holes, BgtSurfaceLabel(feature), BgtSurfaceColor(feature), Math.Abs(area)));
                }
            }
        }

        return polygons
            .Where(polygon => polygon.Ring.Count >= 4 && polygon.Area is > 0.5 and < 500000)
            .ToList();
    }

    private static IEnumerable<IReadOnlyList<List<double[]>>> EnumeratePolygonCoordinateRings(GeoJsonGeometry geometry)
    {
        if (geometry.Type.Equals("Polygon", StringComparison.OrdinalIgnoreCase))
        {
            var rings = ExtractNestedCoordinateLists(geometry.Coordinates).ToList();
            if (rings.Count > 0) yield return rings;
        }
        else if (geometry.Type.Equals("MultiPolygon", StringComparison.OrdinalIgnoreCase) &&
                 geometry.Coordinates is System.Collections.IEnumerable polygons &&
                 geometry.Coordinates is not string)
        {
            foreach (var polygon in polygons)
            {
                var rings = ExtractNestedCoordinateLists(polygon).ToList();
                if (rings.Count > 0) yield return rings;
            }
        }
    }

    private static string BgtSurfaceLabel(GeoJsonFeature feature)
    {
        var objectType = GetFeatureString(feature, "objectType", GetFeatureString(feature, "theme", "BGT"));
        var sourceName = GetFeatureString(feature, "sourceName", "");
        var bgtType = GetFeatureString(feature, "bgtType", "");
        var value = objectType.ToLowerInvariant();
        var function = GetFeatureString(feature, "Functie", "");
        var functionPlus = GetFeatureString(feature, "Functie plus", "");
        var physical = GetFeatureString(feature, "Fysiek voorkomen", "");
        var physicalPlus = GetFeatureString(feature, "Fysiek voorkomen plus", "");
        var classValue = GetFeatureString(feature, "Klasse", "");
        var functionValue = $"{function} {functionPlus}".Replace('_', ' ').Replace('-', ' ').ToLowerInvariant();
        var physicalValue = $"{physical} {physicalPlus} {classValue}".Replace('_', ' ').Replace('-', ' ').ToLowerInvariant();
        var combined = $"{value} {sourceName} {bgtType} {function} {functionPlus} {physical} {physicalPlus} {classValue}"
            .Replace('_', ' ')
            .Replace('-', ' ')
            .ToLowerInvariant();
        var typeValue = $"{objectType} {bgtType} {sourceName}"
            .Replace('_', ' ')
            .Replace('-', ' ')
            .ToLowerInvariant();
        var isExplicitWater = typeValue.Contains("waterdeel") ||
                              typeValue.Contains("waterbody") ||
                              typeValue.Contains("waterloop");
        var isGreen = functionValue.Contains("berm") ||
                      functionValue.Contains("groenvoorziening") ||
                      functionValue.Contains("plantsoen") ||
                      functionValue.Contains("vegetatie") ||
                      physicalValue.Contains("groenvoorziening") ||
                      physicalValue.Contains("gras") ||
                      physicalValue.Contains("kruid") ||
                      physicalValue.Contains("bos");
        var isPaved = functionValue.Contains("rijbaan") ||
                      functionValue.Contains("fietspad") ||
                      functionValue.Contains("voetpad") ||
                      physicalValue.Contains("asfalt") ||
                      physicalValue.Contains("gesloten verharding");

        if (combined.Contains("spoor")) return "spoor";
        if (isExplicitWater || functionValue.Contains("water") || physicalValue.Contains("water")) return "water";
        if (isPaved) return "asfalt";
        if (isGreen) return "groenstrook";
        if (combined.Contains(" water ")) return "water";
        if (combined.Contains("begroeid") || combined.Contains("vegetatie") || combined.Contains("groen") || combined.Contains("plantcover")) return "groenstrook";
        if (combined.Contains("onbegroeid") || combined.Contains("open verharding") || combined.Contains("zand") || combined.Contains("gravel")) return "onverhard";
        if (combined.Contains("pand") || combined.Contains("gebouw") || combined.Contains("building")) return "bebouwing";
        if (combined.Contains("ondersteunend wegdeel")) return "groenstrook";
        if (combined.Contains("wegdeel") || combined.Contains("road") || combined.Contains("traffic")) return "asfalt";
        return objectType.Replace('_', ' ');
    }

    private bool IsBgtSurfaceVisible(string label)
    {
        var key = NormalizeBgtSurfaceKey(label);
        return _gisLayerState.IsBgtSurfaceVisible(key);
    }

    private static string NormalizeBgtSurfaceKey(string label)
    {
        var value = (label ?? string.Empty).Trim().Replace('_', ' ').Replace('-', ' ').ToLowerInvariant();
        if (value.Contains("water")) return "water";
        if (value.Contains("berm")) return "groenstrook";
        if (value.Contains("asfalt") || value.Contains("wegdeel") || value.Contains("verharding") || value.Contains("rijbaan")) return "asfalt";
        if (value.Contains("groen") || value.Contains("begroeid") || value.Contains("vegetatie") || value.Contains("plantcover") ||
            value.Contains("gras") || value.Contains("kruid") || value.Contains("bos")) return "groenstrook";
        if (value.Contains("onverhard") || value.Contains("zand") || value.Contains("gravel")) return "onverhard";
        if (value.Contains("bebouwing") || value.Contains("pand") || value.Contains("gebouw") || value.Contains("building")) return "bebouwing";
        if (value.Contains("spoor")) return "spoor";
        return "overig";
    }

    private static string BgtSurfaceColor(GeoJsonFeature feature)
    {
        var label = BgtSurfaceLabel(feature);
        return label switch
        {
            "water" => "#7DD3FC",
            "asfalt" => "#CBD5E1",
            "spoor" => "#9CA3AF",
            "groenstrook" => "#86EFAC",
            "onverhard" => "#FDE68A",
            "bebouwing" => "#D1D5DB",
            _ => GetFeatureString(feature, "color", "#E2E8F0")
        };
    }

    private static string BgtSurfaceColorForLabel(string label) =>
        NormalizeBgtSurfaceKey(label) switch
        {
            "water" => "#7DD3FC",
            "asfalt" => "#CBD5E1",
            "spoor" => "#9CA3AF",
            "groenstrook" => "#86EFAC",
            "onverhard" => "#FDE68A",
            "bebouwing" => "#D1D5DB",
            _ => "#E2E8F0"
        };

    private static int BgtSurfacePriority(string label)
    {
        return label.ToLowerInvariant() switch
        {
            "asfalt" => 100,
            "water" => 90,
            "spoor" => 85,
            "bebouwing" => 80,
            "onverhard" => 60,
            "groenstrook" => 40,
            _ => 10
        };
    }

    // Only the physical BGT surface (terreindeel) classes tile the ground and belong
    // in the surface profile. Thematic/administrative areas such as "functioneelgebied"
    // normalise to "overig" and must be ignored, otherwise a huge functional-area
    // polygon (or a parser fragment) would swamp the real surface classification.
    private static bool IsRealBgtSurface(string label) =>
        NormalizeBgtSurfaceKey(label) is "water" or "asfalt" or "spoor" or "groenstrook" or "onverhard" or "bebouwing";

    private static double BgtSurfaceRank(BgtSurfacePolygon polygon)
    {
        var areaScore = Math.Log10(Math.Max(1, polygon.Area));
        var priorityScore = BgtSurfacePriority(polygon.Label) * 0.03;
        return areaScore - priorityScore;
    }

    private static bool BgtSurfaceContains(BgtSurfacePolygon polygon, double x, double y)
    {
        if (!PointInPolygon(x, y, polygon.Ring)) return false;
        return !polygon.Holes.Any(hole => PointInPolygon(x, y, hole));
    }

    private static double PolygonArea(IReadOnlyList<RdPoint> ring)
    {
        if (ring.Count < 3) return double.MaxValue;
        var area = 0d;
        for (int i = 0, j = ring.Count - 1; i < ring.Count; j = i++)
        {
            area += (ring[j].X + ring[i].X) * (ring[j].Y - ring[i].Y);
        }

        return Math.Abs(area / 2);
    }

    private static string GetFeatureString(GeoJsonFeature feature, string key, string fallback)
    {
        return feature.Properties.TryGetValue(key, out var value) && value is not null && !string.IsNullOrWhiteSpace(value.ToString())
            ? value.ToString()!
            : fallback;
    }

    private static bool PointInPolygon(double x, double y, IReadOnlyList<RdPoint> ring)
    {
        var inside = false;
        for (int i = 0, j = ring.Count - 1; i < ring.Count; j = i++)
        {
            var pi = ring[i];
            var pj = ring[j];
            if (((pi.Y > y) != (pj.Y > y)) &&
                (x < (pj.X - pi.X) * (y - pi.Y) / Math.Max(0.000001, pj.Y - pi.Y) + pi.X))
            {
                inside = !inside;
            }
        }

        return inside;
    }

    private double SegmentDistance(int index) => index >= 0 && index < _profilePoints.Count - 1
        ? Math.Max(0, _profilePoints[index + 1].Distance - _profilePoints[index].Distance)
        : 0;

    private double SegmentAngle(int index)
    {
        var distance = SegmentDistance(index);
        if (distance <= 0 || index < 0 || index >= _profilePoints.Count - 1) return 0;
        var deltaHeight = _profilePoints[index + 1].Nap - _profilePoints[index].Nap;
        return Math.Atan2(deltaHeight, distance) * 180 / Math.PI;
    }

    private void ProfileSave_OnClick(object sender, RoutedEventArgs e)
    {
        OutputText.Text = SaveDepthProfile();
    }

    private void ProfileZoomIn_OnClick(object sender, RoutedEventArgs e)
    {
        _profileViewZoom = Math.Min(3.0, _profileViewZoom * 1.15);
        _profileLayoutLocked = true;
        SaveProfileVisualSettings();
        RenderProfilePanel();
    }

    private void ProfileZoomOut_OnClick(object sender, RoutedEventArgs e)
    {
        _profileViewZoom = Math.Max(0.55, _profileViewZoom / 1.15);
        _profileLayoutLocked = true;
        SaveProfileVisualSettings();
        RenderProfilePanel();
    }

    private void ProfileExpand_OnClick(object sender, RoutedEventArgs e)
    {
        _profileExpanded = !_profileExpanded;
        _profileLayoutLocked = true;
        if (_profileExpanded && _profileViewZoom < 1.05) _profileViewZoom = 1.15;
        if (!_profileExpanded) _profileViewZoom = 1.0;
        SaveProfileVisualSettings();
        RenderProfilePanel();
        OutputText.Text = _profileExpanded
            ? "Dwarsprofiel vergroot\n\nHet profiel is vastgezet en zoomt nu als een vaste tekening, zonder herberekening van de lijnhoogtes."
            : "Dwarsprofiel ingeklapt\n\nDe profielweergave staat terug op 100%.";
    }

    private void ProfileSmooth_OnClick(object sender, RoutedEventArgs e)
    {
        OutputText.Text = ToggleSmoothProfile();
    }

    private void ProfileLock_OnClick(object sender, RoutedEventArgs e)
    {
        OutputText.Text = ToggleProfileLayoutLock();
    }

    private void ProfileAlign_OnClick(object sender, RoutedEventArgs e)
    {
        OutputText.Text = AlignProfileToMap();
    }

    private string AlignProfileToMap()
    {
        return AlignBorelineHorizontalForProfile(
            "Dwarsprofiel uitlijnen aangevraagd",
            "De kaart boven het profiel stuurt de exacte schermposities van de boorpunten en BGT-oppervlaktes terug. Daardoor wordt de oppervlaktekaart horizontaal gelijkgezet met het dwarsprofiel.");
    }

    private string AlignBorelineHorizontalForProfile()
    {
        return AlignBorelineHorizontalForProfile(
            "Boorlijn horizontaal gezet",
            "De GIS-kaart wordt gedraaid en ingezoomd zodat de boorlijn horizontaal in beeld staat. Het dwarsprofiel gebruikt daarna dezelfde afstands-as.");
    }

    private string AlignBorelineHorizontalForProfile(string title, string body)
    {
        _profileAlignedToMap = true;
        _profileLayoutLocked = false;
        SendProfileModeToMap();
        SendMapMessage("{\"type\":\"profileAlignRequest\"}");
        SaveProfileVisualSettings();
        if (_selectedStep?.Number == ProfileStepNumber)
        {
            SaveMapStateForStep(ProfileStepNumber, false);
            QueueLiveMapReportCapture(ProfileStepNumber);
            RefreshInlineReportPreviewIfVisible();
        }
        RenderProfilePanel();
        return $"{title}\n\n{body}";
    }

    private void RequestProfileMapAlignmentIfNeeded()
    {
        if (!_profileAlignedToMap) return;
        if (_selectedStep?.Number is not ProfileStepNumber and not WorkDrawingStepNumber) return;
        if (!_mapLibreLoaded || StepThreeMapView.CoreWebView2 is null)
        {
            QueueMapSync();
            return;
        }

        SendMapMessage("{\"type\":\"profileAlignRequest\"}");
    }

    private string ToggleSmoothProfile()
    {
        _profileSmoothBore = !_profileSmoothBore;
        SaveProfileVisualSettings();
        RenderProfilePanel();
        ProfileToolsSidebarPanel.Children.Clear();
        RenderProfileToolsSidebarPanel();
        return _profileSmoothBore
            ? "Boorlijn vloeiend\n\nDe boorzone wordt nu als vloeiende curve weergegeven. Dieptepunten blijven behouden."
            : "Boorlijn hoekig\n\nDe boorzone wordt weer als rechte segmenten tussen de dieptepunten weergegeven.";
    }

    private string ToggleSmoothTrace()
    {
        LoadTraceVisualSettings();
        _traceSmoothBore = !_traceSmoothBore;
        SaveTraceVisualSettings();
        SendTraceStateToMap();
        StepSpecificRibbonPanel.Children.Clear();
        BoreTraceSidebarPanel.Children.Clear();
        RenderBoreTraceSidebarPanel();
        return _traceSmoothBore
            ? "Boorlijn vloeiend\n\nDe kaart tekent de boorlijn nu als een vloeiende curve. De tussenpunten blijven opgeslagen en komen terug zodra je weer hoekig kiest."
            : "Boorlijn hoekig\n\nDe kaart toont weer alle oorspronkelijke knikpunten en rechte segmenten.";
    }

    private string ToggleProfileLayoutLock()
    {
        if (!_profileLayoutLocked && _profileScreenMetrics is null)
        {
            _profileAlignedToMap = true;
            SendMapMessage("{\"type\":\"profileAlignRequest\"}");
        }

        _profileLayoutLocked = !_profileLayoutLocked;
        SaveProfileVisualSettings();
        ProfileToolsSidebarPanel.Children.Clear();
        RenderProfileToolsSidebarPanel();
        RenderProfilePanel();
        return _profileLayoutLocked
            ? "Dwarsprofiel vastgezet\n\nDe horizontale uitlijning blijft nu staan. In- en uitzoomen verandert alleen de verticale schaal."
            : "Dwarsprofiel losgezet\n\nUitlijnen mag de horizontale posities weer opnieuw ophalen uit de kaart.";
    }

    private string SaveDepthProfile()
    {
        if (_selectedProject is null) return "Geen project actief.";
        EnsureProfilePoints();
        if (_profilePoints.Count < 2) return $"Geen boorlijn beschikbaar. Teken en sla eerst stap {DisplayStepNumber(3)}.1 op.";

        var payload = JsonSerializer.Serialize(new
        {
            type = "Borevexa3DBoreLine",
            sourceStep = 7,
            units = "m",
            points = _profilePoints.Select(point => new
            {
                point.Index,
                point.Role,
                x = Math.Round(point.X, 3),
                y = Math.Round(point.Y, 3),
                distance = Math.Round(point.Distance, 2),
                depth = Math.Round(point.Depth, 2),
                nap = Math.Round(point.Nap, 2),
                surface = Math.Round(point.Surface, 2)
            })
        }, JsonOptions);
        SaveSelectedProjectStepData(ProfileStepNumber, "diepteprofiel_3d", payload);
        SaveProfileVisualSettings();
        _profileHasUnsavedChanges = false;
        _profileGeometryDirty = false;
        RenderProfilePanel();
        return $"Diepteprofiel opgeslagen\n\n{_profilePoints.Count} punt(en)\nTotale lengte: {_profilePoints[^1].Distance:N1} m\nLaagste punt: {_profilePoints.Min(point => point.Nap):N2} m NAP\n\nDe boorlijn is nu als X/Y/Z-profiel lokaal opgeslagen.";
    }

    private string GenerateDepthProfile()
    {
        EnsureProfilePoints(regenerate: true);
        _profileHasUnsavedChanges = _profilePoints.Count >= 2;
        _profileGeometryDirty = false;
        RenderProfilePanel();
        SendProfileModeToMap();
        return _profilePoints.Count >= 2
            ? $"Dwarsprofiel gegenereerd\n\n{_profilePoints.Count} punt(en)\nLengte: {_profilePoints[^1].Distance:N1} m\nBewerk de diepte of positie in de tabel en sla daarna op."
            : $"Geen boorlijn beschikbaar. Teken en sla eerst een boorlijn op in stap {DisplayStepNumber(3)}.1.";
    }

    private string AddDepthControlPoint()
    {
        EnsureProfilePoints();
        if (_profilePoints.Count < 2) return "Geen profiel beschikbaar. Genereer eerst een profiel.";

        var longestIndex = 0;
        var longestDistance = 0d;
        for (var i = 0; i < _profilePoints.Count - 1; i++)
        {
            var distance = SegmentDistance(i);
            if (distance <= longestDistance) continue;
            longestDistance = distance;
            longestIndex = i;
        }

        var a = _profilePoints[longestIndex];
        var b = _profilePoints[longestIndex + 1];
        var distanceAt = (a.Distance + b.Distance) / 2;
        var depth = Math.Max(0, (a.Depth + b.Depth) / 2);
        var traceRows = GetTraceRowsForProfile();
        var xy = InterpolateTracePoint(traceRows, BuildTraceDistances(traceRows), distanceAt);
        var surface = GetProfileSurfaceNap(xy.X, xy.Y, distanceAt, Math.Max(1, _profilePoints[^1].Distance), _profilePoints.Count, (a.Surface + b.Surface) / 2);
        _profilePoints.Add(new ProfilePointRow(0, "Dieptepunt", xy.X, xy.Y, Math.Round(distanceAt, 2), Math.Round(depth, 2), Math.Round(surface - depth, 2), Math.Round(surface, 2)));
        RecalculateProfileRolesAndNap();
        _profileHasUnsavedChanges = true;
        _profileGeometryDirty = false;
        RenderProfilePanel();
        return $"Dieptepunt toegevoegd\n\nPositie: {distanceAt:N1} m\nDiepte: {depth:N2} m\nSegment: {longestDistance:N1} m opgesplitst.";
    }

    private string ExportDepthProfileGeoJson()
    {
        if (_selectedProject is null) return "Geen project actief.";
        EnsureProfilePoints();
        if (_profilePoints.Count < 2) return "Geen profiel beschikbaar.";

        var feature = new
        {
            type = "Feature",
            properties = new
            {
                name = _selectedProject.Name,
                source = "Borevexa stap 7",
                totalLength = Math.Round(_profilePoints[^1].Distance, 2)
            },
            geometry = new
            {
                type = "LineString",
                coordinates = _profilePoints.Select(point => new[] { Math.Round(point.X, 3), Math.Round(point.Y, 3), Math.Round(point.Nap, 2) })
            }
        };
        var geoJson = JsonSerializer.Serialize(new { type = "FeatureCollection", features = new[] { feature } }, JsonOptions);
        var exportDir = System.IO.Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData), "Borevexa", "PrescanNative", "Exports");
        Directory.CreateDirectory(exportDir);
        var fileName = $"boorlijn-3d-{DateTime.Now:yyyyMMdd-HHmmss}.geojson";
        var path = System.IO.Path.Combine(exportDir, fileName);
        System.IO.File.WriteAllText(path, geoJson, Encoding.UTF8);
        return $"GeoJSON export gemaakt\n\n{path}";
    }

    private void SendFeatureDetail(string message)
    {
        if (StepThreeMapView.CoreWebView2 is null) return;

        try
        {
            using var document = JsonDocument.Parse(message);
            var root = document.RootElement;
            var detailId = root.TryGetProperty("detailId", out var detailIdElement)
                ? detailIdElement.ToString()
                : "";

            MapFeatureDetails.TryGetValue(detailId, out var details);
            var relatedDocuments = FindRelatedDocuments(details).ToList();
            var payload = JsonSerializer.Serialize(new
            {
                type = "featureDetail",
                detailId,
            properties = details ?? new Dictionary<string, object>(),
                documents = relatedDocuments.Select(doc => new
                {
                    doc.Id,
                    doc.Name,
                    doc.Type,
                    doc.SizeKb
                })
            }, JsonOptions);

            _gisMap.TryPostJson(
                StepThreeMapView.CoreWebView2,
                payload,
                exception => AppendMapDiagnostic($"Feature detail naar kaart sturen mislukt: {exception.Message}"));
        }
        catch (Exception exception)
        {
            AppendMapDiagnostic($"Feature detail fout: {exception.Message}");
        }
    }
    private IEnumerable<ProjectDocumentEntry> FindRelatedDocuments(IReadOnlyDictionary<string, object>? details)
    {
        if (_selectedProject is null) yield break;

        _projectFiles = _projects.GetProjectFiles(_selectedProject.Id);
        var docs = BuildProjectDocumentEntries(_projectFiles).ToList();
        if (docs.Count == 0) yield break;

        var haystack = details is null
            ? ""
            : string.Join(" ", details.Select(pair => $"{pair.Key} {pair.Value}"));
        var objectType = details is not null && details.TryGetValue("objectType", out var objectValue)
                ? objectValue?.ToString() ?? ""
                : "";
        var wantsProfile = ContainsAny(haystack, "profiel", "schets", "boring", "boorstaat", "sondering", "mantel", "persing", "boogzinker", "bescherm") ||
                           ContainsAny(objectType, "profiel", "schets", "boring", "mantel", "persing", "boogzinker", "bescherm");

        var ranked = docs
            .Select(doc => new { Document = doc, Score = ScoreRelatedDocument(doc, haystack, wantsProfile) })
            .Where(item => item.Score > 0)
            .OrderByDescending(item => item.Score)
            .ThenBy(item => item.Document.Name)
            .Take(8)
            .Select(item => item.Document)
            .ToList();

        if (ranked.Count == 0 && wantsProfile)
        {
            ranked = docs
                .Where(doc => ContainsAny(doc.Name, "profiel", "schets", "boring", "mantel", "persing", "boogzinker", "ligging", "algemeen"))
                .OrderBy(doc => doc.Name)
                .Take(8)
                .ToList();
        }

        foreach (var doc in ranked)
        {
            _mapDocumentEntries[doc.Id] = doc;
            yield return doc;
        }
    }

    private static int ScoreRelatedDocument(ProjectDocumentEntry doc, string haystack, bool wantsProfile)
    {
        var name = doc.Name;
        var score = 0;
        if (wantsProfile && ContainsAny(name, "profiel", "schets", "boring", "mantel", "persing", "boogzinker")) score += 100;
        if (ContainsAny(name, "ligging", "algemeen", "liander", "klic")) score += 15;
        if (doc.Type.Equals("PDF", StringComparison.OrdinalIgnoreCase)) score += 10;

        foreach (Match token in Regex.Matches(name, @"[A-Za-z0-9]{5,}"))
        {
            if (haystack.Contains(token.Value, StringComparison.OrdinalIgnoreCase)) score += 30;
        }

        return score;
    }

    private static bool ContainsAny(string value, params string[] needles) =>
        needles.Any(needle => value.Contains(needle, StringComparison.OrdinalIgnoreCase));

    private void OpenMapDocument(string message)
    {
        try
        {
            using var document = JsonDocument.Parse(message);
            var id = document.RootElement.TryGetProperty("id", out var idElement) ? idElement.ToString() : "";
            if (string.IsNullOrWhiteSpace(id) || !_mapDocumentEntries.TryGetValue(id, out var doc))
            {
                OutputText.Text = "Bijlage kon niet worden gevonden. Open eerst de KLIC-popup opnieuw.";
                return;
            }

            OutputText.Text = $"Bijlage openen\n\n{doc.Name}\n{doc.Type} · {doc.SizeKb:N0} KB";
            TryOpenDocument(doc);
        }
        catch (Exception exception)
        {
            OutputText.Text = $"Bijlage openen lukte niet\n\n{exception.Message}";
        }
    }

    private void MapOverlay_OnClick(object sender, RoutedEventArgs e)
    {
        if (BlockIfCurrentMapReportLocked()) return;
        if ((sender as Button)?.Tag is not string overlayId) return;

        var visible = !_mapOverlayStates.TryGetValue(overlayId, out var current) || !current;
        _mapOverlayStates[overlayId] = visible;
        if (IsSurfaceAnalysisOverlay(overlayId))
        {
            _mapBgtSurfaceSamples = [];
        }
        _suppressProjectLayerSend = true;
        try
        {
            RenderStepThree(force: true);
        }
        finally
        {
            _suppressProjectLayerSend = false;
        }
        if (overlayId.Equals("profileTracePoints", StringComparison.OrdinalIgnoreCase))
        {
            RenderProfilePanel();
            SaveCurrentMapStateAndQueueReportCapture();
            return;
        }
        if (overlayId.StartsWith("boreTrace", StringComparison.OrdinalIgnoreCase))
        {
            SendTraceStateToMap();
            SaveCurrentMapStateAndQueueReportCapture();
            return;
        }
        if (overlayId.Equals("machines", StringComparison.OrdinalIgnoreCase))
        {
            SendMachineStateToMap();
            SaveCurrentMapStateAndQueueReportCapture();
            return;
        }
        SendMapMessage($"{{\"type\":\"overlay\",\"id\":\"{overlayId}\",\"visible\":{visible.ToString().ToLowerInvariant()}}}");
        SendTraceStateToMap();
        SaveCurrentMapStateAndQueueReportCapture();
    }

