    private void MapRestore_OnClick(object sender, RoutedEventArgs e)
    {
        if (_selectedStep?.Number == 4)
        {
            _gisLayerState.ApplySurfaceAnalysisMapDefaults();
            _mapBgtSurfaceSamples = [];
        }
        else
        {
            _gisLayerState.RestoreVisibleDefaults();
