        SendMapMessage("{\"type\":\"base\",\"id\":\"pdok-brt\"}");
        SendProjectLayersToMap();
        SendAllFilterStatesToMap();
        SendStoredMapStateToMap();
        SaveMapStateForStep(_selectedStep?.Number ?? 3, false);
